-- Poems batch 147
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3516ae9a-15bf-4b28-99f1-04a6c1be2c04','再次韻十首  其三','陳造','宋','宋诗','song-poetry','','[]','客舍無佳晤，君來肯小留。',48,'全唐诗/poet.song.151000.json','["客舍無佳晤，君來肯小留。", "衣穿從見肘，賦好似登樓。", "論世聊捫舌，輸棋不計籌。", "明窗坐方穩，寒日爲誰遒。"]'),
('b365461f-0a4f-4927-b796-f950f1ea61ec','再次韻十首  其四','陳造','宋','宋诗','song-poetry','','[]','吳門詩酒伴，入社記吾曾。',48,'全唐诗/poet.song.151000.json','["吳門詩酒伴，入社記吾曾。", "香篆溫難燼，銅壺冷易冰。", "賡酬恕吾老，聲價放渠增。", "衰謝猶迴首，思分蔀屋燈。"]'),
('124c1572-a3a8-48c5-9b6d-0f175bacbc3b','再次韻十首  其五','陳造','宋','宋诗','song-poetry','','[]','朝家無闕政，秋禜繼春雩。',48,'全唐诗/poet.song.151000.json','["朝家無闕政，秋禜繼春雩。", "恤緯憐吾怯，知言敢自誣。", "閉陰寧董傅，爲己肯楊朱。", "未斷蝸緣壁，仍多豕負塗。"]'),
('f4e6b5e8-0843-4bd4-9963-93fa76fe5fb9','再次韻十首  其六','陳造','宋','宋诗','song-poetry','','[]','城西山水窟，早晚命籃輿。',48,'全唐诗/poet.song.151000.json','["城西山水窟，早晚命籃輿。", "勝絕僧能有，拘攣我不如。", "山雲側步踊，雪壁細行書。", "它日嘗般礴，蕭然樂有餘。"]'),
('533372fa-a006-4203-8190-0f7b612055d0','再次韻十首  其七','陳造','宋','宋诗','song-poetry','','[]','中天有臺閣，自問汝何能。',48,'全唐诗/poet.song.151000.json','["中天有臺閣，自問汝何能。", "世路信薄命，吏曹須異稱。", "北歸甘醉叟，西上且聾丞。", "執友論文地，能無興可乘。"]'),
('1ab42f76-6619-41c0-adeb-ba5a7cca671c','再次韻十首  其八','陳造','宋','宋诗','song-poetry','','[]','進業湖海窄，取名絲縷輕。',48,'全唐诗/poet.song.151000.json','["進業湖海窄，取名絲縷輕。", "因君論前輩，衛道有金城。", "潢潦先知本，機緘貴用情。", "靈臺與秋日，烱燭古今明。"]'),
('b538a0bf-9f34-4e7d-820d-2d3b664cf16a','再次韻十首  其九','陳造','宋','宋诗','song-poetry','','[]','仕爲饑寒迫，歸憐興味長。',48,'全唐诗/poet.song.151000.json','["仕爲饑寒迫，歸憐興味長。", "卜居從詭譎，勿藥幸康强。", "鄰擬千錢買，書開萬卷藏。", "殘年文字癖，更欲競流光。"]'),
('da1dc4f0-6760-4e38-a098-cbdbb424be56','再次韻十首  其一○','陳造','宋','宋诗','song-poetry','','[]','靖節瓶無粟，思歸更命車。',48,'全唐诗/poet.song.151000.json','["靖節瓶無粟，思歸更命車。", "慵垂督郵带，况袖子公書。", "老我須閑適，塵緣得破除。", "還應與鷗鷺，分占碧溪漁。"]'),
('7f795902-a3d5-4009-99e9-66e46480874c','題陳主管小壺天三首  其一','陳造','宋','宋诗','song-poetry','','[]','一室凌埃𡏖，公堂更左偏。',48,'全唐诗/poet.song.151000.json','["一室凌埃𡏖，公堂更左偏。", "閑消官上日，小隠洞中天。", "棋酒隨醒醉，蚊蝱斷撲緣。", "憐渠鍛爐側，矻矻計巢仙。"]'),
('7c833068-4bbc-4370-ac29-1ca34e155ab9','題陳主管小壺天三首  其二','陳造','宋','宋诗','song-poetry','','[]','棋枰外世故，喧靜信奇偏。',48,'全唐诗/poet.song.151000.json','["棋枰外世故，喧靜信奇偏。", "俗網恢三面，冰壺令一天。", "時供詩友課，未斷宰官緣。", "付我紅塵去，如君自半仙。"]'),
('1a3f0ca8-ae56-4396-b583-86d0e9e6ecde','題陳主管小壺天三首  其三','陳造','宋','宋诗','song-poetry','','[]','未放歌雲散，先看醉帽偏。',48,'全唐诗/poet.song.151000.json','["未放歌雲散，先看醉帽偏。", "周郎自醇酎，樂廣定青天。", "持勝收賢業，推枰睨世緣。", "明年一品手，却訪玉堂仙。"]'),
('31a94637-e432-44a0-b7dc-7c8f4887f934','過八疊舖問宿','陳造','宋','宋诗','song-poetry','','[]','平野俄空闊，遥山且有無。',48,'全唐诗/poet.song.151000.json','["平野俄空闊，遥山且有無。", "斜陽對捫蝨，暝樹忽啼烏。", "老去猶羈旅，生平頗壯圖。", "田翁詫豐歲，不擬話爲儒。"]'),
('54b12bf2-70f5-4efe-adba-b7d8b1ca7373','高頭山','陳造','宋','宋诗','song-poetry','','[]','小駐緣雲脚，居然睡眼醒。',48,'全唐诗/poet.song.151000.json','["小駐緣雲脚，居然睡眼醒。", "楚田銜樹闊，漢水挾山青。", "蹀躞初忘倦，巉巖已飽經。", "川原方啖蔗，不擬嘆漂零。"]'),
('5cdf5b2d-af51-48b6-b7f6-7e097f884635','無題三首  其一','陳造','宋','宋诗','song-poetry','','[]','薄宦受風梗，還家歸岫雲。',48,'全唐诗/poet.song.151000.json','["薄宦受風梗，還家歸岫雲。", "行人與喬木，老色竟平分。", "末路慙周朴，窮交有墨君。", "看渠綬若若，千騎詫鄉枌。"]'),
('5d46a1d1-7df6-476a-ba30-bb16a797337e','無題三首  其二','陳造','宋','宋诗','song-poetry','','[]','浪出嗟何補，歸來樂有餘。',48,'全唐诗/poet.song.151000.json','["浪出嗟何補，歸來樂有餘。", "山川付不借，天地託蘧廬。", "酒熟聊呼客，鈎垂不在魚。", "平生棲遯意，政用蓋迂疎。"]'),
('28ad5045-dcb3-4235-b670-9e32de7c040b','無題三首  其三','陳造','宋','宋诗','song-poetry','','[]','卧病十四五，秋來身自輕。',48,'全唐诗/poet.song.151000.json','["卧病十四五，秋來身自輕。", "已拚不籍在，寧復可憐生。", "每笑隠者傳，尚存身後名。", "灌園聊日力，分藥且交情。"]'),
('2e5660d3-95d0-4d05-9da5-7cbca4d56bee','思歸','陳造','宋','宋诗','song-poetry','','[]','薄宦隨漂梗，流光任迅湍。',48,'全唐诗/poet.song.151000.json','["薄宦隨漂梗，流光任迅湍。", "家山蝶夢隔，節物鴈空寒。", "撫事頻回首，微吟小凭欄。", "多情但烏鵲，時肯報平安。"]'),
('5fdcca8f-23c4-4631-8ae9-5d889500b278','答壽詩','陳造','宋','宋诗','song-poetry','','[]','感念垂弧日，無成忽老衰。',48,'全唐诗/poet.song.151000.json','["感念垂弧日，無成忽老衰。", "尚須庚癸諾，可諱甲辰雌。", "但有散人傳，難勝幼婦辭。", "呼兄張座右，言配蓼莪詩。"]'),
('4cc2ca20-4f33-4bc8-8126-11b1aab2842c','次韻章宰  其一','陳造','宋','宋诗','song-poetry','','[]','窮山從薄宦，小郡著衰翁。',48,'全唐诗/poet.song.151000.json','["窮山從薄宦，小郡著衰翁。", "政術甘疎拙，辭壇敢長雄。", "一饑纔自救，五細未宜中。", "又擬包羞去，京塵冒軟紅。"]'),
('066ce148-26bb-4bed-8f91-4e5ce4739417','次韻章宰  其二','陳造','宋','宋诗','song-poetry','','[]','遊舊多厭絕，怪君終眷知。',48,'全唐诗/poet.song.151000.json','["遊舊多厭絕，怪君終眷知。", "帳留仍碧酒，紵獻更清詩。", "風義固難及，月評無乃私。", "相從文字樂，悔作十年遲。"]'),
('9d11af99-91df-430e-a845-c4728dc01381','過樊村','陳造','宋','宋诗','song-poetry','','[]','幾日囚籠鳥，今朝縱壑魚。',48,'全唐诗/poet.song.151000.json','["幾日囚籠鳥，今朝縱壑魚。", "空勞計遲速，凡百有乘除。", "岸勢驚禽過，江聲午夢餘。", "心融得新句，澄水滴銅蜍。"]'),
('9c3a0137-1a68-40d4-a2e7-8e5b2dc5c759','書懷二首  其一','陳造','宋','宋诗','song-poetry','','[]','俛仰人間世，纔爲一笑資。',48,'全唐诗/poet.song.151000.json','["俛仰人間世，纔爲一笑資。", "百年羊胛熟，萬事虎頭癡。", "文字聊遮眼，功名浪朶頤。", "浮生如此爾，况復病餘衰。"]'),
('77f027af-05b6-4bd8-8046-095372e90301','書懷二首  其二','陳造','宋','宋诗','song-poetry','','[]','薄宦爬沙地，平生一不施。',48,'全唐诗/poet.song.151000.json','["薄宦爬沙地，平生一不施。", "才名將底用，齒髮欻如斯。", "自笑書汗馬，誰今手不龜。", "惟餘五色筆，忍賦四愁詩。"]'),
('4100f9ce-467a-43ac-a800-c6f261f03453','步西湖次韻徐南卿  其一','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','載酒幽尋地，乘閑得再臨。',48,'全唐诗/poet.song.151000.json','["載酒幽尋地，乘閑得再臨。", "麗黄啼曉霽，魏紫笑春深。", "撫事揮犀管，他時夢鶴林。", "心期更閴寂，物理付昇沈。"]'),
('9d8a2648-7674-4911-8040-bef83d717835','步西湖次韻徐南卿  其二','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','楊園騫絕嶺，萬象赴窺臨。',48,'全唐诗/poet.song.151000.json','["楊園騫絕嶺，萬象赴窺臨。", "坐久嵐霏潤，來時翠碧深。", "鶑花自佳處，魚鼓亦叢林。", "誰在飛埃外，芸芸付陸沈。"]'),
('3a26b905-ecd3-4c84-a34a-c07c10d93df0','步西湖次韻徐南卿  其三','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山寺曾題竹，尋詩記所臨。',48,'全唐诗/poet.song.151000.json','["山寺曾題竹，尋詩記所臨。", "緣雲俯空曠，捫石探幽深。", "倦鳥低平野，蔫花下碧林。", "沙頭催喚渡，空水遠沈沈。"]'),
('af25615a-3040-4364-b533-f43d3f6c0570','步西湖次韻徐南卿  其四','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水月春猶淺，携壺記此臨。',48,'全唐诗/poet.song.151000.json','["水月春猶淺，携壺記此臨。", "雲煙澹閑寂，魚鳥媚清深。", "堤路俄人海，侯家或肉林。", "高樓下金彈，簾影眇深沈。"]'),
('ba09b023-8712-4998-879d-7d15189441dc','步西湖次韻徐南卿  其五','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','徐子學詩苦，硯池寧暫臨。',48,'全唐诗/poet.song.151000.json','["徐子學詩苦，硯池寧暫臨。", "課功初贔屭，著語遽精深。", "更積歲月力，儻陪英俊林。", "人生才業地，渠輩分平沈。"]'),
('9b373b32-5651-46e6-81fd-d45a38ee970c','步西湖次韻徐南卿  其六','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','徐郎小隠處，愛我許迂臨。',48,'全唐诗/poet.song.151000.json','["徐郎小隠處，愛我許迂臨。", "多遻話歲晚，言歸忘夜深。", "祛愁倚詩酒，結伴卜山林。", "更喜檀欒舊，風煙挺綠沈。"]'),
('3d1c5482-8e46-4a98-b4ed-6ad6d0c92bde','步西湖次韻徐南卿  其七','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖千頃畫，政用好詩臨。',48,'全唐诗/poet.song.151000.json','["西湖千頃畫，政用好詩臨。", "鑒揭霧解駮，屏紆雲淺深。", "鈿車隨寶馬，紅舫度青林。", "歸去開囊錦，君先炷水沈。"]'),
('76656b9e-89bf-4a92-9b1b-39a23ac49e10','步西湖次韻徐南卿  其八','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩課逭離索，蕭窗誰肯臨。',48,'全唐诗/poet.song.151000.json','["詩課逭離索，蕭窗誰肯臨。", "語方逢衆怒，自詫用功深。", "未議辭窮鬼，纔堪補笑林。", "舊交多冊府，肯信有湮沈。"]'),
('3c3eb924-1ec5-459b-8878-a519df73d98e','步西湖次韻徐南卿  其九','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','逐利爭名地，扶衰瞢一臨。',48,'全唐诗/poet.song.151000.json','["逐利爭名地，扶衰瞢一臨。", "官同冰谷冷，盟締海鷗深。", "局步無夷路，卑棲有故林。", "鳶魚天地內，遂性各飛沈。"]'),
('3cfdc3a7-a86e-4c1c-8c9c-32a14b402e0f','觀諸公射於城北書壁二首  其一','陳造','宋','宋诗','song-poetry','','[]','舊約已湯餠，新歡仍碧香。',48,'全唐诗/poet.song.151000.json','["舊約已湯餠，新歡仍碧香。", "小閑障日手，同憩卧雲莊。", "羣彥矢復沓，老夫詩在囊。", "蔬畦暝晚色，野興爲誰長。"]'),
('e7d5e72e-ad10-4f55-84e3-237a00414ea0','觀諸公射於城北書壁二首  其二','陳造','宋','宋诗','song-poetry','','[]','塵我玉蟾蜍，弦君金僕姑。',48,'全唐诗/poet.song.151000.json','["塵我玉蟾蜍，弦君金僕姑。", "分曹雙壁立，中雋萬人呼。", "壯歲功名地，從渠山澤儒。", "他年玉音問，冊府起孫吳。"]'),
('84a61038-5eb9-42ad-a46a-46e764c7a2cb','次韻楊宰次郎裴','陳造','宋','宋诗','song-poetry','','[]','信次尚村落，食眠隨曉晡。',48,'全唐诗/poet.song.151000.json','["信次尚村落，食眠隨曉晡。", "山瓶餘濩倒，僧宇謁伊蒲。", "笑挾兔園策，問收魚澳租。", "前灘起鷗鷺，爲我作前驅。"]'),
('7c858904-306e-4106-b671-c7b6f696b3c3','次韻楊宰公田道上','陳造','宋','宋诗','song-poetry','','[]','人有褰裳去，時閑野渡舟。',48,'全唐诗/poet.song.151000.json','["人有褰裳去，時閑野渡舟。", "知君問彫瘵，隨處訪深幽。", "歲事方關念，村醪不破憂。", "貰租仍己責，或可繼前脩。"]'),
('09854dd8-2d7f-4b32-9e53-c69a6d9d94b5','次韻楊宰樊汊','陳造','宋','宋诗','song-poetry','','[]','龍豈分勤惰，司存想異方。',48,'全唐诗/poet.song.151000.json','["龍豈分勤惰，司存想異方。", "禜雩均此意，豐歉竟殊疆。", "惠戒憎漏網，君寧專擊强。", "東南有偏熟，鄙語未應忘。"]'),
('45d12ce9-e619-45b0-8e14-a58c190a72ff','次韻楊宰秋尾雪','陳造','宋','宋诗','song-poetry','','[]','密雪界秋冬，悲歡可得同。',48,'全唐诗/poet.song.151000.json','["密雪界秋冬，悲歡可得同。", "祥如關歲事，時合奏場功。", "政要肉骨手，民方霜葉風。", "强吟鹽絮句，面不蓋羞紅。"]'),
('e702c023-dd17-4fa9-9738-0013c0faf64a','次韻楊宰葫蘆格','陳造','宋','宋诗','song-poetry','','[]','生常信流坎，老不嘆漂零。',48,'全唐诗/poet.song.151000.json','["生常信流坎，老不嘆漂零。", "雪後菊未死，雨餘山更青。", "仍煩析塵語，遠寄打包僧。", "政績隨詩價，多君日日增。"]'),
('f825a3ff-d9d3-4891-b32c-644660c798be','次韻楊宰述懷','陳造','宋','宋诗','song-poetry','','[]','爲儒如此爾，糧食第晨晡。',48,'全唐诗/poet.song.151000.json','["爲儒如此爾，糧食第晨晡。", "詩漫南山杞，愁連董澤蒲。", "賓筵闕鵝炙，券負有牛租。", "久要惟窮鬼，文成不受驅。"]'),
('4a72903a-d35e-4b76-8305-db0cb53cee60','次韻楊宰野步','陳造','宋','宋诗','song-poetry','','[]','筇杖陪隨去，漂然不繫舟。',48,'全唐诗/poet.song.151000.json','["筇杖陪隨去，漂然不繫舟。", "雲低山影暝，風定竹林幽。", "病減柳臂感，老無蒿目憂。", "吟詩如蝕月，玉斧儻能脩。"]'),
('8d7c3e34-3854-42f4-ae27-2c32005933fb','次韻樊汊','陳造','宋','宋诗','song-poetry','','[]','荒政頼賢守，湛恩推上方。',48,'全唐诗/poet.song.151000.json','["荒政頼賢守，湛恩推上方。", "龔黄真父母，秦越肯圻疆。", "手自起僵仆，術先銷暴强。", "膏肓得司命，銘肺可能忘。"]'),
('69e5f5cf-cf7d-4e87-9e18-a5cb63c3cc9b','次韻楊宰雪','陳造','宋','宋诗','song-poetry','','[]','對雪動遐想，此情今古同。',48,'全唐诗/poet.song.151000.json','["對雪動遐想，此情今古同。", "饒爲灞橋句，會奏蔡城功。", "恥卧袁安屋，思乘列子風。", "高翔廣樂地，眩旋九霞紅。"]'),
('bdcca811-b18c-4a29-b56c-4ce8f814d2f2','次韻楊宰宿田家','陳造','宋','宋诗','song-poetry','','[]','雪曉烏驚矯，無風葉自零。',48,'全唐诗/poet.song.151000.json','["雪曉烏驚矯，無風葉自零。", "人家住莽蒼，徑柏挺寒青。", "千載猶歸鶴，三生省病僧。", "脾虛眼多眚，更比向來增。"]'),
('6ab91fff-ece4-4ad6-b37e-328d120dfa8b','次韻漕使張守二首  其一','陳造','宋','宋诗','song-poetry','','[]','政績新皇眷，功名舊壯懷。',48,'全唐诗/poet.song.151000.json','["政績新皇眷，功名舊壯懷。", "人才雙立玉，筆勢各排淮。", "鵬路天惟咫，鯫生骨未埋。", "行看仲淹弼，接武冠堯階。"]'),
('2ef94f8d-69a8-47b9-ac0d-b1049e6f7073','次韻漕使張守二首  其二','陳造','宋','宋诗','song-poetry','','[]','授書天佐漢，鼓篋客師韓。',48,'全唐诗/poet.song.151000.json','["授書天佐漢，鼓篋客師韓。", "氣宇包溟渤，辭鋒凜莫干。", "經綸股肱似，姓字齒牙寒。", "不作規隨起，誰令九鼎安。"]'),
('812b2e91-4acc-4182-8920-1135218259ed','題吳司理子隆兼隠','陳造','宋','宋诗','song-poetry','','[]','紳笏視林藪，達人忘異同。',48,'全唐诗/poet.song.151000.json','["紳笏視林藪，達人忘異同。", "端知柱下史，却笑鹿門翁。", "犴獄仍陰德，詩書亦雋功。", "何須笠澤去，煙浪放船篷。"]'),
('797492ba-2320-4571-a0e5-2f9b936c3c3f','次韻張守赴真州辭家','陳造','宋','宋诗','song-poetry','','[]','爭引依風領，須公布惠慈。',48,'全唐诗/poet.song.151000.json','["爭引依風領，須公布惠慈。", "深恩手摩拊，數計月盈虧。", "歲事方援溺，情親更語離。", "來時鴈天闊，觸目總宜詩。"]'),
('632571f0-1cb3-4a44-b75b-7b4e40f1b6f2','次韻張守惠山','陳造','宋','宋诗','song-poetry','','[]','詩伯心如水，熊轓再護邊。',48,'全唐诗/poet.song.151000.json','["詩伯心如水，熊轓再護邊。", "教條父老舞，姓字裔夷傳。", "客到牽鈴索，詩成仰屋椽。", "平吞雲夢澤，聊酌隠之泉。"]'),
('bb9d6a4c-8c95-430a-bdf0-5cb645a4b91b','次韻張守塗中逢節二首  其一','陳造','宋','宋诗','song-poetry','','[]','塗中歲遒盡，江影暮澄凝。',48,'全唐诗/poet.song.151000.json','["塗中歲遒盡，江影暮澄凝。", "柏酒惟宗武，河梁似李陵。", "問津田叟傲，捩柂長年能。", "繫纜纔沙觜，人家已上燈。"]'),
('983189e0-9466-4b68-9b68-470886a1eff3','次韻張守塗中逢節二首  其二','陳造','宋','宋诗','song-poetry','','[]','賞心仍令節，十事九相違。',48,'全唐诗/poet.song.151000.json','["賞心仍令節，十事九相違。", "老境家猶遠，愁城日合圍。", "客塗君尚嘆，世路我知非。", "羨殺鄉居子，耕梁木葉衣。"]'),
('c40744ee-5a6d-4797-b212-5d01439014a5','次韻張守與潤守總卿詩四首  其一','陳造','宋','宋诗','song-poetry','','[]','天階玉作筍，此地合垂紳。',48,'全唐诗/poet.song.151000.json','["天階玉作筍，此地合垂紳。", "尚戒專城馭，虛逢籲俊辰。", "公方閲竹馬，名已薦楓宸。", "政恐經綸去，諸公拱後塵。"]'),
('a09fe759-2ad0-4be7-aee4-ca96ecc88ee4','次韻張守與潤守總卿詩四首  其二','陳造','宋','宋诗','song-poetry','','[]','漁樵送晚景，天地著陳人。',48,'全唐诗/poet.song.151000.json','["漁樵送晚景，天地著陳人。", "澗底離奇幹，人間浩蕩春。", "峨冠纔識字，何策可資身。", "不擬千言賦，忉忉慁大鈞。"]'),
('27d28686-6598-4c32-86fa-3789b43b4135','次韻張守與潤守總卿詩四首  其三','陳造','宋','宋诗','song-poetry','','[]','殘年仍舊學，平日亦新書。',48,'全唐诗/poet.song.151000.json','["殘年仍舊學，平日亦新書。", "酒渴今司馬，巖棲昔幼輿。", "夢無三字拜，家有五車儲。", "但諗催詩燭，吾衰冀少徐。"]'),
('bf920ef3-569f-4772-a48b-d1a9c2b19901','次韻張守與潤守總卿詩四首  其四','陳造','宋','宋诗','song-poetry','','[]','向我能忘勢，張侯却甚真。',48,'全唐诗/poet.song.151000.json','["向我能忘勢，張侯却甚真。", "頻分代舍飯，遣濯客裾塵。", "長日無知己，因君愛此身。", "可須砭劑力，振臂起漳濱。"]'),
('0ec2f3b2-2014-4ecd-9226-23e01699d54b','頫江樓分韻得春字','陳造','宋','宋诗','song-poetry','','[]','子政文筆勁，武陵豪氣振。',48,'全唐诗/poet.song.151000.json','["子政文筆勁，武陵豪氣振。", "高騫霄漢步，分占燕鶑春。", "造化歸吟思，罇罍著散人。", "芳時好賓主，載酒未妨頻。"]'),
('e519923a-0972-4c1c-8830-94a1d02fa306','次韻楊宰泛湖','陳造','宋','宋诗','song-poetry','','[]','他日草玄手，效官今武城。',48,'全唐诗/poet.song.151000.json','["他日草玄手，效官今武城。", "端憂計豐歉，行色問陰晴。", "詩酒時陶冶，身名孰重輕。", "猶能記駑蹇，拜賜得瓖纓。"]'),
('63342170-8a1a-4586-9ac1-fab187c3a2ce','次宿北阿韻','陳造','宋','宋诗','song-poetry','','[]','聞道籃輿去，遥崗復近阿。',48,'全唐诗/poet.song.151000.json','["聞道籃輿去，遥崗復近阿。", "詩應弔孝逸，碑或贊頭陀。", "靜者官餬口，公朝禮作羅。", "憐君日阡陌，塵土撲陰何。"]'),
('0262c5b4-9d1d-43d3-99eb-d0b0f12417f3','次韻趙帥四首  其一','陳造','宋','宋诗','song-poetry','','[]','藩方人奠枕，楚尾鐵爲城。',48,'全唐诗/poet.song.151000.json','["藩方人奠枕，楚尾鐵爲城。", "曉日熙仁惠，春雷殷政聲。", "護邊一李勣，增戶幾王成。", "笑指瓊花露，如公徹底清。"]'),
('c1d5a479-fa51-4561-a5b1-b690aacbc898','次韻趙帥四首  其二','陳造','宋','宋诗','song-poetry','','[]','腹裏羣經笥，毫端五字城。',48,'全唐诗/poet.song.151000.json','["腹裏羣經笥，毫端五字城。", "少陵寧漫興，侯喜欲無聲。", "竊聽鏘金奏，仍聞破竹成。", "君知盥手處，毛骨爲誰清。"]'),
('a5c2583f-1202-44be-bdb6-1235f3392b4c','次韻趙帥四首  其三','陳造','宋','宋诗','song-poetry','','[]','我亦飽參僧，贏糧走百城。',48,'全唐诗/poet.song.151000.json','["我亦飽參僧，贏糧走百城。", "諸公傳句法，夫子擅詩聲。", "自笑屠龍誤，時須畫鶩成。", "峨肩出苦語，蛩夜共凄清。"]'),
('14618431-f6a8-440d-9037-14ae7d8ddfc1','次韻趙帥四首  其四','陳造','宋','宋诗','song-poetry','','[]','自昔繁雄地，蕪城壓錦城。',48,'全唐诗/poet.song.151000.json','["自昔繁雄地，蕪城壓錦城。", "惟公工活國，上課已蜚聲。", "富庶幾當日，調虞屬老成。", "歸應演周頌，宗祀奏維清。"]'),
('1af71bd4-d9a8-4b87-8b1a-1fd4073f031a','次韻林子長','陳造','宋','宋诗','song-poetry','','[]','詩壇舊同歃，攀附不無因。',48,'全唐诗/poet.song.151000.json','["詩壇舊同歃，攀附不無因。", "攬轡今膚使，回轅記老身。", "雲泥知已隔，譚笑尚容親。", "不記棋前酒，當時定幾巡。"]'),
('e271d928-a6df-4498-9368-ef14db6e2b8b','次韻趙帥歲暮','陳造','宋','宋诗','song-poetry','','[]','虛心觀物變，投老得詩窮。',48,'全唐诗/poet.song.151000.json','["虛心觀物變，投老得詩窮。", "玄草居然白，爐萁却暫紅。", "詩緣梅雋發，愁倩酒消融。", "未用凌羈客，疎簾逗雪風。"]'),
('9d4dc530-a73a-4356-ab3d-76f31a1887db','次韻小閤','陳造','宋','宋诗','song-poetry','','[]','聞道委蛇地，金虬自炷香。',48,'全唐诗/poet.song.151000.json','["聞道委蛇地，金虬自炷香。", "心雖便靜默，時恐後騫翔。", "物外貯春色，人間占夜光。", "定誰傳句法，俗骨點玄霜。"]'),
('978b81d9-5b2b-4832-ad17-10d91cf3ed74','高宗皇帝挽章四首  其一','陳造','宋','宋诗','song-poetry','','[]','雨露均皇澤，丹青煥帝猷。',48,'全唐诗/poet.song.151000.json','["雨露均皇澤，丹青煥帝猷。", "恢圖自天運，授聖與神謀。", "方眕脩齡夢，俄偕造物游。", "姑山餘四子，不復候瓊輈。"]'),
('d096ff16-44a3-4a45-b771-5f65f3d566b6','高宗皇帝挽章四首  其二','陳造','宋','宋诗','song-poetry','','[]','措俗皇風粹，怡神象帝先。',48,'全唐诗/poet.song.151000.json','["措俗皇風粹，怡神象帝先。", "寶圖傳聖嗣，金闕覲羣僊。", "典訓昭如日，華夷痛所天。", "衣冠游歷地，一一淚河前。"]'),
('1ccf5e16-c1e7-41a4-a21f-bb9988eb8435','高宗皇帝挽章四首  其三','陳造','宋','宋诗','song-poetry','','[]','天地重開闢，華夷赴指揮。',48,'全唐诗/poet.song.151000.json','["天地重開闢，華夷赴指揮。", "羣生欣按堵，三紀仰垂衣。", "鳳歷雖無極，龍樓忽告違。", "廣成譚道處，千古想驂騑。"]'),
('2d8c2cca-e541-4e6d-a55f-546cc7f0f4aa','高宗皇帝挽章四首  其四','陳造','宋','宋诗','song-poetry','','[]','精一心傳後，功隆道固存。',48,'全唐诗/poet.song.151000.json','["精一心傳後，功隆道固存。", "徐乘僊馭去，往儷玉皇尊。", "典誥無遺意，臣民有斷魂。", "嵩靈弓劍望，愁霧慘中原。"]'),
('d2751e7d-8b3c-44d3-a97e-cb27766dc1c5','壽皇聖帝挽章三首  其一','陳造','宋','宋诗','song-poetry','','[]','孝儉超千古，初終秉一心。',48,'全唐诗/poet.song.151000.json','["孝儉超千古，初終秉一心。", "時前未央酒，每惜露臺金。", "遺範天同久，湛恩海與深。", "攀摧慟夷夏，悲淚作秋霖。"]'),
('f794a231-f9b6-4c94-b966-44edf9df6f17','壽皇聖帝挽章三首  其二','陳造','宋','宋诗','song-poetry','','[]','受授光堯禹，規摹陋漢唐。',48,'全唐诗/poet.song.151000.json','["受授光堯禹，規摹陋漢唐。", "皇圖開壽域，國步坦康莊。", "檢玉方慈範，乘雲忽帝鄉。", "華夷均孺慕，矯首涕滂浪。"]'),
('3ba0f788-8a25-4c0b-bdf8-b08da2285843','壽皇聖帝挽章三首  其三','陳造','宋','宋诗','song-poetry','','[]','慈儉遵先志，剛明肖上乾。',48,'全唐诗/poet.song.151000.json','["慈儉遵先志，剛明肖上乾。", "題期千一遇，躋治五三前。", "他日山藏壑，終天澤漏泉。", "稽山穿望眼，松影五雲連。"]'),
('5f4c9599-ff5f-4c9e-a79e-509ed0058f23','强同年次子挽詩二首  其一','陳造','宋','宋诗','song-poetry','','[]','識子初衿佩，嶄然自夙成。',48,'全唐诗/poet.song.151000.json','["識子初衿佩，嶄然自夙成。", "風猷乃公似，文字老夫驚。", "遽隕連城器，難推造物情。", "新宮漫仙伯，政復待君銘。"]'),
('8bcd6062-60b8-4e1c-a43a-65fdff1f2b46','强同年次子挽詩二首  其二','陳造','宋','宋诗','song-poetry','','[]','弱歲不好弄，俯窺同隊魚。',48,'全唐诗/poet.song.151000.json','["弱歲不好弄，俯窺同隊魚。", "開編便頭角，諸老辦吹噓。", "囊錦餘詩草，悲風忽輤車。", "人今埋玉恨，清淚灑衣裾。"]'),
('08b3ee22-67b8-45ac-92ef-61373cd7a064','黄尉挽章二首  其一','陳造','宋','宋诗','song-poetry','','[]','傳緒祖風懿，居鄉家道肥。',48,'全唐诗/poet.song.151000.json','["傳緒祖風懿，居鄉家道肥。", "羣書了漁獵，一性自弦韋。", "官僅紆黄綬，時須補黑衣。", "空纏百身恨，遽作九原歸。"]'),
('7ff25d1a-ff8f-48fe-a435-24b7096a07c2','黄尉挽章二首  其二','陳造','宋','宋诗','song-poetry','','[]','落筆心猶壯，論年鬢未斑。',48,'全唐诗/poet.song.151000.json','["落筆心猶壯，論年鬢未斑。", "硯捐初鑄鐵，澤失善藏山。", "談麈那容數，靈輀去莫攀。", "松阡縈望眼，衰淚可勝潸。"]'),
('5326e038-ead8-422d-a307-1da6b774a2ea','李粹伯挽章二首  其一','陳造','宋','宋诗','song-poetry','','[]','今代論時傑，如公未易量。',48,'全唐诗/poet.song.151000.json','["今代論時傑，如公未易量。", "冰壺鍾器質，繡段粲文章。", "遂鬰鸞臺望，俄成馬鬣藏。", "忠賢如此爾，天意竟茫茫。"]'),
('99a7ec08-2e7f-44e7-b180-fcce6e63db2c','李粹伯挽章二首  其二','陳造','宋','宋诗','song-poetry','','[]','病酒漳濱久，傳聞信復疑。',48,'全唐诗/poet.song.151000.json','["病酒漳濱久，傳聞信復疑。", "爲郎真地下，哭友漫天涯。", "雨紼何由挽，風松想助悲。", "自今思有道，時展蔡邕碑。"]'),
('043d14bc-02b6-4035-a2e6-fc033fe2a291','九日','陳造','宋','宋诗','song-poetry','','[]','樽俎天風度，亭高眼界寬。',72,'全唐诗/poet.song.151000.json','["樽俎天風度，亭高眼界寬。", "江山對吹帽，煙雨入凭欄。", "蟻酒傾靈液，霜花碎辟寒。", "樂長回過鴈，香細靄雙狻。", "樂事酬佳節，千金命一歡。", "燈前喚歸騎，星漢已闌干。"]'),
('95f8c6fa-3498-4f70-94fc-386bfd7547a6','次韻盛教授','陳造','宋','宋诗','song-poetry','','[]','詞章有餘力，老色嘆侵尋。',240,'全唐诗/poet.song.151000.json','["詞章有餘力，老色嘆侵尋。", "况苦漳濱卧，俄聆正始音。", "新篇驚間發，平處冠來今。", "脩月無前手，凌雲得此心。", "葩華分子細，矛戟駭陰森。", "玉楮何勞刻，於菟不易擒。", "競傳平水市，或博樂浪金。", "妙斲風無迹，窮搜海并深。", "與時猶落落，逼古謾駸駸。", "襆被征塵暗，臨流鬢雪侵。", "徐驅憐老驥，決起羨驚禽。", "善價渠能許，清愁可得禁。", "不無青白眼，聊費短長吟。", "頃歲欣相識，高山慰所欽。", "周旋窺義府，衰朽謝書林。", "適越慙荒陋，依劉耐滯淫。", "交情向來密，詩病幾時箴。", "遲子迂軒蓋，呼奴潔釜鬵。", "萁爐足幽趣，玉唾滌煩襟。", "斗酒窮簷日，招摇得共斟。"]'),
('d8f2d067-512e-4357-b71d-bd99fe6f3917','再遊殖軒小酌','陳造','宋','宋诗','song-poetry','','[]','生世岐喧靜，平章有不如。',144,'全唐诗/poet.song.151000.json','["生世岐喧靜，平章有不如。", "宦塗吾畫虎，濠上子知魚。", "去索長安米，歸紬笠澤書。", "茲軒住蒼莽，勝日復躊躇。", "酒盞扶頭後，鶑聲禁火餘。", "蘭風度樽俎，蝶翅掠襟裾。", "有底煙霄意，便爲水竹居。", "可須供麴糵，未後課耰鉏。", "花蓓紅酣日，池光碧浸虛。", "鶴頭依綠荇，龍骨閙清渠。", "詩興因超忽，愁端得破除。", "時從一吟醉，小計百硨磲。"]'),
('47cdfda3-b50e-4c66-ae9d-ac74d0f8bc1e','送羅提舉','陳造','宋','宋诗','song-poetry','','[]','萬口歌謠裏，臨岐挽使車。',240,'全唐诗/poet.song.151000.json','["萬口歌謠裏，臨岐挽使車。", "五雲金碧際，平步闖天居。", "皇眷須裨益，清朝有詔除。", "致君真夙素，活國此權輿。", "壯歲持英節，春風滿比閭。", "民皆樂耕鑿，吏敢狃侵漁。", "日者流離嘆，時方旱暵餘。", "飽饑親勞來，骨肉費勤渠。", "汲直開倉後，韓公報政初。", "重前漢皇席，肯挾子公書。", "冠豸傳應實，嬰鱗可待徐。", "規恢今日事，抱負與時攄。", "吏治捐邦蠹，羣妖信鼎魚。", "衰翁憐命蹇，違世坐才疎。", "但有江山助，曾無甔石儲。", "登門仍造次，作意借吹噓。", "此去遊丹地，能無薦子虛。", "壯心翔碧落，歸夢謝黄淤。", "凝睇成分袂，從人更曳裾。", "念爲天下賀，不擬賦愁予。"]'),
('e8e113cc-a4c8-446a-9f90-c68356aace61','謝龔養正病後分藥','陳造','宋','宋诗','song-poetry','','[]','如許卧痾久，入春知少蘇。',144,'全唐诗/poet.song.151000.json','["如許卧痾久，入春知少蘇。", "遽能捐藥物，分惠及吾徒。", "字驗親題健，形非賤子臞。", "人情工老芋，友意寓柴胡。", "怪底陰陽寇，偏陵山澤儒。", "從君足力減，嘆我酒腸枯。", "解橐供砭劑，投筇試步趨。", "身方困厲鬼，名已屬亨衢。", "書蠹妨生理，盃蛇可自誣。", "斯文千歲計，平世萬金軀。", "大手堪周史，諸公待董狐。", "幾時隨急詔，帆影漾前湖。"]'),
('6b89c53e-a340-4eb7-b07f-660beb147a41','勸農書浄居壁','陳造','宋','宋诗','song-poetry','','[]','小出成休務，徐驅免戴星。',72,'全唐诗/poet.song.151000.json','["小出成休務，徐驅免戴星。", "風枝禽磔磔，煙隴麥青青。", "蕭寺蜚塵外，行軒數刻停。", "賸呼黄髮叟，看卧碧香瓶。", "庶富幾無憾，耕桑飽所經。", "由衷疎直語，或可比閭聽。"]'),
('a6f219cb-99b8-46d8-8bb0-48de4840245a','寄顧簽判','陳造','宋','宋诗','song-poetry','','[]','版財虛占籍，爲弊與年深。',96,'全唐诗/poet.song.151000.json','["版財虛占籍，爲弊與年深。", "挹酒空名斗，無虞可即禽。", "焦頭寧自救，捫舌未渠瘖。", "上幕真時望，平居念陸沈。", "蠲痾丹九轉，援墜綆千尋。", "容易令公喜，恩勤獲我心。", "益昌留署考，神武貸抽簪。", "厚德何容報，交情擬斷金。"]'),
('134281ac-765f-4f8b-8367-7dd1d25b19c5','飲寓隠','陳造','宋','宋诗','song-poetry','','[]','軒亭曉清曠，行樂未妨頻。',144,'全唐诗/poet.song.151000.json','["軒亭曉清曠，行樂未妨頻。", "無客不堪醉，有花長是春。", "憑欄尚紅藥，結伴擅芳辰。", "笑駐凌波步，香分折角巾。", "鶑聲殊自健，杏子况嘗新。", "仰止宗英伯，來爲鄭驛賓。", "言辭獨樂樂，仍命可人人。", "鴻弄舞時影，梁蜚歌處塵。", "棋枰誰得雋，詩筆自疑神。", "欹倒何妨屢，歌呼却甚真。", "升沈塞上馬，容易鬢如銀。", "奈許追歡地，回頭迹便陳。"]'),
('63da4c42-aa29-44ed-b61f-1a8be3d70fa6','再遊福溪巖贈主僧','陳造','宋','宋诗','song-poetry','','[]','山路細縈蛇，欹危訝泛槎。',144,'全唐诗/poet.song.151000.json','["山路細縈蛇，欹危訝泛槎。", "幽人肯假榻，倦客似還家。", "柏徑初軒豁，筠窗更靜嘉。", "饑腸如作苦，齋鼓恰停撾。", "茶供含秋露，菘葅带早花。", "香秔有炊玉，煮餠不摇牙。", "好在經行處，還憐舊約差。", "摩挱驗蛇蚓，圓缺屢蝦蟇。", "境信人俱勝，心寧迹與遐。", "農時多閔雨，意緒每如麻。", "却話三生契，空嗟兩鬢華。", "蒲團坐雙穩，良夜對篝紗。"]'),
('efe3b497-523d-410b-9f86-93f55b314a4d','均州贈應守沈倅','陳造','宋','宋诗','song-poetry','','[]','聞道均陽郡，平時百萬家。',288,'全唐诗/poet.song.151000.json','["聞道均陽郡，平時百萬家。", "客行休訪古，世異定興嗟。", "逐逐纔爲市，通通亦摻撾。", "僅成新聚落，那復舊豪奢。", "屬者歌簫地，連畦蔓瓠瓜。", "今來冠蓋侶，薦筯欠魚蝦。", "狹路幾沙磧，頹垣賸土花。", "街塵坌鳥雀，屋影暗桑麻。", "恐有如鴞鵩，仍驚攫肉鴉。", "遺基滿空闊，面勢踞谽谺。", "一水紆龍脊，羣峯簉犬牙。", "封疆界梁楚，形勝引黔巴。", "郡計稽圖牒，農功富秉秅。", "吏庸常報最，帝澤向來賒。", "劫火延中夏，髦頭震四遐。", "風聲離夷裔，俗習墮奇衷。", "穀蓄寧關慮，山荒久廢畬。", "腰間尚牛犢，籬脚漫豵豝。", "久矣皇恩洽，悠哉戶籍加。", "帥車初柅軌，倅戍未歸槎。", "厚本還千載，移風待兩衙。", "撫摩端不苟，悃愊信無華。", "巳日知胥悅，爲生漸有涯。", "耕耘捐末務，惰窳棄前瑕。"]'),
('4acb3800-32ab-4ab3-bcdd-f831b6e35dab','赭圻','陳造','宋','宋诗','song-poetry','','[]','朱旗僅奏蜀川功，咫尺中原未向風。',64,'全唐诗/poet.song.151000.json','["朱旗僅奏蜀川功，咫尺中原未向風。", "禮接謝安猶故舊，心知越石是英雄。", "生前逆氣無宗國，身後餘殃有狡童。", "忍對青山話遺臭，人生過鳥抹秋空。"]'),
('93357344-fb4a-479c-b370-b26960e4edc3','閒題','陳造','宋','宋诗','song-poetry','','[]','自笑冠裳裹沐猴，只今江海信虛舟。',64,'全唐诗/poet.song.151000.json','["自笑冠裳裹沐猴，只今江海信虛舟。", "斷無貝闕珠宮夢，好在黄鷄紫蟹秋。", "詩外盡爲閑日月，人間分占素公侯。", "政須鷗鷺供青眼，未厭山林映白頭。"]'),
('5cfebef3-528a-45de-acb9-878526b500e5','飲客','陳造','宋','宋诗','song-poetry','','[]','暑氣憑秋已自消，可能枯策伴良宵。',64,'全唐诗/poet.song.151000.json','["暑氣憑秋已自消，可能枯策伴良宵。", "試開玉友招詩客，共吸金波對舞腰。", "人近笙歌堪耐老，天非風月定無聊。", "簿書正使無閑暇，卜夜時須慰寂寥。"]'),
('58488715-b59e-4101-8451-11fb91c4f428','次丁嘉會韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','倦駐頻題醉後襟，離羣自嘆闕知音。',64,'全唐诗/poet.song.151000.json','["倦駐頻題醉後襟，離羣自嘆闕知音。", "卜鄰未暇論前約，著語聊須慰此心。", "小挽歸軒清夜飲，憶嘗對卧白頭吟。", "中年畏別猶輕別，添我霜毛又幾尋。"]'),
('b0856430-fc5b-4ae9-8a20-e59589dec2b8','次丁嘉會韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','塵裏清風忽滿襟，詩成正始識遺音。',64,'全唐诗/poet.song.151000.json','["塵裏清風忽滿襟，詩成正始識遺音。", "才輕餘子今文舉，氣壓諸豪復季心。", "棋罷蠟燈銜燼暗，酒闌庭樹挾霜吟。", "百年衮衮須今夕，歲晚鷗盟要重尋。"]'),
('5a4a4b98-d861-4b6f-af17-49dfe1860cb1','再用韻寄丁知縣三首  其一','陳造','宋','宋诗','song-poetry','','[]','旗亭風月小披襟，慰我東歸聽足音。',64,'全唐诗/poet.song.151000.json','["旗亭風月小披襟，慰我東歸聽足音。", "潮水去來當有信，岫雲出入自無心。", "酒盃乘興從妨夢，詩律緣愁久廢吟。", "明日揚舲回白首，烟橫北固櫂千尋。"]'),
('1df20620-e214-45d2-b781-4f1daf555b69','再用韻寄丁知縣三首  其二','陳造','宋','宋诗','song-poetry','','[]','南樓酌酒未分襟，啅鵲啼烏亦好音。',64,'全唐诗/poet.song.151000.json','["南樓酌酒未分襟，啅鵲啼烏亦好音。", "晴日倒紅生笑頰，烟梧摇淥漲盃心。", "可堪歲月供行色，盡把江山博醉吟。", "不繼蕪湖留十日，焦峯浮玉恣幽尋。"]'),
('b6ef04e1-67ee-4425-b3bb-a43b929c00d0','再用韻寄丁知縣三首  其三','陳造','宋','宋诗','song-poetry','','[]','別時把酒欲霑襟，楚翼吳鱗要嗣音。',64,'全唐诗/poet.song.151000.json','["別時把酒欲霑襟，楚翼吳鱗要嗣音。", "撞玉饜聽辭客語，斷金深得故人心。", "對床風雨終前約，滿眼湖山念獨吟。", "何日水雲淮上宅，草荒三徑肯深尋。"]'),
('dab8098c-c06d-4865-b70e-8639b88b2b61','念衰','陳造','宋','宋诗','song-poetry','','[]','心意彫殘底自娛，每臨清鏡笑頭顱。',64,'全唐诗/poet.song.151000.json','["心意彫殘底自娛，每臨清鏡笑頭顱。", "詩從多病難爲好，官過中年劣勝無。", "急景驅秋著髭鬢，歸鴻銜夢下江湖。", "更應載酒高陽伴，誤輟歌呼話故吾。"]'),
('1f674068-5aab-4f8c-9df8-82fa64772db1','閑適二首  其一','陳造','宋','宋诗','song-poetry','','[]','人間火烈更風蜚，笑殺幽人詠檜枝。',64,'全唐诗/poet.song.151000.json','["人間火烈更風蜚，笑殺幽人詠檜枝。", "貪赴敵場爭腐鼠，寧知造物玩癡兒。", "百年擾擾玄駒聚，萬化悠悠野馬馳。", "老子床頭但周易，尚容隠几耐支離。"]'),
('d4235468-d365-4ad1-ac7e-3006190c6c10','閑適二首  其二','陳造','宋','宋诗','song-poetry','','[]','丁年故紙枉埋頭，老去時名底用求。',64,'全唐诗/poet.song.151000.json','["丁年故紙枉埋頭，老去時名底用求。", "得句蓋嘗身被謗，屏書姑免眼爲仇。", "關門工作橐駝坐，閲世已冥鵬鷃遊。", "槁木山麋真適適，從來里舍議家丘。"]'),
('b59b12e9-81de-42ca-b9de-c9d196e7d0a8','九日留交代','陳造','宋','宋诗','song-poetry','','[]','歸軒小駐莫匆匆，佳節胡宜客路中。',64,'全唐诗/poet.song.151000.json','["歸軒小駐莫匆匆，佳節胡宜客路中。", "已締金蘭千載契，政思萸菊一樽同。", "磕山烟薄秋容瘦，槐衮簾疎晚照紅。", "此興向君殊不淺，要看醉帽受西風。"]'),
('732a280b-9759-4852-abed-400e078bc2c6','次韻蘇監倉二首  其一','陳造','宋','宋诗','song-poetry','','[]','交朋又得一相如，高掩虞郎行祕書。',64,'全唐诗/poet.song.151000.json','["交朋又得一相如，高掩虞郎行祕書。", "妙論析微驚我倒，諸生到眼可人無。", "一官幸此分鄰燭，五字渠能攬虎鬚。", "快讀清篇病如掃，北軒風竹對森疎。"]'),
('cc011177-12a0-4981-9969-a840d266cd23','次韻蘇監倉二首  其二','陳造','宋','宋诗','song-poetry','','[]','長日奔馳傳置如，久妨著論與抄書。',64,'全唐诗/poet.song.151000.json','["長日奔馳傳置如，久妨著論與抄書。", "逢人爭席有時有，疥壁留詩無處無。", "禦寇未辭躬楚製，論文常憶攬桓鬚。", "扁舟再有東游便，肯向朋從自作疎。"]'),
('beaa68ca-2723-4518-9052-ed03618cbc50','再次前韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','未說高文錦不如，談間已勝十年書。',64,'全唐诗/poet.song.151000.json','["未說高文錦不如，談間已勝十年書。", "是中我亦潛心久，作者君今舉世無。", "應俗不堪塵瞇目，論交政復棘如鬚。", "獨憐兒戲心猶在，更向詩筒較戚疎。"]'),
('7707d5f2-0e18-4b7e-8d39-5b65fc4c1d45','再次前韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','倉官尉職賤誰如，終歲區區奉簡書。',64,'全唐诗/poet.song.151000.json','["倉官尉職賤誰如，終歲區區奉簡書。", "勝日偷閑須著便，青山有約定來無。", "著書聊閣如椽筆，疾惡休張磔蝟鬚。", "好袖新瓢五峯路，碧淙清樾伴蕭疎。"]'),
('9ac4c7a0-05e5-4e9f-a3aa-1640a852882f','縣圃酴醾','陳造','宋','宋诗','song-poetry','','[]','北園紅紫已蜚塵，始放幽亭爛熳春。',64,'全唐诗/poet.song.151000.json','["北園紅紫已蜚塵，始放幽亭爛熳春。", "疊翠影低珠幰重，洗粧人倦玉容真。", "薔薇清露疑分派，茉莉評香且外臣。", "領略濃芳須好語，即令袖手恐花嗔。"]'),
('53fbc729-7f11-486d-94a6-cb05a112ac53','賞酴醾病不赴','陳造','宋','宋诗','song-poetry','','[]','不得花前共一樽，蕭齋藥裹自相親。',64,'全唐诗/poet.song.151000.json','["不得花前共一樽，蕭齋藥裹自相親。", "閑追水佩風裳夢，空負雲階月地春。", "縹緲瑶英霧爲幄，敷腴玉面酒生鱗。", "蜚觴刻燭輸公等，定指芳條笑惡賓。"]'),
('0c1b32d3-9681-4ed5-b2cf-aac24ee7fca5','次陳宰韻','陳造','宋','宋诗','song-poetry','','[]','觥籌交錯舞僛僛，曉色侵窗客未知。',64,'全唐诗/poet.song.151000.json','["觥籌交錯舞僛僛，曉色侵窗客未知。", "便整醉魂乘款段，尚餘吟興屬酴醾。", "還家擬趁寶瓔珞，喚客重乾金屈巵。", "著意風煙與調護，免教花意恨歸遲。"]'),
('4ea471bd-5105-4fed-952c-aaa950261882','徐陶會','陳造','宋','宋诗','song-poetry','','[]','松底軒窗卸虎韉，竹簾閑褭石爐烟。',64,'全唐诗/poet.song.151000.json','["松底軒窗卸虎韉，竹簾閑褭石爐烟。", "山間風日小春後，會裏杯盤長至前。", "蟻子醪敷能及客，彈圓侯栗不論錢。", "巖棲野嘯平生意，失脚塵埃雪滿顛。"]'),
('72ffc30a-7479-49e8-82d2-48d060bfee7b','即事','陳造','宋','宋诗','song-poetry','','[]','泛蟻醪敷且命斟，中年節物自關心。',64,'全唐诗/poet.song.151000.json','["泛蟻醪敷且命斟，中年節物自關心。", "風前千柳競春態，烟際一鳩啼晏陰。", "急景絕憐添鬢雪，芳辰猶阻盍朋簪。", "年時醉藉梨花地，回首鷗盟可得尋。"]'),
('4594174b-36d5-4dae-9d13-8d769dc07d66','縣西','陳造','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一徑斜穿犖确行，身閑尤覺馬蹄輕。',64,'全唐诗/poet.song.151000.json','["一徑斜穿犖确行，身閑尤覺馬蹄輕。", "坡頭嘉樹千幢立，烟際長江匹練橫。", "茶鼓適敲靈鷲院，夕陽欲壓赭圻城。", "一春簿領沈迷裏，野鳥山花眼最明。"]'),
('79f1b0c0-6e77-4275-aade-5b8bef53495f','上峨橋早行','陳造','宋','宋诗','song-poetry','','[]','一從箠楚替陳編，漸慣山行野店眠。',64,'全唐诗/poet.song.151000.json','["一從箠楚替陳編，漸慣山行野店眠。", "白氎風霜鷄唱後，黄塵岐路馬蹄前。", "光陰付我千莖雪，伏臘何時二頃田。", "寄語淮鄉隠君子，浪言梅福是神仙。"]'),
('66ba4b37-0a23-4cc7-bbcf-34446308f17b','寄幼度主簿','陳造','宋','宋诗','song-poetry','','[]','辭家暑雨濺紅蕖，轉首蕎花已雪如。',64,'全唐诗/poet.song.151000.json','["辭家暑雨濺紅蕖，轉首蕎花已雪如。", "歲月祇隨流水逝，笑談陡與故人疎。", "簡書我正罷長道，歸棹君行指舊居。", "他日霜風吹夢破，空從旅鴈覓來書。"]'),
('f69867b3-257e-445c-aa25-399218a65138','和張秀才','陳造','宋','宋诗','song-poetry','','[]','山川向晚點塵無，忽訝篩瓊屑玉鋪。',64,'全唐诗/poet.song.151000.json','["山川向晚點塵無，忽訝篩瓊屑玉鋪。", "巧與梅花爭便旋，試將姑射比肌膚。", "破寒春酒何曾釅，薦筯窮鳩不料臞。", "陵藉東君從作意，未妨芽甲暗昭蘇。"]'),
('193863f0-c345-40d3-a594-322e94d78147','雪晴再用韻','陳造','宋','宋诗','song-poetry','','[]','龍燭飛空雪漸無，光摇窮巷麗金鋪。',64,'全唐诗/poet.song.151000.json','["龍燭飛空雪漸無，光摇窮巷麗金鋪。", "妓樓遽喜春生座，席戶渾驚粟在膚。", "剡水不須乘興去，飯山猶是作詩臞。", "自憐白髮疎慵客，擁被高舂夢未蘇。"]'),
('31434307-4284-4fd5-aa43-e6cf99467fe0','次韻早春','陳造','宋','宋诗','song-poetry','','[]','良辰邀醉得錢無，雪後郊原翠欲鋪。',64,'全唐诗/poet.song.151000.json','["良辰邀醉得錢無，雪後郊原翠欲鋪。", "無力晚風摇柳線，有情新日養花膚。", "尋芳擬貸愁邊意，照水還驚病後臞。", "春到祇思爲圃樂，賸移杞菊種鷄蘇。"]'),
('0fee49bb-8e97-492e-ae35-4473202914b3','次韻張秀才雪','陳造','宋','宋诗','song-poetry','','[]','可是春皇吝物華，羣仙剪水作奇葩。',64,'全唐诗/poet.song.151000.json','["可是春皇吝物華，羣仙剪水作奇葩。", "壺中天地渾糜玉，風處園林盡勒花。", "宿火煖寒聊榾柮，夜光落手忽驚嗟。", "忍饑遽擬搜詩謝，何異空腸更飲茶。"]'),
('3037c5af-0902-46a2-9d4b-60247169cada','用前韻酬雪霽','陳造','宋','宋诗','song-poetry','','[]','東風吹暖擅年華，不放江雲颺素葩。',64,'全唐诗/poet.song.151000.json','["東風吹暖擅年華，不放江雲颺素葩。", "嫩碧忽看摇水面，暗香已復辨梅花。", "塵埃憐我褐之父，名德思君留子嗟。", "沈辱清詩祛滯思，真成酒病薦真茶。"]'),
('d13e0c5c-2f4c-424d-9594-ce138dab59da','寄丁主簿','陳造','宋','宋诗','song-poetry','','[]','江邊聚首偶經旬，自挽園蔬拂甑塵。',64,'全唐诗/poet.song.151000.json','["江邊聚首偶經旬，自挽園蔬拂甑塵。", "老檜根株官舍古，凉蟬風露賊曹貧。", "斑騅去後情無那，紫燕飛還句更新。", "一舸東浮待秋老，菊花蘆葉定留賓。"]'),
('0ef8f403-626e-424a-97a9-7060e972ecbb','寄林子長教授','陳造','宋','宋诗','song-poetry','','[]','芹堂風景幾經過，匝坐紅蕖倚綠荷。',64,'全唐诗/poet.song.151000.json','["芹堂風景幾經過，匝坐紅蕖倚綠荷。", "下筯慣嘗雲子味，開樽仍費雪兒歌。", "官移催我離羣去，夢境思君樂事多。", "鴈足寄詩情未薄，却慙屬和付羊何。"]'),
('13ef929d-aa6c-4a66-8146-98225e3a17bd','楊家會小坐','陳造','宋','宋诗','song-poetry','','[]','斷蜺收盡有雲屯，月映蒼茫山斂昏。',64,'全唐诗/poet.song.151000.json','["斷蜺收盡有雲屯，月映蒼茫山斂昏。", "白露素空猶暑意，碧林危葉已秋痕。", "鳥烏定爲何人樂，絡緯惟能竟夕喧。", "老閲流光易悽惋，惜無佳客共清樽。"]'),
('ef38d73a-3100-4a8f-8b25-90c04b993600','七夕','陳造','宋','宋诗','song-poetry','','[]','龍旌鳳扇一相迎，知費青禽幾寄聲。',64,'全唐诗/poet.song.151000.json','["龍旌鳳扇一相迎，知費青禽幾寄聲。", "天上經年纔舊約，人間轉盼便深更。", "凉河只向樽前落，微月偏來酒面明。", "後夜玉琴彈別鶴，獨應乾鵲夢魂驚。"]'),
('05ea9846-a4dd-4552-b6be-4376e6249de9','復程平叔','陳造','宋','宋诗','song-poetry','','[]','早歲雄文手自編，偶同聞喜聽鈞天。',64,'全唐诗/poet.song.151000.json','["早歲雄文手自編，偶同聞喜聽鈞天。", "漫爲官去吾何取，肯寄詩來子定賢。", "潘岳自憐頭易白，士安况苦病相纏。", "羨君身健須如漆，萬里亨衢穩著鞭。"]'),
('37a7f465-25af-45a0-8a6b-4380b9bb1728','汪叔量白酒','陳造','宋','宋诗','song-poetry','','[]','妙訣何年受異人，釀成珍齊祇逡巡。',64,'全唐诗/poet.song.151000.json','["妙訣何年受異人，釀成珍齊祇逡巡。", "端憂肯念霜髯客，取醉時分玉色春。", "篘處想如君德厚，飲來渾類我詩醇。", "借書問字渠須計，走馬鳴鞭莫厭頻。"]'),
('5edf9154-b73a-4214-a864-9511f438e085','寄鄉中親舊','陳造','宋','宋诗','song-poetry','','[]','携書憶上上江船，撚指官曹欲二年。',64,'全唐诗/poet.song.151000.json','["携書憶上上江船，撚指官曹欲二年。", "白傅病多空自嘆，老坡仙去却虛傳。", "人生脩短庸非命，我判浮休不問天。", "來歲過君定驚笑，尚堪詩酒與周旋。"]'),
('2f7b1de5-572c-4410-87d8-482e9588b54f','隠靜簡堂老贈籐杖','陳造','宋','宋诗','song-poetry','','[]','兩枝籐杖各過頭，一贈詩翁一自留。',64,'全唐诗/poet.song.151000.json','["兩枝籐杖各過頭，一贈詩翁一自留。", "借力崎嶇知意厚，分岐喧靜果誰優。", "拄歸山路煙嵐好，橫向禪堂魔魅愁。", "償盡阿師行脚債，不妨分我老滄洲。"]'),
('5fe52908-ff88-4e69-99d9-4b75428311e4','次韻楊樞視圩遊隠靜','陳造','宋','宋诗','song-poetry','','[]','勸相江糜畚鍤忙，却回小隊訪山房。',64,'全唐诗/poet.song.151000.json','["勸相江糜畚鍤忙，却回小隊訪山房。", "松風不約爐烟直，晝晷潛隨僧話長。", "政外輟閑知有味，區中得醉浪名鄉。", "銅丸好句長哦罷，坐聽驚猿墮莽蒼。"]'),
('55c95b67-7fa7-4c10-9b33-cc5a95805b0e','次韻楊樞喜雨','陳造','宋','宋诗','song-poetry','','[]','神護天關色正莊，挽回帝眷一絲香。',64,'全唐诗/poet.song.151000.json','["神護天關色正莊，挽回帝眷一絲香。", "人間雨信先鳴鸛，仙界雷翁叱卧羊。", "剡剡青秧迷迥野，浮浮白水溜方塘。", "豐年信出爲霖手，懇悃憂民意叵忘。"]'),
('6adddeb4-914a-41b6-baf5-3e41af862623','病中書懷二首  其一','陳造','宋','宋诗','song-poetry','','[]','少日清孤效樂天，諫書未落世間傳。',64,'全唐诗/poet.song.151000.json','["少日清孤效樂天，諫書未落世間傳。", "曾圓八節灘頭夢，重了三生石上緣。", "雪竹霜林便老境，蒲團禪板付臞仙。", "詩篇把玩真聊爾，古井無波敢自賢。"]'),
('e5aa8652-0081-409d-ba5a-7eca852d9f32','病中書懷二首  其二','陳造','宋','宋诗','song-poetry','','[]','促促浮生忽二毛，安心有法頼禪逃。',64,'全唐诗/poet.song.151000.json','["促促浮生忽二毛，安心有法頼禪逃。", "夢知二豎今相避，仇問三彭底許饕。", "世路從今蝸兩角，燈窗姑置兔千毫。", "破顔細點功名錄，祇許淵明酒處高。"]'),
('94d065cc-48ca-4148-a11b-b0e6b7226e95','次韻元卿二首  其一','陳造','宋','宋诗','song-poetry','','[]','君自才高與世疎，我頑能使此溪愚。',64,'全唐诗/poet.song.151000.json','["君自才高與世疎，我頑能使此溪愚。", "醫師久已肱三折，賦客枵然屋四隅。", "莫道十年同好惡，相過一笑間憂虞。", "胸中圭角今餘幾，詩膽由來已破觚。"]'),
('04e78ca1-4ac3-4782-85b6-ddecf6f1f9d1','次韻元卿二首  其二','陳造','宋','宋诗','song-poetry','','[]','笑携佳句又衝寒，政用消憂觴詠間。',64,'全唐诗/poet.song.151000.json','["笑携佳句又衝寒，政用消憂觴詠間。", "酒賤粗能留子醉，食貧未暇慘予顔。", "搜詩杜老方須藥，强項蕭生且抱關。", "舊約偶耕猶念否，霜林雪竹正斕斑。"]'),
('c4d8735d-daf3-4be1-ad70-28f1bebae4a0','次韻劉宰','陳造','宋','宋诗','song-poetry','','[]','傾蓋回舟一再逢，向來淮左又江東。',64,'全唐诗/poet.song.151000.json','["傾蓋回舟一再逢，向來淮左又江東。", "自驚歲鑰催衰白，况說京塵踏軟紅。", "吏役吾方百寮底，詩工君更古人中。", "挽留重試傳杯手，得醉歌呼興未窮。"]'),
('dda3ede2-a241-49d0-ac10-9c2ed286b3db','夏夜飲客','陳造','宋','宋诗','song-poetry','','[]','矻矻官曹興易窮，得閑何惜一樽同。',64,'全唐诗/poet.song.151000.json','["矻矻官曹興易窮，得閑何惜一樽同。", "傍愁邊到無惡客，從竹間來皆好風。", "勝日詩狂輸酒聖，轉頭渭北復江東。", "雕鞍未作扶携去，更放蘭缸子夜紅。"]'),
('c2690c6b-edbf-4186-9026-5d84c0802bb1','贈趙監嶽','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','才俊如君士論推，下交從昔最知歸。',64,'全唐诗/poet.song.151000.json','["才俊如君士論推，下交從昔最知歸。", "談間八面無餘敵，酒處千金不當揮。", "方辦西湖陪語笑，預愁南浦訴分違。", "只今又捧江西檄，連夜驚魂夢打磯。"]'),
('87356df3-8199-4b03-add3-7d7d164751d0','行都','陳造','宋','宋诗','song-poetry','','[]','露冷河傾斗柄低，望仙橋外獨歸時。',64,'全唐诗/poet.song.151000.json','["露冷河傾斗柄低，望仙橋外獨歸時。", "風梳御柳娟娟靜，月度觚稜故故遲。", "幾處清歌留客醉，誰家長笛倚樓吹。", "太平喜樂朝仍暮，帝力何曾爾輩知。"]'),
('33ccda2f-88f0-4849-8511-4e16f16c50d6','春晚郊外','陳造','宋','宋诗','song-poetry','','[]','輕雲閣雨不成飛，稍喜行軒貸夾衣。',64,'全唐诗/poet.song.151000.json','["輕雲閣雨不成飛，稍喜行軒貸夾衣。", "帝里園林春欲老，人家簾幕燕初歸。", "滄灣潮應沙痕瘦，碧隴烟生麥浪肥。", "眼底湖山聊著句，那憂樂事與心違。"]'),
('1805303e-dcb2-450b-b0ad-37927203507c','託人賣馬二首  其一','陳造','宋','宋诗','song-poetry','','[]','伴我山城慣嶮巇，長因馬健感吾衰。',64,'全唐诗/poet.song.151000.json','["伴我山城慣嶮巇，長因馬健感吾衰。", "三年粗了癡兒事，併日猶嗟竈婦炊。", "會見千金市龍種，可能一笑換蛾眉。", "還家劣有枯籐在，神駕尻輪得自欺。"]'),
('4b387a9a-62a3-4052-80c6-0d89f86e9043','託人賣馬二首  其二','陳造','宋','宋诗','song-poetry','','[]','閑人徐步覺優游，馬似羞貧意不留。',64,'全唐诗/poet.song.151000.json','["閑人徐步覺優游，馬似羞貧意不留。", "久厭短衣隨射虎，更憐匣劍佩耕牛。", "楚山好處聊雙屩，淮水生時辦一舟。", "如子長才當柄用，佇看干旆擁鳴騶。"]'),
('2e6a0e18-df7f-4763-9525-f929005ce9d3','次韻王知軍雪','陳造','宋','宋诗','song-poetry','','[]','雪神濡物不遺時，嗣歲懸知羨帝祺。',64,'全唐诗/poet.song.151000.json','["雪神濡物不遺時，嗣歲懸知羨帝祺。", "沙界積蘇煩阿母，天仙剪水倩風姨。", "郢城曲好無前調，梁苑賓來有後期。", "未辦壺天陪一笑，夜深空歛索詩眉。"]'),
('510bdac4-d15f-4879-ae30-155e4dc6e524','次韻汪解元','陳造','宋','宋诗','song-poetry','','[]','萬里亨衢子舊期，故人留眼看蜚馳。',64,'全唐诗/poet.song.151000.json','["萬里亨衢子舊期，故人留眼看蜚馳。", "低回尚作風黧面，遇合何妨物在頤。", "落筆每驚風雨駛，探囊或恐鬼神悲。", "禹門合有龍頭信，小待桃花浪暖時。"]'),
('a2f10e8a-48f4-455b-a2d9-dee2f033d479','次韻王知軍夜坐有懷','陳造','宋','宋诗','song-poetry','','[]','夢想天兵下不其，壯心摇蕩受風枝。',64,'全唐诗/poet.song.151000.json','["夢想天兵下不其，壯心摇蕩受風枝。", "攝衣試作聽鷄舞，窮我庸非造物兒。", "腰下誰懸蘇子印，城中人笑董生帷。", "西來江左夷吾在，小敵纔堪劍首吹。"]'),
('f280a13a-384c-4baa-ac60-e411fe34e579','次沈倅韻呈王漕','陳造','宋','宋诗','song-poetry','','[]','王家流慶水傾東，不獨烏衣紀數公。',64,'全唐诗/poet.song.151000.json','["王家流慶水傾東，不獨烏衣紀數公。", "天畀臧孫當有後，人遲汲直未居中。", "鳳巢衮衮九文羽，鵬路摇摇萬里風。", "隔坐從今幾雲母，定知周魯各元功。"]'),
('c9bf0665-3235-46b1-8f75-33c1bf18629b','次韻王漕起秀亭','陳造','宋','宋诗','song-poetry','','[]','夢躡常山萬仞巔，寶符千載尚依然。',64,'全唐诗/poet.song.151000.json','["夢躡常山萬仞巔，寶符千載尚依然。", "烏孫有底梟憑夜，赤子能忘蟻就羶。", "正朔會須還禹服，登臨聊復對吳天。", "明年重放危亭目，萬旅公方北首燕。"]'),
('c6cf4053-4784-44d1-8f83-ae8440882fb9','次韻趙教授  其一','陳造','宋','宋诗','song-poetry','','[]','爭米何心問斗城，聚蚊底許太狂生。',64,'全唐诗/poet.song.151000.json','["爭米何心問斗城，聚蚊底許太狂生。", "未遑餼粟如子罕，謾復公言付阿平。", "緩我愁腸千縷結，羨君筆力萬鈞輕。", "何時去上中和頌，却用詩情寫物情。"]'),
('b824cde9-5d35-49f3-ae32-293afefd3efb','次韻趙教授  其二','陳造','宋','宋诗','song-poetry','','[]','携孥西壘復東城，觸處千愁百恨生。',64,'全唐诗/poet.song.151000.json','["携孥西壘復東城，觸處千愁百恨生。", "如許堯民艱粒食，未應漢法廢常平。", "愛君長策三農重，泥古迂儒一芥輕。", "會略文移倒陳廩，一時骨肉慰皇情。"]'),
('83f92c67-bb5e-468a-996d-5df6e2be0ed3','再次韻贈郭高叔','陳造','宋','宋诗','song-poetry','','[]','知君詩價舊連城，不作渠儂苦瘦生。',64,'全唐诗/poet.song.151000.json','["知君詩價舊連城，不作渠儂苦瘦生。", "血指有人慙妙斲，空弮如我合輸平。", "珠同魚目曾非匹，鼓過雷門定見輕。", "久已傳抄呼阿買，陶編可復置閑情。"]'),
('980795a0-60e8-41c2-8f81-df9bb2e2cd6c','寄陳居仁二首  其一','陳造','宋','宋诗','song-poetry','','[]','鵲語晨簷燈夜花，雙魚隨客到寒家。',64,'全唐诗/poet.song.151000.json','["鵲語晨簷燈夜花，雙魚隨客到寒家。", "交情從昔金可斷，別夢即今天一涯。", "風雨對床他日意，雪霜欺鬢與時加。", "閲人半世花開謝，更覺松筠耐歲華。"]'),
('eb02cf99-1409-4734-a437-e4fc7afea49c','寄陳居仁二首  其二','陳造','宋','宋诗','song-poetry','','[]','尚記誅茅柳外隄，水光摇霧潤窗扉。',64,'全唐诗/poet.song.151000.json','["尚記誅茅柳外隄，水光摇霧潤窗扉。", "桑間曾是僧三宿，海上能忘鶴一歸。", "野店樽罍醅脚釅，比鄰鷄鶩稿頭肥。", "解顔一醉平生事，更向行藏計是非。"]'),
('0ca782e3-e080-4ee9-9c4b-c7162cde8a57','次韻郭教授雪二首  其一','陳造','宋','宋诗','song-poetry','','[]','皇心憂喜與民同，帝意深憐歲不豐。',64,'全唐诗/poet.song.151000.json','["皇心憂喜與民同，帝意深憐歲不豐。", "瑶檢何時下仙界，瑞花一昔覆寰中。", "和聲已自消疵癘，陳廩從知飽困窮。", "今世皋夔活國手，信知人職代天工。"]'),
('9abb40c7-651e-40ba-a13b-029df8b13b39','次韻郭教授雪二首  其二','陳造','宋','宋诗','song-poetry','','[]','詩力駸駸雅頌同，人言平處逼熙豐。',64,'全唐诗/poet.song.151000.json','["詩力駸駸雅頌同，人言平處逼熙豐。", "清篇自昔傳平水，妙曲何人和郢中。", "頗怪鯨牙須手攬，懸知鼠技笑吾窮。", "衰慵合袖推敲手，且可旁觀斲鼻工。"]'),
('e01da558-d5ca-4ce7-aaa6-1cc4ad1d59b6','次王帥韻後詩呈葉教授  其一','陳造','宋','宋诗','song-poetry','','[]','業履冰壺器鏌邪，元戎韜略况儒家。',64,'全唐诗/poet.song.151000.json','["業履冰壺器鏌邪，元戎韜略况儒家。", "功名自昔須橫草，南北于今頼灌瓜。", "村墅稻田黄罷亞，塞垣榆樹老丫叉。", "爲公著意收詩稿，傳與中都萬口誇。"]'),
('48005e6f-26b8-4a1f-b751-70365dee7e09','次王帥韻後詩呈葉教授  其二','陳造','宋','宋诗','song-poetry','','[]','功名回首負年華，梨棗諸雛未克家。',64,'全唐诗/poet.song.151000.json','["功名回首負年華，梨棗諸雛未克家。", "老計生涯須下澤，才非世用但匏瓜。", "爲儒僅博肱三折，謀食寧羞手一叉。", "青眼故人猶念此，肯持巴唱向人誇。"]'),
('8e3ede74-ba9e-4e43-ace1-950fc1363f7f','次王帥韻','陳造','宋','宋诗','song-poetry','','[]','使君觴客及公榮，慰我他時渴德深。',64,'全唐诗/poet.song.151000.json','["使君觴客及公榮，慰我他時渴德深。", "已爲穆生重設醴，更聞正始嗣遺音。", "打圍紅袖留連舞，論檻黄花取次簪。", "恰似雄邊臺上醉，回頭歲月嘆侵尋。"]'),
('f98eeb81-e36a-4012-86cf-69c6ff13b9ba','書劉元之教授劄子後','陳造','宋','宋诗','song-poetry','','[]','碧酒清歌興未央，挽留行色爲風光。',64,'全唐诗/poet.song.151000.json','["碧酒清歌興未央，挽留行色爲風光。", "小人政自屬饜足，老子工於作樂妨。", "舞雪放閑愁踏月，夢雲驚散冷禁霜。", "明朝一寄相思字，旅鴈無情亦斷腸。"]'),
('a4ae3a48-668b-43a1-937f-526bf37111f7','立春前一夕雪二首  其一','陳造','宋','宋诗','song-poetry','','[]','天仙幾夜集瑶臺，剪水篩瓊不受催。',64,'全唐诗/poet.song.151000.json','["天仙幾夜集瑶臺，剪水篩瓊不受催。", "直遣瑞花將臘去，盡驅和氣與春回。", "坐窗客有吟飛絮，對酒人應唱落梅。", "雪與相如俱末至，可能草賦壓鄒枚。"]'),
('7fa8a393-d38f-40f5-9cc2-374e423d46f0','立春前一夕雪二首  其二','陳造','宋','宋诗','song-poetry','','[]','雪龍侵夜正銜枚，破曉郊原玉作堆。',64,'全唐诗/poet.song.151000.json','["雪龍侵夜正銜枚，破曉郊原玉作堆。", "雲葉攀翻徒自舞，瑶花頃刻爲誰開。", "土膏已遽宜農事，綵勝何妨映酒杯。", "幻作冰壺天一噱，夢回品物各春臺。"]'),
('9f51c4c3-d837-4009-b5a6-56dd36c8efcb','餞趙伯衛趙有詩次其韻','陳造','宋','宋诗','song-poetry','','[]','雪後垂楊裊綠絲，郵亭折贈訴違離。',64,'全唐诗/poet.song.151000.json','["雪後垂楊裊綠絲，郵亭折贈訴違離。", "明朝月地嗟分影，勝日風流此一時。", "白閤論詩成夢境，清湖載酒有心期。", "樽前擬倩如椽筆，細與邦人寫去思。"]'),
('550ac9c2-0763-4926-8e95-9a28cef7d383','贈仲國美','陳造','宋','宋诗','song-poetry','','[]','三閲春光一建瓴，依然歸棹泊危亭。',64,'全唐诗/poet.song.151000.json','["三閲春光一建瓴，依然歸棹泊危亭。", "烏迎客子各頭白，柳學故人俱眼青。", "曾是縱譚僵婢僕，又成豪飲卧罍瓶。", "明朝小話前溪別，分付溪風管醉醒。"]'),
('7561eaab-263f-4dbd-b2ec-0428ab982d75','次韻彭景貺','陳造','宋','宋诗','song-poetry','','[]','紫燕穿簾若有求，爲人端作置書郵。',64,'全唐诗/poet.song.151000.json','["紫燕穿簾若有求，爲人端作置書郵。", "詩翁別後猶能酒，妄尉歸來亦未侯。", "江閤香溫留語笑，花樓月好記從游。", "即今滿眼悲凉意，投老寧禁此段愁。"]'),
('b48b92ec-5687-447e-a194-f44f3b03f2cd','贈課會諸公','陳造','宋','宋诗','song-poetry','','[]','歲月翩翩驥受檛，妙年雲路不應賒。',64,'全唐诗/poet.song.151000.json','["歲月翩翩驥受檛，妙年雲路不應賒。", "手中白羽真穿葉，門外蒼槐又著花。", "丹竈功成須換骨，天河波淺待乘槎。", "鴈行看即青冥上，却笑臞儒兩鬢華。"]'),
('6ce5fcdd-e54b-4448-8d73-76f42d93148f','再次韻答陳居仁二首  其一','陳造','宋','宋诗','song-poetry','','[]','籬菊擎霜又著花，插花猶記醉君家。',64,'全唐诗/poet.song.151000.json','["籬菊擎霜又著花，插花猶記醉君家。", "兩州札翰雖頻寄，一笑班荆迄未涯。", "酒處賦成千載計，床頭易熟數年加。", "珠璣屬我元無踵，坐想揮毫寫物華。"]'),
('163db5f5-4781-40d6-bf3b-247f73c60dd1','再次韻答陳居仁二首  其二','陳造','宋','宋诗','song-poetry','','[]','丁年也辦刺天蜚，幾夢西垣與北扉。',64,'全唐诗/poet.song.151000.json','["丁年也辦刺天蜚，幾夢西垣與北扉。", "未簉時英書汗簡，已煩溪友寄當歸。", "桑榆境界寧辭冷，芹藻杯盤可得肥。", "說似故人應絕倒，衰顔五十盍知非。"]'),
('a153f7ac-415a-498f-9b99-d5a246348cdc','題殖軒','陳造','宋','宋诗','song-poetry','','[]','窗戶青紅斷手初，桃蹊竹徑類僧居。',64,'全唐诗/poet.song.151000.json','["窗戶青紅斷手初，桃蹊竹徑類僧居。", "日陪騷客揮椽筆，時著班衣奉板輿。", "領會能忘一樽酒，窮通擬付十年書。", "仍聞布穀催春事，一雨朝來溜决渠。"]'),
('edd302d9-cc3b-4b27-98e9-41324319f2a0','賀二石登科','陳造','宋','宋诗','song-poetry','','[]','捷音西下亟蜚星，二雋辭鋒舊莫京。',64,'全唐诗/poet.song.151000.json','["捷音西下亟蜚星，二雋辭鋒舊莫京。", "桂樹前宵減清影，棣華同日擅香名。", "謝家蘭玉真門戶，蘇氏文章亦弟兄。", "此去提衡霄漢上，鵬摶鯤運更論程。"]'),
('a536eeb3-28d3-4949-b682-35ba4fb7e741','次韻何符山人二首  其一','陳造','宋','宋诗','song-poetry','','[]','門下軒裳不轉頭，何人皮底著陽秋。',64,'全唐诗/poet.song.151000.json','["門下軒裳不轉頭，何人皮底著陽秋。", "獨煩客子衝泥屐，屢到衰翁聽雨樓。", "從昔詩聲追正始，即今賓友驗宣州。", "清篇快讀彊人意，未覺京塵厭薄游。"]'),
('9ed4e192-951b-4af1-b65e-a7799fa73b5a','次韻何符山人二首  其二','陳造','宋','宋诗','song-poetry','','[]','曉看明璣下網絲，物華俱屬喜晴詩。',64,'全唐诗/poet.song.151000.json','["曉看明璣下網絲，物華俱屬喜晴詩。", "一詞不措重呈拙，七字鼎來當更奇。", "喜鵲啅人真作意，蝸牛屏迹似知時。", "湖山好處長謠去，擬赴蘇堤勝日期。"]'),
('784b25a4-211b-4453-b8f4-4801f73aca2c','同高叔不愚如晦飲再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','詩老掀髯吟掉頭，紅粧間坐眼波秋。',64,'全唐诗/poet.song.151000.json','["詩老掀髯吟掉頭，紅粧間坐眼波秋。", "快傾良夕如澠酒，宛是當時鎖燕樓。", "想有疎簾窺白下，可無急鼓衮伊州。", "憑君更挽劉師命，寬破三年爛熳游。"]'),
('5999e1e4-a7fa-4120-b04f-c90021120a6f','同高叔不愚如晦飲再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','珠簾深裏按金絲，幻出揚州杜牧詩。',64,'全唐诗/poet.song.151000.json','["珠簾深裏按金絲，幻出揚州杜牧詩。", "共引玻璃扶窈窕，更煩側理寫瓌奇。", "一歡有約能如願，四者求并每後時。", "却念少陵從鄭老，得錢沽酒話襟期。"]'),
('63aa8810-e6a6-4fdb-9077-0b2007e6c316','題潘德久竹居','陳造','宋','宋诗','song-poetry','','[]','竹裏幽棲不掩關，解將應俗等居山。',64,'全唐诗/poet.song.151000.json','["竹裏幽棲不掩關，解將應俗等居山。", "風流彭澤羲黄上，詩力蘇州季孟間。", "官縛猶存紫公服，客來肯靳玉絛環。", "雪兒小直珠千斛，可但疎簾見一斑。"]'),
('87d55cb1-a22a-48c2-a9da-68f637ea0561','次韻張直閤避暑','陳造','宋','宋诗','song-poetry','','[]','紅榴照眼笋穿階，峭閤登臨快此來。',64,'全唐诗/poet.song.151000.json','["紅榴照眼笋穿階，峭閤登臨快此來。", "浄境祛煩仍客共，醉鄉逃暑更書催。", "庭陰碎喜風頭動，虹影明看雨脚回。", "萬事屏除詩債迫，此心抖擻未容灰。"]'),
('701f12f2-9afb-44a3-be2d-6fc2132320b4','次前韻謝胡運屬二首  其一','陳造','宋','宋诗','song-poetry','','[]','耐暑初宵露白頭，詩來分我一襟秋。',64,'全唐诗/poet.song.151000.json','["耐暑初宵露白頭，詩來分我一襟秋。", "露飛瓊滴溥蒼竹，月漾金波冰小樓。", "政用桐君絃白雪，便煩從事到青州。", "此懷未滿須牋與，更爲狂生賦遠游。"]'),
('eaac18d5-94a8-4623-bbc6-0796404811c1','次前韻謝胡運屬二首  其二','陳造','宋','宋诗','song-poetry','','[]','爐烟褭褭上晴絲，伴閲長須送似詩。',64,'全唐诗/poet.song.151000.json','["爐烟褭褭上晴絲，伴閲長須送似詩。", "眼著昏花予已老，句鏘哀玉子能奇。", "隨人趨步庸非俗，取意粧梳自入時。", "大手只宜臺閤裏，不應猶話鹿門期。"]'),
('7f695fd9-2b54-4715-ab28-4cc0af030b1c','早步湖上','陳造','宋','宋诗','song-poetry','','[]','忽忽京塵漬客衣，正須軒曠一伸眉。',64,'全唐诗/poet.song.151000.json','["忽忽京塵漬客衣，正須軒曠一伸眉。", "獨行初日葱蘢處，不待游人雜遝時。", "魚樂暗摇亭樹影，風輕閑弄水雲姿。", "因循又耐簫歌聒，早晚湖山細入詩。"]'),
('74b1383d-b666-4dc1-8d95-38735b578877','次韻章守移學','陳造','宋','宋诗','song-poetry','','[]','千柱崇成儼舊規，小勞移築未爲非。',64,'全唐诗/poet.song.151000.json','["千柱崇成儼舊規，小勞移築未爲非。", "諸儒受業三熏沐，賢守收功一指揮。", "蕆事此時爭拭目，决科它日看增輝。", "問玄亦復侯芭事，可但經生識指歸。"]'),
('1a50c196-2b24-44d9-97c9-7d5c4831d031','次趙解元韻  其一','陳造','宋','宋诗','song-poetry','','[]','養病年來嬾著書，逢人掉臂睨迂儒。',64,'全唐诗/poet.song.151000.json','["養病年來嬾著書，逢人掉臂睨迂儒。", "愁邊好客從天下，譚處清風起座隅。", "愧我多言終不近，似君知已未應無。", "酸鹹嗜好雖殊稟，政恐渠儂誚太愚。"]'),
('fe2edf30-aad2-4e6b-a088-d4fb9021aabb','次趙解元韻  其二','陳造','宋','宋诗','song-poetry','','[]','興劉止用一編書，萬軸垂籤或腐儒。',64,'全唐诗/poet.song.151000.json','["興劉止用一編書，萬軸垂籤或腐儒。", "表表君今超北學，多多我已悔東隅。", "聲華看續諸公後，爾雅深知一筆無。", "縮手袖間真老矣，灌園蓄㹀了朱愚。"]'),
('75b5690f-db0d-4f43-bc03-50474dc618a5','再次韻呈章守','陳造','宋','宋诗','song-poetry','','[]','吾儒交賀得宗師，片善盱衡置百非。',64,'全唐诗/poet.song.151000.json','["吾儒交賀得宗師，片善盱衡置百非。", "小駐鋒車宣室召，時觀譚麈頖宮揮。", "詩壇已許公餘論，鄰燭何曾靳寸輝。", "此意急須牋阿衮，不因魚稻久忘歸。"]'),
('cc4e76cd-f545-434b-bd19-beb57c9b4a0d','次韻章守獵','陳造','宋','宋诗','song-poetry','','[]','身著邦君小隊中，縱觀虎將萬旗紅。',64,'全唐诗/poet.song.151000.json','["身著邦君小隊中，縱觀虎將萬旗紅。", "目光注射鷹窺草，電影騰凌馬弄風。", "忽有清詩驚破竹，更憐蜚翼墮抨弓。", "南歸又苦車中婦，夢憶分鮮一醉同。"]'),
('adacd31b-2f09-4f78-a3b9-c7bdbcdc4d22','飲殖軒','陳造','宋','宋诗','song-poetry','','[]','病骨今朝覺倍輕，雲天昨夜已全晴。',64,'全唐诗/poet.song.151000.json','["病骨今朝覺倍輕，雲天昨夜已全晴。", "爛遊花木欣榮處，賸喜風烟指顧生。", "春草池塘頻入夢，夜窗燈火會尋盟。", "悵然又與禽魚別，波影沉隄晚照明。"]'),
('3f4324f3-c608-4240-980f-df25cd18d17f','趙使君淮春樓落成二首  其一','陳造','宋','宋诗','song-poetry','','[]','五鳳規橅到眼中，摘星奇觀欲爭雄。',64,'全唐诗/poet.song.151000.json','["五鳳規橅到眼中，摘星奇觀欲爭雄。", "客乘雲氣遊三島，人聽歌聲指半空。", "便擬瑶盃酌銀漢，何妨醉面受天風。", "胡床不盡登臨興，未覺邦君後庾公。"]'),
('a382dc54-e709-4c68-8c00-b0e4ac53f877','趙使君淮春樓落成二首  其二','陳造','宋','宋诗','song-poetry','','[]','步帳高牙置下方，華筵雲影入風裳。',64,'全唐诗/poet.song.151000.json','["步帳高牙置下方，華筵雲影入風裳。", "西山爽氣珠簾外，北海芳罇錦瑟傍。", "賓主前聞無勝事，簪鈿明日賸餘香。", "一天和氣誰拘檢，付與邦人作醉鄉。"]'),
('4fb03012-145c-4a0e-b1a0-aeb660e9f71f','贈趙秀才一首','陳造','宋','宋诗','song-poetry','','[]','平生心事釣漁舟，邂逅青衫映白頭。',64,'全唐诗/poet.song.151000.json','["平生心事釣漁舟，邂逅青衫映白頭。", "肯爲功名戲雕虎，不留顔面對沙鷗。", "露漙青蓋高荷曉，風約黄陂小麥秋。", "入眼斜川歸趣好，此身何處不菟裘。"]'),
('fe918daf-5ab7-4ca5-9c99-1e784614d9f4','寄興化葉明府進卿二首  其一','陳造','宋','宋诗','song-poetry','','[]','奧學居瞻數仞堂，業文自笑及肩牆。',64,'全唐诗/poet.song.151000.json','["奧學居瞻數仞堂，業文自笑及肩牆。", "平時江月工分影，勝日篝燈約對床。", "身世我方憐枘鑿，風期君肯遽參商。", "相忘兩舍雖匏繫，當有詩筒訪士鄉。"]'),
('4455f0b6-b1a2-4262-ba43-60036e2a5a2a','寄興化葉明府進卿二首  其二','陳造','宋','宋诗','song-poetry','','[]','一昨連甍較詐狙，缿筩合鬭未良圖。',64,'全唐诗/poet.song.151000.json','["一昨連甍較詐狙，缿筩合鬭未良圖。", "君來嚬笑民之法，政絕鋒鋩古與徒。", "俗變身如游建德，時清人不畏萑苻。", "自公日有詩書樂，大府仍無急急符。"]'),
('9640c235-b479-4c74-85ca-dd36ad651c51','贈曹秀才二首  其一','陳造','宋','宋诗','song-poetry','','[]','不復林逋起九京，空留詩卷逼人清。',64,'全唐诗/poet.song.151000.json','["不復林逋起九京，空留詩卷逼人清。", "如君况自鬼神助，擲地應聞金玉聲。", "敗履人今笑東郭，奔蜂我亦愧南榮。", "三千奏牘真餘事，側耳齊廷待一鳴。"]'),
('1104e4da-5410-4fe7-bca6-d77dc7e00f0a','贈曹秀才二首  其二','陳造','宋','宋诗','song-poetry','','[]','抖擻胸襟一不優，迂臨惟子肯綢繆。',64,'全唐诗/poet.song.151000.json','["抖擻胸襟一不優，迂臨惟子肯綢繆。", "訪書笠澤心摧落，苟祿吳門路阻脩。", "老去欲追三徑約，客來當辦一錢留。", "它年水北山南計，更挈詩瓢就我不。"]'),
('39947c03-8079-4639-9ae6-0d61dc2bd71e','次林計議喜雪韻','陳造','宋','宋诗','song-poetry','','[]','雪縞長空紵带翻，數知冬意未闌殘。',64,'全唐诗/poet.song.151000.json','["雪縞長空紵带翻，數知冬意未闌殘。", "歲功告瑞須三白，客子憑高耐一寒。", "拍塞閑郊瑶圃闊，晶熒危堞玉龍蟠。", "歸來凍坐追清賞，重把君詩剪燭看。"]'),
('773c5935-87db-4118-8925-3cf5e2145bed','次韻朱秀才二首  其一','陳造','宋','宋诗','song-poetry','','[]','蕭齋愁興倩誰寬，籠鶴昂霄顧羽翰。',64,'全唐诗/poet.song.151000.json','["蕭齋愁興倩誰寬，籠鶴昂霄顧羽翰。", "自昔詩深知武諤，肯辭雨濕過蘇端。", "心期落落空軒豁，世事悠悠拙控摶。", "正枕誦君悲壯語，夢隨飛將躡鞮汗。"]'),
('e8ea9962-84fc-49db-a254-a2df74942368','次韻朱秀才二首  其二','陳造','宋','宋诗','song-poetry','','[]','儒冠林立更鴻生，經倚菑畬道可耕。',64,'全唐诗/poet.song.151000.json','["儒冠林立更鴻生，經倚菑畬道可耕。", "便合摘髭書桂籍，未須擁鼻避時名。", "似聞眕夢成三耳，會見驚人取一鳴。", "講易露門誰第一，佇君重席振家聲。"]'),
('25994438-57b7-4ee8-b71f-2812d129b61e','次韻石湖居士見梅','陳造','宋','宋诗','song-poetry','','[]','東風猶是玉爲塵，靜女冰肌小带皴。',64,'全唐诗/poet.song.151000.json','["東風猶是玉爲塵，靜女冰肌小带皴。", "尚壓芳華擅春事，枉當窮臘議花神。", "仙姿絕俗遺羣妬，鼎實收功看一新。", "疎影暗香吾袖手，且容詩伯繼黄陳。"]'),
('84b0c007-6e3b-4f2d-8476-6a725638db62','虎丘','陳造','宋','宋诗','song-poetry','','[]','長日蕭齋類蠹魚，出門春事半銷除。',64,'全唐诗/poet.song.151000.json','["長日蕭齋類蠹魚，出門春事半銷除。", "快舒中散飛鴻眼，穩憩文公卧虎廬。", "塵外風光詩筆底，竹梢禪榻茗甌餘。", "歸塗定有行人問，底許空青潤客裾。"]'),
('8da05e8d-b0ef-45a2-ac98-4686c2726fe8','次王仲衡尚書韻','陳造','宋','宋诗','song-poetry','','[]','著脚功名馬絡頭，人生君所幾居州。',64,'全唐诗/poet.song.151000.json','["著脚功名馬絡頭，人生君所幾居州。", "惟公德操朱絃直，映世冰壺白月秋。", "久已短長冥尺寸，可須骯髒羨伊優。", "即今千里謳謠地，贏得揮斤五鳳樓。"]'),
('e5e86e01-349e-4742-a643-bd1509a2a4ba','次韻石湖居士晴窗遣興','陳造','宋','宋诗','song-poetry','','[]','閶門車馬隠晴雷，我亦臨風詠快哉。',64,'全唐诗/poet.song.151000.json','["閶門車馬隠晴雷，我亦臨風詠快哉。", "平碧際空烟羃歷，蔫紅照影水縈回。", "園翁門巷初沾絮，遊子杯盤欲薦梅。", "落晚小家還饌客，旋篘春甕取新醅。"]'),
('7ba019b2-1b2a-4fe1-86da-fa735d2b5acd','次韻石湖居士遊虎丘','陳造','宋','宋诗','song-poetry','','[]','山靈知我欲巾車，岫幌雲扃已袚除。',64,'全唐诗/poet.song.151000.json','["山靈知我欲巾車，岫幌雲扃已袚除。", "竹葆松幢平几席，碧烟紅影認林廬。", "飯分禪供清無敵，飲屬詩流興有餘。", "莫話長安牢落客，付渠塵土曳長裾。"]'),
('10770a6b-d0f8-4fa4-b24f-c4e7a86d33c1','寄王仲衡尚書','陳造','宋','宋诗','song-poetry','','[]','世態翻雲覆雨間，令人合眼夢還山。',64,'全唐诗/poet.song.151000.json','["世態翻雲覆雨間，令人合眼夢還山。", "生平名義非肝膈，歲晚師門要面顔。", "鷗鷺波寬雖有約，鳳凰城近可容閑。", "留年看試調元手，未擬安仁賦拙艱。"]'),
('06848fae-e537-4951-8af5-817da0b5a2c9','贈陳簽判','陳造','宋','宋诗','song-poetry','','[]','熠熠螢光畧露荷，摇摇盃面漲金波。',64,'全唐诗/poet.song.151000.json','["熠熠螢光畧露荷，摇摇盃面漲金波。", "受風正作團欒飲，閉戶深防褦襶過。", "情話想無雲母隔，新篇應有雪兒歌。", "揆予可諱劉郎笑，講舌長乾鬢自皤。"]'),
('49354688-35f7-4084-a937-993317ebea58','京口呈張閤學  其一','陳造','宋','宋诗','song-poetry','','[]','歸懷未用話南園，卧治于今又北門。',64,'全唐诗/poet.song.151000.json','["歸懷未用話南園，卧治于今又北門。", "但息兒啼寬上意，小稽霆擊取中原。", "虎頭銳視非無種，獅子當觴且勿喧。", "更恐譚公家世事，斷無宣勸定驚魂。"]'),
('8e36018e-b97b-4875-8924-7f21692fcc8a','京口呈張閤學  其二','陳造','宋','宋诗','song-poetry','','[]','色辭他日慰凄凉，別去吳山楚水長。',64,'全唐诗/poet.song.151000.json','["色辭他日慰凄凉，別去吳山楚水長。", "蟻國槐安消幾夢，鶴歸華表恐千霜。", "安排久饜冷官飲，軟語重登君子堂。", "所惜將迎無暇日，妨人詩律悟濠梁。"]'),
('f27241bc-8377-49fa-88c9-9af5baf7502f','題成倅小築','陳造','宋','宋诗','song-poetry','','[]','主人領客竟成遲，閑殺林園此段奇。',64,'全唐诗/poet.song.151000.json','["主人領客竟成遲，閑殺林園此段奇。", "勝日阿蓮須後乘，即今佳菊尚東籬。", "肯來雪壁題詩處，許繼華堂墮幘時。", "醉後與渠同起舞，一庭花影月迷離。"]'),
('59d116f5-9268-4374-8ded-d8944a708c59','皇孫壽詩二首  其一','陳造','宋','宋诗','song-poetry','','[]','寶祚煌煌羨帝祺，天潢餘潤到孫枝。',64,'全唐诗/poet.song.151000.json','["寶祚煌煌羨帝祺，天潢餘潤到孫枝。", "壽星良月占重見，振古熙朝此一時。", "椽筆紀祥芳草頌，龍樓開笑正含飴。", "蘿圖况與乾坤永，長款三宮奉玉巵。"]'),
('23c6629c-d1ea-41b1-89c2-1883c8e908fb','皇孫壽詩二首  其二','陳造','宋','宋诗','song-poetry','','[]','曾簉蓬萊挹德風，日親儒保罄寅恭。',64,'全唐诗/poet.song.151000.json','["曾簉蓬萊挹德風，日親儒保罄寅恭。", "學窮奧閫包賢聖，人仰英明肖祖宗。", "綵服近天仍樂孺，帝觴拜賜更從容。", "應劉壽語年年事，九萬香牋未闕供。"]'),
('3fc4cd65-1596-47bc-bd03-38bdecd88bfe','酬賈學錄韻并送炭','陳造','宋','宋诗','song-poetry','','[]','何人戴目倚錢神，更問吾徒拂甑塵。',64,'全唐诗/poet.song.151000.json','["何人戴目倚錢神，更問吾徒拂甑塵。", "醉纈不供詩客眼，弊裘應笑廣文貧。", "坐看十日澠爲雨，遥想千家桂作薪。", "貸子曲身當得句，地爐分施臘前春。"]'),
('f17fa535-792c-47ac-b291-1080751f0e59','次陳夢錫韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','薄雪晶瑩壓屋茅，未須桂玉計晨庖。',64,'全唐诗/poet.song.151000.json','["薄雪晶瑩壓屋茅，未須桂玉計晨庖。", "已便鹽絮明愁眼，更喜烏鳶得夜巢。", "小聽騷人賦梁苑，旋看春意滿東郊。", "忍寒便擬尋梅去，夢想瑶英點舊梢。"]'),
('737f2c08-3924-4d3f-9532-15c30661a2b8','次陳夢錫韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','思君采艾嘆如年，眼底羈愁只自煎。',64,'全唐诗/poet.song.151000.json','["思君采艾嘆如年，眼底羈愁只自煎。", "破夢有來驚剝啄，衝泥徑欲跨連錢。", "新篇端復千年計，舊集猶須百手傳。", "早晚聚頭三日語，麈邊閑聽有源泉。"]'),
('d750e411-d37d-4aa8-87f7-6acddd97ced8','次韻朱解元雪','陳造','宋','宋诗','song-poetry','','[]','掉頭取別未經旬，已積胸中幾斛塵。',64,'全唐诗/poet.song.151000.json','["掉頭取別未經旬，已積胸中幾斛塵。", "密雪忽明銀海夜，端憂空負玉花春。", "筆驅和氣君何健，囊致新詩我未貧。", "勝日兔園當有賦，可能客右欠斯人。"]'),
('7c491dc7-2109-452b-b674-3420a63233b0','次韵陳夢錫','陳造','宋','宋诗','song-poetry','','[]','手板夤緣替荷鋤，從渠爭挾子公書。',64,'全唐诗/poet.song.151000.json','["手板夤緣替荷鋤，從渠爭挾子公書。", "三年已辦青箱蠹，一飽纔分代舍魚。", "煙燼萁爐朝兀兀，窗明風霰夜疎疎。", "獨思把酒看君醉，墨汁淋浪點翠裾。"]'),
('4bc54235-0d1b-4c7e-b92f-8b843a6d28d4','約二同年游虎丘','陳造','宋','宋诗','song-poetry','','[]','兼旬閉戶耐寒威，起視晴空碧四圍。',64,'全唐诗/poet.song.151000.json','["兼旬閉戶耐寒威，起視晴空碧四圍。", "黄鳥啼邊忽游子，白龍去後漸單衣。", "年時尚記尋芳約，老境仍憐得醉希。", "紅影幽香虎丘路，杖藜携酒莫相違。"]'),
('b0faadc0-6327-458a-9c4a-b8f0533b1bbc','次韻陳倅趙宰雙竹','陳造','宋','宋诗','song-poetry','','[]','兩君深結此君緣，句裏蕭森墮我前。',64,'全唐诗/poet.song.151000.json','["兩君深結此君緣，句裏蕭森墮我前。", "筍茁便應欺瑞麥，詩成端合付雙蓮。", "窗間儷影斜新月，風處駢梢褭綠煙。", "會擬韓公頌連理，爲渠小輟枕書眠。"]'),
('0af53369-7b2d-4dc5-a559-6e4565b6a64e','寄王尚書','陳造','宋','宋诗','song-poetry','','[]','一昨家庭拜帝綸，熊轓催去不逡巡。',64,'全唐诗/poet.song.151000.json','["一昨家庭拜帝綸，熊轓催去不逡巡。", "小遲繡衮昇元輔，復向蓬萊作主人。", "竹馬未迎歡意浹，蒲鞭重試教條新。", "詩賡樂職諸生事，筆力誰今斡萬鈞。"]'),
('28dc629d-66ea-4291-8e23-c30baef37bd0','次韻嚴上舍','陳造','宋','宋诗','song-poetry','','[]','待月尚思前度月，中天圓璧不留分。',64,'全唐诗/poet.song.151000.json','["待月尚思前度月，中天圓璧不留分。", "即今霜氣挾靈籟，如許金波乘壞雲。", "念我吳牛終喘夜，憶君冀北忽空羣。", "睡魂作魔病作祟，猶頼清詩來解紛。"]'),
('739999fc-3fd7-4ea0-94a2-4ebb6a44e11f','次韻朱通判嚴上舍  其一','陳造','宋','宋诗','song-poetry','','[]','蜀莊漂泊闔閭城，獨向陶朱意氣傾。',64,'全唐诗/poet.song.151000.json','["蜀莊漂泊闔閭城，獨向陶朱意氣傾。", "詩寫閑情易爲好，雨鏖炎暑欲爭清。", "居同蟻穴晴猶閉，歸笑鳩巢老未營。", "久擬投君渠保社，援毫空復可憐生。"]'),
('337db7a6-87ea-4598-8e0c-606a98a2a36d','次韻朱通判嚴上舍  其二','陳造','宋','宋诗','song-poetry','','[]','君家名酒壓吳城，肯向時流取次傾。',64,'全唐诗/poet.song.151000.json','["君家名酒壓吳城，肯向時流取次傾。", "篘玉誰今窺正色，班荆渠定賞真清。", "雙壺問字寧能許，一醉留賓不辦營。", "莫惜驅車餉元亮，須防結襪要王生。"]'),
('242b1581-fb7b-439f-a7eb-5ff0a15a1992','次韻朱通判嚴上舍  其三','陳造','宋','宋诗','song-poetry','','[]','萬手抄詩遍洛城，老懷可但向來傾。',64,'全唐诗/poet.song.151000.json','["萬手抄詩遍洛城，老懷可但向來傾。", "采菱白雪方迭奏，蜚雨曉風相與清。", "價重欲輸和氏璧，令嚴誰犯伏波營。", "即今貂尾那容續，更判工夫費此生。"]'),
('11f0f42b-e800-483f-b253-f824fc3108a7','次韻朱通判嚴上舍  其四','陳造','宋','宋诗','song-poetry','','[]','子元才望未專城，玉面醪敷且細傾。',64,'全唐诗/poet.song.151000.json','["子元才望未專城，玉面醪敷且細傾。", "寵辱盡捐身外事，醺酣聊樂聖之清。", "分甘亦復憐吾老，飲濕終慙不自營。", "歸去須君傳此法，秫田百畝便平生。"]'),
('4c5af2e0-864e-439b-8c62-906b2f2aca9b','再次韻後篇戲朱  其一','陳造','宋','宋诗','song-poetry','','[]','淙淙雨勢欲沈城，衮衮辭源亦對傾。',64,'全唐诗/poet.song.151000.json','["淙淙雨勢欲沈城，衮衮辭源亦對傾。", "闢戶渾疑雲氣近，誦詩如在玉壺清。", "射知猿臂須穿札，陳怯魚麗且閉營。", "只把兩君新句法，爲歌豐樂詔諸生。"]'),
('9f28119b-55cd-4770-9b03-bc2b07c5fc5c','再次韻後篇戲朱  其二','陳造','宋','宋诗','song-poetry','','[]','似聞新醖敵宜城，想對簷花又獨傾。',64,'全唐诗/poet.song.151000.json','["似聞新醖敵宜城，想對簷花又獨傾。", "別乘工爲海鯨吸，廣文當念露蟬清。", "投醪頻遣春浮頰，盜印寧無夜闖營。", "約束長鬚牢閉戶，甕間防有畢先生。"]'),
('eb98bb99-bdff-4249-8dd0-396e0ba0a8a7','苦雨再次前韻  其一','陳造','宋','宋诗','song-poetry','','[]','席蚓堂蛙豈趙城，崩空急雨未休傾。',64,'全唐诗/poet.song.151000.json','["席蚓堂蛙豈趙城，崩空急雨未休傾。", "青秧可復成堅皂，碧海渠能受濁清。", "田舍望秋猶萬一，官曹需祿更征營。", "寶熏定有回天力，即看朝曦指顧生。"]'),
('a895a1ad-ffe5-4468-bb60-5684d4d57b0f','苦雨再次前韻  其二','陳造','宋','宋诗','song-poetry','','[]','底用詩名到鳳城，未妨醉帽笑欹傾。',64,'全唐诗/poet.song.151000.json','["底用詩名到鳳城，未妨醉帽笑欹傾。", "日聞螟蠃譏狂率，目送鯤鵬簉紫清。", "譚客有時三不對，生涯除酒一無營。", "鳴鞭走送君能斷，小印親封定好生。"]'),
('097e971c-b9ff-4b37-90f5-a2c74c6b2861','試院贈三同官','陳造','宋','宋诗','song-poetry','','[]','果飣茶甌意未闌，獨慙衰鬢映朱顔。',64,'全唐诗/poet.song.151000.json','["果飣茶甌意未闌，獨慙衰鬢映朱顔。", "聚頭長作三更語，屈指惟餘兩日閑。", "食葉蠶聲行入聽，探珠驪頷不應慳。", "預憐朱墨秋宵永，咫尺燈窗斷往還。"]'),
('052382ec-ff66-42a5-b81c-fb4f98efe521','歸有日喜作','陳造','宋','宋诗','song-poetry','','[]','夜燈晨飯棘圍重，檻束飛猱鶴在籠。',64,'全唐诗/poet.song.151000.json','["夜燈晨飯棘圍重，檻束飛猱鶴在籠。", "敢效騷人悲迫阨，祇防舉子誚冬烘。", "摶風定有莊鵬化，得雋從知冀馬空。", "明日還家壓新酒，菊登金蕊拒霜紅。"]'),
('4bd72b3b-17d3-4d27-ab6c-ddd85369487d','次韻袁提刑勞軍許浦中路風雨','陳造','宋','宋诗','song-poetry','','[]','方隅咫尺儼威顔，窮谷回春不作難。',64,'全唐诗/poet.song.151000.json','["方隅咫尺儼威顔，窮谷回春不作難。", "渥澤欲隨金節到，先聲已失鐵衣寒。", "來時敢憚風將雨，泊處仍聽浪卷灘。", "天自與公供壯觀，海涵雲物正闌干。"]'),
('e187df7b-e909-4d06-bc20-62f7bc2a74c1','次韻常熟感舊','陳造','宋','宋诗','song-poetry','','[]','詩囊隨處紀山川，古縣繁雄更海邊。',64,'全唐诗/poet.song.151000.json','["詩囊隨處紀山川，古縣繁雄更海邊。", "按節將春巡甲壘，循陔回首記丁年。", "綵衣尚念親三釜，芝檢終當歲九遷。", "移孝爲忠賢聖事，期公迄反汶陽田。"]'),
('db8c2ac0-8fbd-4301-b6d2-706f0c9dc314','次韻犒士','陳造','宋','宋诗','song-poetry','','[]','萬竈連連儼舊屯，朝來喜氣襲人溫。',64,'全唐诗/poet.song.151000.json','["萬竈連連儼舊屯，朝來喜氣襲人溫。", "固知除器須平日，政復投醪亦至恩。", "帝綍函春周壘壁，使星回耀照和門。", "文經武緯君王聖，汗簡須公紀治原。"]'),
('eee0d03e-fb7d-43c7-b26c-aa1382a1cb52','次韻回塗打冰欲遵陸','陳造','宋','宋诗','song-poetry','','[]','轉頭風日破堅冰，未用穿危冒滑行。',64,'全唐诗/poet.song.151000.json','["轉頭風日破堅冰，未用穿危冒滑行。", "瀚海無波聊整棹，陽春有脚莫論程。", "詩情動處髭頻撚，使事閒時酒細傾。", "馮問逢迎黄髮叟，里間歡意爲誰生。"]'),
('18a8d239-b397-42eb-b2bb-2b8dc257eea8','別趙文卿明府','陳造','宋','宋诗','song-poetry','','[]','人品推君第一流，論文向我肯綢繆。',64,'全唐诗/poet.song.151000.json','["人品推君第一流，論文向我肯綢繆。", "日從紅粉追譚笑，家置青編紀唱酬。", "轉首各乘鳬背去，幾時同作鳳城游。", "臨風莫道書難寄，旅鴈飛還是便郵。"]'),
('bee07ec8-53a9-46ed-977d-328fa394ebda','次韻袁丈知府喜雨','陳造','宋','宋诗','song-poetry','','[]','使君今代段荆州，指顧爲霖旱不憂。',64,'全唐诗/poet.song.151000.json','["使君今代段荆州，指顧爲霖旱不憂。", "比屋便令開笑口，散人亦復掉吟頭。", "封君擅富寧容數，義廩賙貧可待求。", "想閲賀章天更喜，津津玉色動凝旒。"]'),
('bdf52274-d5f1-4cde-8567-6ee74c2c5ef0','次韻袁憲雪二首  其一','陳造','宋','宋诗','song-poetry','','[]','犯雪回帆歲遽殘，自憐雨澁更風慳。',64,'全唐诗/poet.song.151000.json','["犯雪回帆歲遽殘，自憐雨澁更風慳。", "從遊已落鄒枚後，著語渠能季孟間。", "夢逐蜚僊凌色界，誰因逋客護雲關。", "獨思快目毗陵曉，玉襯金波妥錫山。"]'),
('4e34b267-1113-4d15-a5c9-b34c1f25ceea','次韻袁憲雪二首  其二','陳造','宋','宋诗','song-poetry','','[]','天憐梅蕊怯摧殘，善後何妨小作慳。',64,'全唐诗/poet.song.151000.json','["天憐梅蕊怯摧殘，善後何妨小作慳。", "一雪應期真望外，三詩說喜想顔間。", "瑶花已兆食四鬴，沉炷爲通天九關。", "捲帳盍酬民氣樂，蘇臺持酒挹湖山。"]'),
('9cd5d71e-b08e-415a-8483-5ed004a98575','贈趙步帥','陳造','宋','宋诗','song-poetry','','[]','出處升沉轉首非，無端顛倒念分違。',64,'全唐诗/poet.song.151000.json','["出處升沉轉首非，無端顛倒念分違。", "瘦羊博士尚骨立，白馬將軍今肉飛。", "共仰鈎陳明帝極，少須尺箠下金微。", "爲公草罷平羌檄，徑指淮鄉舊釣磯。"]'),
('cffb8a44-74c1-4bfd-b3f3-bd94bf77ed15','壯觀亭爲真州作','陳造','宋','宋诗','song-poetry','','[]','頻年入夢此躋攀，驟覺平時氣象還。',64,'全唐诗/poet.song.151000.json','["頻年入夢此躋攀，驟覺平時氣象還。", "吳客到應忘月觀，淮鄉勝不數平山。", "飛檐曲檻霄霏處，疊嶂橫江几席間。", "見說能詩好賓主，風雷落筆每乘閑。"]'),
('3e1fb529-c594-4119-9d72-0c9329f20cd0','次韻吳江陳學長送行二首  其一','陳造','宋','宋诗','song-poetry','','[]','詩人六十合恩袍，平日周庠重譽髦。',64,'全唐诗/poet.song.151000.json','["詩人六十合恩袍，平日周庠重譽髦。", "舊學堪重漢儒席，新文欲僕楚人騷。", "等觀得喪心無累，飽閲豪英眼更高。", "聞道青箱富嘉頌，詔音早晚召王褒。"]'),
('0453a9dc-7910-4fe9-a41e-929dacab4c29','次韻吳江陳學長送行二首  其二','陳造','宋','宋诗','song-poetry','','[]','白首詩書未亢宗，還紆墨綬揖王公。',64,'全唐诗/poet.song.151000.json','["白首詩書未亢宗，還紆墨綬揖王公。", "玉堂金馬拌身外，法護僧彌且眼中。", "自詭噓枯酬雅志，肯從束濕就奇功。", "垂虹高士知心客，定信襟期出處同。"]'),
('255e4453-8259-4e80-ab11-b1b39856a9d1','次韻張丞月試士人','陳造','宋','宋诗','song-poetry','','[]','居有齋庖教有官，諸生肯復計安閑。',64,'全唐诗/poet.song.151000.json','["居有齋庖教有官，諸生肯復計安閑。", "充庭數貢知非遠，造物于人本不慳。", "思苦得無金注拙，眼明終眩錦花斑。", "自憐慣秉雌黄筆，案牘如今拄屋山。"]'),
('6634b099-172a-4a4a-9181-9ee67174ef19','次韻答張丞','陳造','宋','宋诗','song-poetry','','[]','顧省辭華分槁乾，簿書堆裏作粗官。',64,'全唐诗/poet.song.151000.json','["顧省辭華分槁乾，簿書堆裏作粗官。", "客懷止飲仍多病，海氣乘秋早戒寒。", "好語相濡真禁臠，不才持答欠琅玕。", "從今惡况能排遣，日課君詩一再觀。"]'),
('1c6b25ec-a5fb-4bc8-8f15-50217b6fa572','次韻張丞二首  其一','陳造','宋','宋诗','song-poetry','','[]','夫君腹笥盡奇謀，每叩談鋒聽不休。',64,'全唐诗/poet.song.151000.json','["夫君腹笥盡奇謀，每叩談鋒聽不休。", "誦賦久嗟無此作，薦賢端合拔其尤。", "小遲榮路觀掀趠，聊爲同寮蓋謬悠。", "政恐諸公有推挽，平時果藝仰由求。"]'),
('c7965ef7-8af9-499a-ad31-5a4a606ec6c2','次韻張丞二首  其二','陳造','宋','宋诗','song-poetry','','[]','槁梧閑據自沈吟，投老真成負此心。',64,'全唐诗/poet.song.151000.json','["槁梧閑據自沈吟，投老真成負此心。", "酒沃渴鯨悲事往，官隨跛鼈笑吾今。", "進爲終愧周人朴，歸去曾無陸子金。", "尚頼君詩慰牢落，時清聾聵發純音。"]'),
('903d1cb2-db24-44e1-bb5f-38933d77a85a','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','鉛墨才爲一飽謀，還因跋疐賦休休。',64,'全唐诗/poet.song.151000.json','["鉛墨才爲一飽謀，還因跋疐賦休休。", "南州習俗難馴擾，北客迂疎易悔尤。", "世味辰星今落落，歸心風旆正悠悠。", "知非况自五十九，爲問衰翁底更求。"]'),
('7632f2e5-7915-4bf6-904b-ed7340484b12','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','自揖高人擁鼻吟，湖濱詩酒便論心。',64,'全唐诗/poet.song.151000.json','["自揖高人擁鼻吟，湖濱詩酒便論心。", "天教聯綬同民社，日許挑燈訂古今。", "刺眼未妨翻著襪，躍爐寧問不祥金。", "簡編自有千年計，遲子追還正始音。"]'),
('5392628d-e7eb-411c-bc78-40d3a283e28c','次韻周秀才','陳造','宋','宋诗','song-poetry','','[]','暇日枝筇對摇落，衰年悲感爲誰多。',64,'全唐诗/poet.song.151000.json','["暇日枝筇對摇落，衰年悲感爲誰多。", "政疎里俗有囁呫，身遠貴遊無孰何。", "耐病阻陪吹帽醉，祛愁聊復擊罇歌。", "詩來起我湖海興，夢逐狎鷗分白波。"]'),
('f1c4b7a9-b542-487d-82da-40b24f5bb570','正覺寺','陳造','宋','宋诗','song-poetry','','[]','細穿詰曲上高寒，一鷲青冥杳靄間。',64,'全唐诗/poet.song.151000.json','["細穿詰曲上高寒，一鷲青冥杳靄間。", "欄楯欹浮滄海影，東南重見紫金山。", "方壺入眼鯨堪跨，璧月依人桂易攀。", "聞說老禪佳寢飯，一生無夢落塵寰。"]'),
('50ac170d-5628-4984-a997-976f127231b7','次韻張丞','陳造','宋','宋诗','song-poetry','','[]','邦人邑吏總堪憐，茶供爐熏共籲天。',64,'全唐诗/poet.song.151000.json','["邦人邑吏總堪憐，茶供爐熏共籲天。", "占雨幾孤霞粲曉，望霓何啻日爲年。", "翻黄已熟村村麥，平淥行看處處田。", "擬倩龍公作霖手，更煩終惠息頭燃。"]'),
('f32283fd-4892-43ba-a596-bb80ef2ab3d7','次韻任解元喜雨二首  其一','陳造','宋','宋诗','song-poetry','','[]','寄語今年主雨神，當知小雨未康屯。',64,'全唐诗/poet.song.151000.json','["寄語今年主雨神，當知小雨未康屯。", "人心正切霶𩃱望，農事深愁晼晚春。", "朽壤舊嘗封蟻穴，停雲空復疊魚鱗。", "鯫生宿藴天人學，無計王前拜手陳。"]'),
('7a926b10-ae57-4fe2-990b-04d2b012ebd2','次韻任解元喜雨二首  其二','陳造','宋','宋诗','song-poetry','','[]','跪奉爐香幸見憐，人言匹庶可回天。',64,'全唐诗/poet.song.151000.json','["跪奉爐香幸見憐，人言匹庶可回天。", "及今一睹盆傾勢，滿意重占斗覆年。", "僅息黄塵昏永晝，幾時翠羽冒中田。", "此心安得頑如石，水旱豐凶付偶然。"]'),
('e88fb545-1003-48d3-b9e1-fa1496e6b49c','次韻陳秀才二首  其一','陳造','宋','宋诗','song-poetry','','[]','吏治因循俗已疵，可無柱後濟寬慈。',64,'全唐诗/poet.song.151000.json','["吏治因循俗已疵，可無柱後濟寬慈。", "顧慙德化一何取，敢意古人三不欺。", "剔蠹方圖洗熏染，放麑端復惎衰遲。", "成君今段萊衣笑，莫更風前賦百罹。"]'),
('4f2213fe-f7f5-41c3-b6a3-508573aadcaa','次韻陳秀才二首  其二','陳造','宋','宋诗','song-poetry','','[]','七字開緘粲陸離，元非劍氣燭圜扉。',64,'全唐诗/poet.song.151000.json','["七字開緘粲陸離，元非劍氣燭圜扉。", "夜光信出老蚌殻，錦段遽分鄰女機。", "庭賦繼今行北闕，市娼過眼忽南威。", "蜚騰可但榮親計，我亦他年得儁歸。"]'),
('cd5b7b83-80eb-461a-86b2-e08957409922','元日','陳造','宋','宋诗','song-poetry','','[]','爆竹聲中雜笑呼，斗杓插海寺鐘初。',64,'全唐诗/poet.song.151000.json','["爆竹聲中雜笑呼，斗杓插海寺鐘初。", "椒觴带夢隨小飲，桃板得詩仍自書。", "愒日晚塗知內訟，占風吉卜定非虛。", "新年舊管新收累，大府隆寬儻貸予。"]'),
('94457298-68d9-4a11-a4b4-942f0f59ccb9','次韻張丞  其一','陳造','宋','宋诗','song-poetry','','[]','縣人燈夕舊嘗看，夜敞窗扉曉不關。',64,'全唐诗/poet.song.151000.json','["縣人燈夕舊嘗看，夜敞窗扉曉不關。", "勝賞繼應追俗尚，晴暉巧與破天慳。", "招邀便擬日復日，容易遽吟山上山。", "更乞紫姑豐樂語，爲添喜色到顔間。"]'),
('f3a3b482-ed05-4cb5-8f23-8a9566dc7c87','次韻張丞  其二','陳造','宋','宋诗','song-poetry','','[]','長日官曹迄未閑，佳辰一笑頗相關。',64,'全唐诗/poet.song.151000.json','["長日官曹迄未閑，佳辰一笑頗相關。", "萬情同樂那容失，四者來并每坐慳。", "歌酒恐孤燈市月，烟霏猶曀海門山。", "龍公可復會事發，汛掃陰霾彈指間。"]'),
('af43daa5-e86f-4109-9dd9-0faea3664a52','再次韻','陳造','宋','宋诗','song-poetry','','[]','好時好節工惱客，投老祇思深閉關。',64,'全唐诗/poet.song.151000.json','["好時好節工惱客，投老祇思深閉關。", "鶴膝痛醫終是病，蛾眉公奪豈容慳。", "浩歌已減落梅曲，苦思更妨頹醉山。", "冷語陋姝何所似，貧家矮屋劣成間。"]'),
('24cd415d-e660-4a0e-8986-7314a079460c','十四夜丞和章來復次韻','陳造','宋','宋诗','song-poetry','','[]','衰年寢食僧齋似，甚欲持盃解入關。',64,'全唐诗/poet.song.151000.json','["衰年寢食僧齋似，甚欲持盃解入關。", "桂魄元非月蛾靳，韭葅終笑庾郎慳。", "不成小醉穿燈市，又作相逢嘲飯山。", "思澁徒貽山婦怪，羨渠飛雉落黄間。"]'),
('07003aa9-4ec9-4a92-9c48-13b831e736f3','十六夜張丞有詩次韻','陳造','宋','宋诗','song-poetry','','[]','燈夕勝遊皆遻意，可無歌酒答豐年。',64,'全唐诗/poet.song.151000.json','["燈夕勝遊皆遻意，可無歌酒答豐年。", "雲藏玉斧重修月，樂奏壺仙小隠天。", "鴈陣低空危欲墮，龍公驅雨未成眠。", "惟應鐵鎖銀花句，落紙明朝萬口傳。"]'),
('b0dab935-5502-4f81-b771-0804204f5761','張丞再有詩次韻','陳造','宋','宋诗','song-poetry','','[]','仰高排奡玩清圓，學力卑摧舊判年。',64,'全唐诗/poet.song.151000.json','["仰高排奡玩清圓，學力卑摧舊判年。", "後進或夸金擲地，前修猶是斗橫天。", "晚規省語安衰病，暇復分題攪醉眠。", "祇有君詩追古作，未忘緗素遣兒傳。"]'),
('2c094362-eb85-4b65-9177-759c72940c83','再次張丞韻','陳造','宋','宋诗','song-poetry','','[]','龍職陰晴肯轉圜，寒侵春事倍常年。',64,'全唐诗/poet.song.151000.json','["龍職陰晴肯轉圜，寒侵春事倍常年。", "彌旬稔聽盆翻雨，一室何殊甕裏天。", "多病可堪嚴酒戒，高舂未憗枕書眠。", "忘憂蠲忿疑無策，小草論功亦浪傳。"]'),
('1b1d9125-96c0-4000-aa75-698b81117d7b','次韻王簽判','陳造','宋','宋诗','song-poetry','','[]','奧學聞君不近名，聲華猶是壓時英。',64,'全唐诗/poet.song.151000.json','["奧學聞君不近名，聲華猶是壓時英。", "詩篇向我肯揮掃，句法驚人渾老成。", "未厭泛蓮依衛幕，只今薦鶚達周京。", "明朝置酒當投轄，萬斛洪源看倒傾。"]'),
('6e7f3aed-a3f3-475b-bde7-86cd8aea9d00','次韻自序','陳造','宋','宋诗','song-poetry','','[]','丁年拾芥視功名，可但紉蘭茹落英。',64,'全唐诗/poet.song.151000.json','["丁年拾芥視功名，可但紉蘭茹落英。", "深愧官曹無所補，向來志願幾餘成。", "分營伏臘耕淮壤，久絕音郵到帝京。", "尚有好賢餘習在，老懷端合向君傾。"]'),
('7890d951-53c4-4ab3-92f9-a65486bfac4f','次韻戰艦','陳造','宋','宋诗','song-poetry','','[]','下瀨千艘舊擅名，漢家虓將况飛英。',64,'全唐诗/poet.song.151000.json','["下瀨千艘舊擅名，漢家虓將况飛英。", "呼韓款渭人胥後，小耿平齊事竟成。", "擊楫定無違廟算，覆盂端有奠神京。", "聖君動靜天人合，持滿何妨亦定傾。"]'),
('09520c30-4872-4eeb-9272-7a9e16f3729d','次韻招飯不赴','陳造','宋','宋诗','song-poetry','','[]','吏能儒業實慙名，晚喜論交蓋代英。',64,'全唐诗/poet.song.151000.json','["吏能儒業實慙名，晚喜論交蓋代英。", "千里久勞魂夢往，一歡猶阻咄嗟成。", "粲花論勝違頻聽，擊鉢詩工况莫京。", "別後槱溪縈望眼，此心川水漫東傾。"]'),
('a341a093-4888-4ff5-aa9f-c7b2dfa43ec4','即事','陳造','宋','宋诗','song-poetry','','[]','江漾晨光入縣門，樓斜晚影到漁村。',64,'全唐诗/poet.song.151000.json','["江漾晨光入縣門，樓斜晚影到漁村。", "海聲不爲無風靜，山色居常带霧昏。", "問俗即今防愒日，來時撫事錯銷魂。", "浮生寄寓君恩重，未覺天涯異故園。"]'),
('d4436e71-9e5a-4d26-89e9-5adf47eeab46','勞農浄居贈皎啟二僧','陳造','宋','宋诗','song-poetry','','[]','勞農今喜復南轅，夾道扶携亦笑諠。',64,'全唐诗/poet.song.151000.json','["勞農今喜復南轅，夾道扶携亦笑諠。", "縣尹庶幾無疾病，山人迎送耐頻煩。", "芼葱湯餠聊堪飽，出甕春醪半带渾。", "惟有爲民真實意，異時陳迹付公言。"]'),
('10f37164-0fae-4f3c-854f-a4a8082e1fb0','題林監稅漁鄉小樓','陳造','宋','宋诗','song-poetry','','[]','半是蜚軒半是樓，主人雅趣寄滄洲。',64,'全唐诗/poet.song.151000.json','["半是蜚軒半是樓，主人雅趣寄滄洲。", "晨霞莫靄紛濃淡，越舶番檣閲去留。", "徙倚想君舒醉眼，從容須我掉吟頭。", "病來止酒便高卧，幾夢烟波沒白鷗。"]'),
('47cded87-a5ca-456b-91f4-4f47c026bd91','九日登樓','陳造','宋','宋诗','song-poetry','','[]','縣曹逢節猶忙迫，陰雨乘秋每接連。',64,'全唐诗/poet.song.151000.json','["縣曹逢節猶忙迫，陰雨乘秋每接連。", "九日歡娛異前日，幾年晴霽有今年。", "湖山入座褰珠箔，萸菊挼香薦玉船。", "帽委西風判一醉，故人應未笑華顛。"]'),
('0cf2b502-56da-4766-9434-b82629879ad5','鑑湖道中','陳造','宋','宋诗','song-poetry','','[]','風烟佳處放歸橈，吟坐篷窗首屢搔。',64,'全唐诗/poet.song.151000.json','["風烟佳處放歸橈，吟坐篷窗首屢搔。", "萬壑千巖爭獻狀，三江九堰自忘勞。", "尚多菡萏張秋錦，少待蟾蜍印夜濤。", "繚碧森青誰子宅，未容載酒訪清高。"]'),
('e0801356-9953-47f2-8f3f-15d9502a91f9','言懷二首  其一','陳造','宋','宋诗','song-poetry','','[]','此身與世分相違，可是平生不見幾。',64,'全唐诗/poet.song.151000.json','["此身與世分相違，可是平生不見幾。", "知己方占白雞夢，寸心已傍碧山飛。", "周旋觴詠須三益，斟酌行藏欠一歸。", "甓社湖西隠君子，爲翁應掃釣魚磯。"]'),
('d4f13d76-6e73-48fa-a066-6a45ef9d0d7b','言懷二首  其二','陳造','宋','宋诗','song-poetry','','[]','自是三生賀季真，亟應收拾水雲身。',64,'全唐诗/poet.song.151000.json','["自是三生賀季真，亟應收拾水雲身。", "蜚鳬吏隠聊同俗，飯犢生涯且耐貧。", "林壑風烟當未憗，利名韁鎖聽橫陳。", "世間靜者猶張邴，老境婆娑定笑人。"]'),
('fd5f21d1-e34b-4eb3-8078-6fb5ae06a705','贈陳居士','陳造','宋','宋诗','song-poetry','','[]','昏宦冥冥墮急流，羨君高謝此籠囚。',64,'全唐诗/poet.song.151000.json','["昏宦冥冥墮急流，羨君高謝此籠囚。", "能詩似是林和靖，博古寧慙許散愁。", "上藥化金纔頃刻，虛舟觸物信沉浮。", "何時我亦休官去，對卧元龍百尺樓。"]'),
('87d0acbd-10f8-4ab8-bf69-c6e9df4bb3be','次諸公韻','陳造','宋','宋诗','song-poetry','','[]','回首舟餐野店棲，何殊子美詠青泥。',64,'全唐诗/poet.song.151000.json','["回首舟餐野店棲，何殊子美詠青泥。", "朅來賢將先回盼，徑上詩壇許命題。", "舉白爛陪山簡醉，凝香到有武陵迷。", "異時過計今方悔，曾慮談間彼子西。"]'),
('3735826c-3a0e-4af0-9b65-73d45914897a','對雪小吟次前韻','陳造','宋','宋诗','song-poetry','','[]','翻鴉啅鵲暝爭棲，舞絮郊原雪冰泥。',64,'全唐诗/poet.song.151000.json','["翻鴉啅鵲暝爭棲，舞絮郊原雪冰泥。", "已綴瓏璁分檜柏，併揚光彩賁榱題。", "撚鬚句好無前勇，索酒人歸有後迷。", "客子鬢毛今愧此，忍寒挾策市橋西。"]'),
('a988bfe6-6a96-4f4b-abeb-986afed317eb','再次韻謝張守得新居','陳造','宋','宋诗','song-poetry','','[]','得巢歸翼愜卑棲，尚卷風茅落凍泥。',64,'全唐诗/poet.song.151000.json','["得巢歸翼愜卑棲，尚卷風茅落凍泥。", "病樹緣階旋培植，舊書堆案細籤題。", "地非新野聊龍卧，人似東屯賸客迷。", "身世只今供冷笑，百川東注月行西。"]'),
('0b89ede6-cdf2-4363-8323-758b09502f5d','再次韻呈張守  其一','陳造','宋','宋诗','song-poetry','','[]','烏衣雛燕正依棲，又見南風遞赤泥。',64,'全唐诗/poet.song.151000.json','["烏衣雛燕正依棲，又見南風遞赤泥。", "宣室殊恩子夜對，天章清問御書題。", "可無上藥蠲民瘼，有待司南覺世迷。", "好在論功繼皋益，毋庸問管凟曾西。"]'),
('82434966-e05a-46b2-9d6b-8f5ad461d83a','再次韻呈張守  其二','陳造','宋','宋诗','song-poetry','','[]','朋舊携持過陋棲，炊香瀹雪鱠拖泥。',64,'全唐诗/poet.song.151000.json','["朋舊携持過陋棲，炊香瀹雪鱠拖泥。", "酒澆礧磈聊娛老，詩愬酸寒最切題。", "種秫集功今有約，對棋銷日不嫌迷。", "千奴別去平安否，時欲拏舟甓社西。"]'),
('f9f1f34a-e18d-4b4a-bb70-1ec9324bd843','聞盱眙北使信感事再次韻','陳造','宋','宋诗','song-poetry','','[]','猰犬妖狐合故棲，函關底限一丸泥。',64,'全唐诗/poet.song.151000.json','["猰犬妖狐合故棲，函關底限一丸泥。", "幄中已辦吞青海，甲外寧惟馘白題。", "犂老上庭煩指顧，笞中行背問顛迷。", "提封舊物渠須計，一候鞮汗更向西。"]'),
('c99a33ef-e103-47c1-aab1-e327cc4b3199','雪晴再次韻','陳造','宋','宋诗','song-poetry','','[]','璇穹瑩澈晴風後，曉日初融陌路泥。',64,'全唐诗/poet.song.151000.json','["璇穹瑩澈晴風後，曉日初融陌路泥。", "老檜蒼筠潛動色，迎春送臘好分題。", "藏春僧閤心曾戀，闖海山亭夢到迷。", "回首桑陰三宿舊，鄮城東去虎存西。"]'),
('0bf75b8f-1707-4f41-b45f-2029459585bc','對客再次韻','陳造','宋','宋诗','song-poetry','','[]','客來一笑同鄉味，便粉秋菰刷藕泥。',64,'全唐诗/poet.song.151000.json','["客來一笑同鄉味，便粉秋菰刷藕泥。", "糟浥子薑仍舊法，籠緘乾笋儼新題。", "白魚紫蟹空濡沫，窘兔驚麋想碭迷。", "自揣臞儒合蔬糲，放麑終恐愧巴西。"]'),
('2c1ae8fc-527f-4fc9-bb40-771d50c886dd','述懷再次韻','陳造','宋','宋诗','song-poetry','','[]','高車駟馬笑雞棲，亦笑餔糟與汩泥。',64,'全唐诗/poet.song.151000.json','["高車駟馬笑雞棲，亦笑餔糟與汩泥。", "魯酒得間聊復飲，晉輿投老偶然題。", "春冰自水收新悟，雨矢無鄉悔舊迷。", "尚有平生山水癖，未妨遊戲向京西。"]'),
('a1504d9b-e4b5-4c57-9f51-0409a41ccec0','次韵嚴文炳兼簡張守二首  其一','陳造','宋','宋诗','song-poetry','','[]','嬉遊有願自今償，回首春容已浩茫。',64,'全唐诗/poet.song.151000.json','["嬉遊有願自今償，回首春容已浩茫。", "霽景偏遲張錦地，小園秀出卧雲莊。", "梅林破玉香沾袂，池水摇漪淥泛堂。", "茶具筆床陪語笑，未妨日飲慰還鄉。"]'),
('2995cb1d-7926-4cf6-a9ef-f83631323433','次韵嚴文炳兼簡張守二首  其二','陳造','宋','宋诗','song-poetry','','[]','梅梅柳柳護深行，倦客重遊眼更明。',64,'全唐诗/poet.song.151000.json','["梅梅柳柳護深行，倦客重遊眼更明。", "谷鳥自應尋舊約，渚蘭潛欲換新萌。", "詩工已可醒人醉，賦就當須冰坐清。", "老我客渠真得計，夢魂無復鳳凰城。"]'),
('5905c7d6-c884-42aa-bc6c-4c7e7c61a556','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','宋璞隋珠不當償，平時佳思墮荒茫。',64,'全唐诗/poet.song.151000.json','["宋璞隋珠不當償，平時佳思墮荒茫。", "老規種秫師陶令，備有前茅愧楚莊。", "蜂鶴攪腸空軋軋，鸛鵝嚴陣怯堂堂。", "即今全勝輸公等，自占床敷霸睡鄉。"]'),
('fe3f0313-e73d-4832-8d3d-da2721e4e2f8','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','欲轡青驄試小行，擁衾待得曉窗明。',64,'全唐诗/poet.song.151000.json','["欲轡青驄試小行，擁衾待得曉窗明。", "端知霽日渾無價，可信啼鳩識未萌。", "勝處風烟堪一醉，是家池館擅雙清。", "不憂兒輩妨人樂，倚頼詩豪五字城。"]'),
('ff0d370a-5987-4ae9-81bc-1a6cee82f8a9','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','郡政只今多暇日，名園欲到指蒼茫。',64,'全唐诗/poet.song.151000.json','["郡政只今多暇日，名園欲到指蒼茫。", "能詩有客憐侯喜，好士惟公繼鄭莊。", "促膝未妨澠似酒，轉頭當復玉爲堂。", "聯金綴玉真吾事，賸刻堅珉表士鄉。"]'),
('26ff1731-3cd1-4e5a-8d3c-4f716612d91f','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','近墅何妨一再行，後車應著老彌明。',64,'全唐诗/poet.song.151000.json','["近墅何妨一再行，後車應著老彌明。", "詩成直壓搶榆上，譚勝寧容鄙吝萌。", "鷗鷺一灘窺語笑，松筠千挺峙寒清。", "從今好繪斜川集，莫靳流傳到帝城。"]'),
('4a66b3e8-aa0b-4ca2-928e-6e66a69f6a21','再次韻張德恭二首  其一','陳造','宋','宋诗','song-poetry','','[]','公家父子書林傑，力探希微析混茫。',64,'全唐诗/poet.song.151000.json','["公家父子書林傑，力探希微析混茫。", "膝上風流識文度，鯈游領解契蒙莊。", "六花陣勢容摩壘，五鳳規模見肯堂。", "自嘆吾兒豚犬爾，祇宜耕牧守窮鄉。"]'),
('66c0a29b-1663-45d4-8e0a-7bb65faa493b','再次韻張德恭二首  其二','陳造','宋','宋诗','song-poetry','','[]','平日疎愚但意行，每從師友仰高明。',64,'全唐诗/poet.song.151000.json','["平日疎愚但意行，每從師友仰高明。", "如君况是庭蘭秀，向我防譏凍芋萌。", "柏悅懸知待松茂，渭流終不溷涇清。", "新詩應敵纔餘事，紙價于今貴列城。"]'),
('2176ad41-cd94-4751-a7c7-b873aecded64','文炳近歲節感愴作詩寬之','陳造','宋','宋诗','song-poetry','','[]','嚴侯才氣舊無朋，晚作江淮肉食僧。',64,'全唐诗/poet.song.151000.json','["嚴侯才氣舊無朋，晚作江淮肉食僧。", "飽對風烟吐膏馥，時因節物動銷凝。", "君今宛是林和靖，我亦何如杜伯升。", "濁酒寒菹共一笑，未妨同剔課詩燈。"]'),
('eb5a7571-0c51-4219-97ad-1cac48518a9b','再次韻復文炳','陳造','宋','宋诗','song-poetry','','[]','君猶芹泮老賓朋，我似房公再世僧。',64,'全唐诗/poet.song.151000.json','["君猶芹泮老賓朋，我似房公再世僧。", "烟徑幽尋春澹沲，月窗冷語夜澄凝。", "人情感舊多爲祟，酒盞澆愁更計升。", "笑命棋枰同永夜，旋添萁火上篝燈。"]'),
('a4eeb905-d7ce-41a4-9cca-b0088827d74a','再次韻呈張守','陳造','宋','宋诗','song-poetry','','[]','使君劉白信其朋，笑我頑然粥飯僧。',64,'全唐诗/poet.song.151000.json','["使君劉白信其朋，笑我頑然粥飯僧。", "打睡正便簷日煖，味詩還喜蔗漿凝。", "破陰風軟梅猶小，弄影雲疎月漸升。", "一自藏鈎得新句，莫停吟筆到燒燈。"]'),
('1a2e0646-99a4-4fb2-99c0-af7fd0ca6cc0','再次韻贈張德恭  其一','陳造','宋','宋诗','song-poetry','','[]','老尋詩法得良朋，轉處驪珠悟後僧。',64,'全唐诗/poet.song.151000.json','["老尋詩法得良朋，轉處驪珠悟後僧。", "帝所宮商中夜奏，仙盤沆瀣未秋凝。", "樂天不幸逢元稹，季友而來有彥升。", "交手當家親父子，爲君別本記傳燈。"]'),
('500ede8e-4159-48e2-835b-8f95b0b72a9f','再次韻贈張德恭  其二','陳造','宋','宋诗','song-poetry','','[]','辭鋒森列看分朋，退作窮山苦行僧。',64,'全唐诗/poet.song.151000.json','["辭鋒森列看分朋，退作窮山苦行僧。", "每讀嚴詩驚我倒，亦知舜績待公凝。", "絲綸指日從天下，閶闔摩霄接武升。", "更想班衣奉親壽，五雲低護九枝燈。"]'),
('6ac95a0a-8c85-4c63-aed2-f332b6c98537','再次韻贈張德恭  其三','陳造','宋','宋诗','song-poetry','','[]','闖門不乏遠方朋，辟席渾如問話僧。',64,'全唐诗/poet.song.151000.json','["闖門不乏遠方朋，辟席渾如問話僧。", "筆底煙雲無盡藏，譚間霜霰不寒凝。", "身行建德歡謠裏，人在春臺瑞日升。", "老子生涯漫訾省，擁書猶傍短檠燈。"]'),
('965b194e-1af5-4878-b78b-efe6b1dbec5c','再次韻贈張德恭  其四','陳造','宋','宋诗','song-poetry','','[]','同門誰定肯論朋，拙似苕鳩嬾似僧。',64,'全唐诗/poet.song.151000.json','["同門誰定肯論朋，拙似苕鳩嬾似僧。", "病減不辭詩語拙，歸來少貸客愁凝。", "老欺鬢髮絲千丈，糴仰官倉日五升。", "臺閤中天清夢斷，分眠山店問漁燈。"]'),
('604047b0-0e59-4ccf-bafe-3893594f496d','都梁塗中','陳造','宋','宋诗','song-poetry','','[]','西來行路未妨長，敢指淮山作異鄉。',64,'全唐诗/poet.song.151000.json','["西來行路未妨長，敢指淮山作異鄉。", "隨處饋漿驚禦寇，有人酬藥話韓康。", "柳方弄色新經雨，雲似多情巧護霜。", "風俗淳厖節物好，一樽時與倒詩囊。"]'),
('ea560e7c-0a01-46f7-89b6-39d6a16e9064','謝鄒祕正惠淮白呂判院送酒','陳造','宋','宋诗','song-poetry','','[]','簷鵲聲前拆鴈書，雙材有底到蝸廬。',64,'全唐诗/poet.song.151000.json','["簷鵲聲前拆鴈書，雙材有底到蝸廬。", "潔樽幾夢沾膏露，下筯于今薦腹腴。", "仙府流霞端伯仲，徐州禿尾但臺輿。", "寒人醉飽何緣靜，徑攪詩腸撚白鬚。"]'),
('94f757e5-0a6b-4df9-a3a3-91d0f097a8da','寄章茂深郎中二首  其一','陳造','宋','宋诗','song-poetry','','[]','州麾郎省未華顛，解組歸來作地仙。',64,'全唐诗/poet.song.151000.json','["州麾郎省未華顛，解組歸來作地仙。", "杖屨良多閑日月，亭臺仍占好林泉。", "青奴白牯冰壺裏，墮絮漂花醉眼前。", "政用著書傳我輩，未須緘口縛枯禪。"]'),
('efe3a03b-a73d-4017-b81b-223ac5a939aa','寄章茂深郎中二首  其二','陳造','宋','宋诗','song-poetry','','[]','立譚當日受知深，不待陳情道古今。',64,'全唐诗/poet.song.151000.json','["立譚當日受知深，不待陳情道古今。", "高會幾陪山簡醉，長篇許爲愛卿吟。", "歲華遷謝心雖在，世路崎嶇老不禁。", "擬近卞山謀卜築，借公泉水濯塵襟。"]'),
('3cdf9da5-d078-4b68-af48-2e4e527ec283','自適三首  其一','陳造','宋','宋诗','song-poetry','','[]','自憐老瘦仍癡絕，每强衰顔趁後生。',64,'全唐诗/poet.song.151000.json','["自憐老瘦仍癡絕，每强衰顔趁後生。", "療癖無方了詩課，迷魂有寨對棋枰。", "繞床不著阿堵物，玩世何須身後名。", "倚頼兒曹解人意，典衣長得解餘酲。"]'),
('51e58bcc-7e4a-4720-bc8d-966a0c9c4373','自適三首  其二','陳造','宋','宋诗','song-poetry','','[]','渺漭湖天入短篷，心期祇許白鷗同。',64,'全唐诗/poet.song.151000.json','["渺漭湖天入短篷，心期祇許白鷗同。", "人言火食閬蓬客，自命官身田舍翁。", "酒可銷閑時得醉，詩憑寫意不求工。", "更那長日溫書眼，一送蜚鴻下遠空。"]'),
('a3201821-bb67-4c4b-b7c7-54d43ce01a54','自適三首  其三','陳造','宋','宋诗','song-poetry','','[]','雲水爲家百累無，意行從昔畧方隅。',64,'全唐诗/poet.song.151000.json','["雲水爲家百累無，意行從昔畧方隅。", "飲忘醒醉狂常爾，夢到無何午未蘇。", "遺俗可辭翻襪錯，付渠陰作負舟趨。", "譊譊禮法工相聒，閉戶仍防大小儒。"]'),
('5cd4bdc1-cae1-4b6e-965c-506f2c457b99','正月十四日雪','陳造','宋','宋诗','song-poetry','','[]','鄉園燈市頗豪奢，客子扁舟恰到家。',64,'全唐诗/poet.song.151000.json','["鄉園燈市頗豪奢，客子扁舟恰到家。", "月姊層雲藏寶鑒，雪神千手撲天葩。", "未容火樹陪宵燕，謾說江梅擅歲華。", "苦憶醉穿羅綺陣，小軿吟度赤城霞。"]'),
('4051e256-39ac-4149-832f-6b3852fd460c','送七子赴省','陳造','宋','宋诗','song-poetry','','[]','旋轉璣衡運化樞，嗣皇襲六待耆儒。',64,'全唐诗/poet.song.151000.json','["旋轉璣衡運化樞，嗣皇襲六待耆儒。", "斗南譽望俱難匹，鄴下才華舊不孤。", "郡賦今推作者並，王庭可但諍臣趨。", "竹林昔隠休回首，四輔三公此首塗。"]'),
('213e99a4-33f6-4e8b-999f-5dd86a9d7ae6','次韻胡元善','陳造','宋','宋诗','song-poetry','','[]','柳間鶑友羽衣輕，花外溪流鏡面平。',64,'全唐诗/poet.song.151000.json','["柳間鶑友羽衣輕，花外溪流鏡面平。", "勝處過君時得醉，今春屬我老歸耕。", "吏塵祇可黄粱夢，棋社聊尋白鷺盟。", "猶計浮名孤樂事，風煙滿眼得無情。"]'),
('bcdeba68-9227-48f2-be8b-0e534fd4b3ff','張守招隠','陳造','宋','宋诗','song-poetry','','[]','春風吹作萬家春，誰得聯鑣從使君。',64,'全唐诗/poet.song.151000.json','["春風吹作萬家春，誰得聯鑣從使君。", "微徑問花同載酒，深堂剪燭細論文。", "王郎把臂簪仍盍，嚴老呼舟首又分。", "安得雲龍隨上下，佳辰不復嘆離羣。"]'),
('5ad4976f-25aa-40f3-a687-f91be8a25bb5','次韻張守勸農  其一','陳造','宋','宋诗','song-poetry','','[]','東郊春好近清明，小隊相羊爲省耕。',64,'全唐诗/poet.song.151000.json','["東郊春好近清明，小隊相羊爲省耕。", "扶路人歸皆喜色，應時雷殷亦和聲。", "不妨密雨催花放，有底屯雲妬月盈。", "遥想一尊同客夜，燭花未剪已詩成。"]'),
('b9c21d22-25be-4f9a-8c30-9f3091144f45','次韻張守勸農  其二','陳造','宋','宋诗','song-poetry','','[]','眼向囊書老不明，合遵寬教事農耕。',64,'全唐诗/poet.song.151000.json','["眼向囊書老不明，合遵寬教事農耕。", "雨餘驟變菖條綠，曉起欣聆布穀聲。", "譚笑俾民無死徙，豐凶轉手有虛盈。", "衰翁倍荷殷勤意，緘致無非翠織成。"]'),
('7b3311a7-8f02-4dd4-bd6d-788837983ad2','次韻王勉夫晚春','陳造','宋','宋诗','song-poetry','','[]','送春無酒未須嗟，却有新茶試大家。',64,'全唐诗/poet.song.151000.json','["送春無酒未須嗟，却有新茶試大家。", "便愜輕凉生小扇，獨憐撲蔌下蔫花。", "霜膚解籜初嘗筍，怒癭因誰擬問蛙。", "嘉樹著行森羽葆，翠青疎密儼排衙。"]'),
('8f901cb2-8d03-4bfa-87a9-930d45f7ed18','次韻張守遊趙園','陳造','宋','宋诗','song-poetry','','[]','躬挽慈輿訪小園，徑𣂏和氣滿壺天。',64,'全唐诗/poet.song.151000.json','["躬挽慈輿訪小園，徑𣂏和氣滿壺天。", "微風會意祛輕暑，紅藥多情駐晚妍。", "欬唾生春見能事，平反供笑掩前賢。", "奉親得句無窮樂，不學狂生卧酒船。"]'),
('4b5ec26b-4c88-424f-a924-f08fa0e32f91','次韻張守王勉夫二首  其一','陳造','宋','宋诗','song-poetry','','[]','兩雋詩聲敢重輕，蒼山對峙大川傾。',64,'全唐诗/poet.song.151000.json','["兩雋詩聲敢重輕，蒼山對峙大川傾。", "形爲幼眇無遺恨，有入題評莫遁情。", "未許曹劉夸獨步，不應邾莒合逃盟。", "清篇讀罷重看鏡，似覺青絲鬢脚生。"]'),
('2493dc7e-4d38-4476-b198-2beaaeb1ca3c','次韻張守王勉夫二首  其二','陳造','宋','宋诗','song-poetry','','[]','世味平時蟲臂輕，獨留意氣與君傾。',64,'全唐诗/poet.song.151000.json','["世味平時蟲臂輕，獨留意氣與君傾。", "向來繾綣資磨玷，擬話分携已愴情。", "盛際功名方策足，他年車笠肯渝盟。", "漢廷取重張廷尉，可待區區結襪生。"]'),
('52dcd092-bd85-4aba-b637-016c1c71d503','再次韻送張守  其一','陳造','宋','宋诗','song-poetry','','[]','目送歸帆風翮輕，贈詩還笑字欹傾。',64,'全唐诗/poet.song.151000.json','["目送歸帆風翮輕，贈詩還笑字欹傾。", "如公風義仍知己，計我隆污合用情。", "想覲龍顔新得意，未忘牛耳舊同盟。", "周旋尚可諸公後，肯放江湖了此生。"]'),
('01612f06-26ae-480a-83fb-182e6d7bf621','再次韻送張守  其二','陳造','宋','宋诗','song-poetry','','[]','未解州符累已輕，辭源滿意酒邊傾。',64,'全唐诗/poet.song.151000.json','["未解州符累已輕，辭源滿意酒邊傾。", "頡頏前輩真無愧，褒拂迂儒每過情。", "老境更堪聽別語，書郵當復固齊盟。", "吳山正合供酬唱，安得風前兩翼生。"]'),
('4fbc3dc1-48d5-496e-a6cc-bb67c44656b2','再次韻送張守  其三','陳造','宋','宋诗','song-poetry','','[]','唾壺聲裏晚凉輕，風自虛徐月自傾。',64,'全唐诗/poet.song.151000.json','["唾壺聲裏晚凉輕，風自虛徐月自傾。", "詩好要從知者道，格高今識古人情。", "三熏誰定分膏馥，十襲吾方守詛盟。", "預恐幽居念離索，時須開卷慰愁生。"]'),
('59422c61-9fe5-480c-bd07-5cbdc22db844','再次韻送張守  其四','陳造','宋','宋诗','song-poetry','','[]','性資凉踽繫時輕，青眼惟公底裏傾。',64,'全唐诗/poet.song.151000.json','["性資凉踽繫時輕，青眼惟公底裏傾。", "砥柱頹波儲碩望，陽春窮谷見高情。", "青冥蜚上應回首，陸續詩來可待盟。", "念我老無當世意，擬從樵牧寄餘生。"]'),
('54a5554b-0904-4c6c-92aa-5011f4b73f63','次韻常倅俞君任二首  其一','陳造','宋','宋诗','song-poetry','','[]','匆匆同醉記前年，客路重逢亦偶然。',64,'全唐诗/poet.song.151000.json','["匆匆同醉記前年，客路重逢亦偶然。", "理窟扣君彌入域，生涯憐我欠加鞭。", "了知富貴難投足，共約歸來徑息肩。", "舊欲將雛卜鄰去，未應須辦十牛田。"]'),
('bea3554a-40fd-4655-a4a9-1fa02a9884fd','次韻常倅俞君任二首  其二','陳造','宋','宋诗','song-poetry','','[]','與君顔面各臨年，同滯江湖恐不然。',64,'全唐诗/poet.song.151000.json','["與君顔面各臨年，同滯江湖恐不然。", "虎兕向來甘曠野，驊騮寧復待揮鞭。", "政成合進凌霄步，客裏猶擡斲句肩。", "人品國華君可仰，豈應學我賦歸田。"]'),
('9eaba57f-9865-4f98-89f0-5cbbf4e1cf48','又悼石湖老人','陳造','宋','宋诗','song-poetry','','[]','老商笑不待三年，枵腹人人得果然。',64,'全唐诗/poet.song.151000.json','["老商笑不待三年，枵腹人人得果然。", "商俗均霑傅巖雨，中行羞死繞朝鞭。", "探原已茹丘軻胾，落筆聊差屈宋肩。", "緬想神遊知有處，定驂鸞鶴戲芝田。"]'),
('bb71ea09-5cc5-4f3a-a160-bf8c9946d091','再次韻酬俞君任','陳造','宋','宋诗','song-poetry','','[]','闖首亨衢屬壯年，即今奔騖恐徒然。',64,'全唐诗/poet.song.151000.json','["闖首亨衢屬壯年，即今奔騖恐徒然。", "時情合退羊腸步，宦路難加馬腹鞭。", "朱紫浪驚流俗眼，風騷要拍古人肩。", "歸休計辦君當賀，兒輩新營種秫田。"]'),
('20ede86a-e499-4d73-b956-0c2cdcbc45d2','再次韻呈楊侍郎','陳造','宋','宋诗','song-poetry','','[]','左符得請未逾年，民譽朝評兩藹然。',64,'全唐诗/poet.song.151000.json','["左符得請未逾年，民譽朝評兩藹然。", "補衮工夫舊荷橐，承流政績暫蒲鞭。", "周衡可迓須分陝，孔室容窺顧及肩。", "側佇翹材著枚叟，看公親反汶陽田。"]'),
('b866733c-7785-437f-9285-56dfb0bbdf53','楊侍郎召飯再用韻','陳造','宋','宋诗','song-poetry','','[]','昇沉渠敢話齊年，妙句推褒輩行然。',64,'全唐诗/poet.song.151000.json','["昇沉渠敢話齊年，妙句推褒輩行然。", "高燕况叨瓊作醴，凡駘底稱玉爲鞭。", "歌終畫扇猶遮面，舞困欹花半壓肩。", "此去雋遊縈客夢，夢陪笙鶴下瓊田。"]'),
('92e341f9-991f-41f7-b410-e37876abd9f0','郝澤民主簿贈詩次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','夫君糠粃視錢神，詩逼黄初論借秦。',64,'全唐诗/poet.song.151000.json','["夫君糠粃視錢神，詩逼黄初論借秦。", "義槩咸推天下士，簿曹聊見宰官身。", "茶香延客自不飽，書幣踵門誰可人。", "從古功名多晚節，相逢雙鬢未妨新。"]'),
('7e687eb7-fba5-42fe-aa91-e018cd78360c','郝澤民主簿贈詩次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','薄宦年來尚轉蓬，忍將榮悴問虛中。',64,'全唐诗/poet.song.151000.json','["薄宦年來尚轉蓬，忍將榮悴問虛中。", "共憐杜老諳爲客，不訝元忠厭作公。", "勝日笑譚方衮衮，殘冬光景苦匆匆。", "棋枰得雋詩反水，誰信吾徒舊諱窮。"]'),
('645a9b21-0127-42c2-9cbc-96392970705c','再次前韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','解纜征塗一愴神，房陵十舍望西秦。',64,'全唐诗/poet.song.151000.json','["解纜征塗一愴神，房陵十舍望西秦。", "苦無勳業裨昭代，久分江湖著老身。", "三楚上遊常定伯，六朝陳迹渺愁人。", "不緣俛仰悲凉甚，可博臨風得句新。"]'),
('ac62cd22-451c-421c-978e-707f6ea230e9','再次前韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','起柁揚帆趁便風，狎鷗驚鴈水煙中。',64,'全唐诗/poet.song.151000.json','["起柁揚帆趁便風，狎鷗驚鴈水煙中。", "裹香薦彘聊隨俗，計日聽雞等自公。", "詩句滌愁收一一，酒杯澆別悔匆匆。", "與君二紀陳雷契，猶遣時人笑兩窮。"]'),
('7e83063e-8d80-4242-b2e1-8613561f0ef9','登平山堂','陳造','宋','宋诗','song-poetry','','[]','平山堂上命琴樽，前輩風流肯見分。',64,'全唐诗/poet.song.151000.json','["平山堂上命琴樽，前輩風流肯見分。", "戀客嬾斜當檻日，藏山不斷隔江雲。", "吟牋得意窺天巧，醉面禁凉減纈紋。", "杖策歸來新月上，落梅如雪點風裙。"]'),
('b9464f06-4979-4084-8ede-1974bc6dd5ba','郢州二首  其一','陳造','宋','宋诗','song-poetry','','[]','古郢繁華得少留，披雲更喜識賢侯。',64,'全唐诗/poet.song.151000.json','["古郢繁華得少留，披雲更喜識賢侯。", "徑容拱挹侍譚笑，怪底咄嗟成獻酬。", "羅綺香中偷醉眼，蕙蘭叢裏掉吟頭。", "何如白玉堂中客，試問樽前小莫愁。"]'),
('dc0c1b34-fc0d-4d95-93a5-b9a66c2bb807','郢州二首  其二','陳造','宋','宋诗','song-poetry','','[]','滿慰人間渴雨心，未收雲靄定爲霖。',64,'全唐诗/poet.song.151000.json','["滿慰人間渴雨心，未收雲靄定爲霖。", "憐渠沾水論涓滴，况我行舟苦滯淫。", "已漲麥田千里碧，更添沙料一篙深。", "小軿會指晴山去，布穀提壺各好音。"]'),
('4b924755-d513-4270-b847-b62b2b33cc71','春日客中二首  其一','陳造','宋','宋诗','song-poetry','','[]','平時謾說醉爲鄉，對景今如石作腸。',64,'全唐诗/poet.song.151000.json','["平時謾說醉爲鄉，對景今如石作腸。", "老去猶興客中嘆，春來剛制酒邊狂。", "露桃煙柳爲誰好，蜂蜜燕泥徒自忙。", "紅紫打圍歌笑地，暮年多感怕思量。"]'),
('7e4aab0e-d73d-46db-a8c3-38fada66af5b','春日客中二首  其二','陳造','宋','宋诗','song-poetry','','[]','芳時已嘆鬢毛斑，何况棲棲客路間。',64,'全唐诗/poet.song.151000.json','["芳時已嘆鬢毛斑，何况棲棲客路間。", "杯酒故人千里隔，錦囊著語一春閑。", "燕鶑飛處頻回首，桃李香前合厚顔。", "昨夜東風貸庭竹，少容歸夢到家山。"]'),
('b11dfaba-76fd-4eba-b7a2-862313fea042','石城','陳造','宋','宋诗','song-poetry','','[]','山巖水繚石爲城，千古餘風尚典刑。',64,'全唐诗/poet.song.151000.json','["山巖水繚石爲城，千古餘風尚典刑。", "競詫君王啟藍縷，不無艇子載娉婷。", "流連猶問圭堪柲，兆朕虛傳蜜作萍。", "更惜讒鋒發蘭尚，祇今日月炳騷經。"]'),
('ef9f2f13-8bd7-431e-a6fc-f44a6f5784d9','次韻程帥遊習池三首  其一','陳造','宋','宋诗','song-poetry','','[]','牙纛猶容後乘追，枕書不出此何時。',64,'全唐诗/poet.song.151000.json','["牙纛猶容後乘追，枕書不出此何時。", "香飄玳席千花塢，影倒粧光百子池。", "詩句肯藏捫虱手，仙曹容著牧羊兒。", "回思行李冒塵土，更喜百憂偷一嬉。"]'),
('e2201691-bd9a-44be-965f-ae22402d421e','次韻程帥遊習池三首  其二','陳造','宋','宋诗','song-poetry','','[]','清明勝賞尚容追，不減觴浮曲水時。',64,'全唐诗/poet.song.151000.json','["清明勝賞尚容追，不減觴浮曲水時。", "坐覺晴雲戀歌扇，看供吟筆瀉天池。", "春光有底遽如許，酒量勉添些子兒。", "可但大堤民氣樂，啼鶑語燕共嬉嬉。"]'),
('ddcbc41a-b50b-4600-8532-6b03efc1dd97','次韻程帥遊習池三首  其三','陳造','宋','宋诗','song-poetry','','[]','青編勛業笑談追，千載生賢瑞聖時。',64,'全唐诗/poet.song.151000.json','["青編勛業笑談追，千載生賢瑞聖時。", "竹帛會書河似带，封疆不止漢爲池。", "玄譚日屬王平子，妙語心輕謝客兒。", "來歲賞花應帝所，賡歌宣勸倍歡嬉。"]'),
('39fdc864-3868-4cf2-aa61-aff33b846a41','春雨贈陳主管','陳造','宋','宋诗','song-poetry','','[]','初宵微月尚窺簷，雨脚斜斜曉入簾。',64,'全唐诗/poet.song.151000.json','["初宵微月尚窺簷，雨脚斜斜曉入簾。", "春謝歡悰風處減，愁將老色鏡中添。", "頗思甫里陪觴詠，不嘆周南更滯淹。", "倚頼宗盟慰牢落，得閑詩筆未妨拈。"]'),
('be3a3acd-434c-43b1-817c-8e8a8328ea23','陳主管招飲','陳造','宋','宋诗','song-poetry','','[]','鵲拳庭竹語頻頻，忽有書來寂寞濱。',64,'全唐诗/poet.song.151000.json','["鵲拳庭竹語頻頻，忽有書來寂寞濱。", "盛事許同花燭夜，芳辰仍醉綺羅春。", "璧聯香閤初鳴鳳，霞泛仙觴定脯麟。", "更辦歸裝攟珠玉，一時人物各詩人。"]'),
('65faeafa-9b0e-4017-a4b0-2742d5921bad','山行寄程帥','陳造','宋','宋诗','song-poetry','','[]','雨餘支徑濕平沙，恰稱卑官下澤車。',64,'全唐诗/poet.song.151000.json','["雨餘支徑濕平沙，恰稱卑官下澤車。", "雜樹暝烟森立槊，亂峰迎客儼排衙。", "水禽時弄蹁躚影，野草爭開細碎花。", "久憶山行此如願，不應回首更思家。"]'),
('4babc7f4-e0df-44d2-a215-84ffbdb7dafe','次日再次韻三首  其一','陳造','宋','宋诗','song-poetry','','[]','山行風色怒飛沙，山末屯雲湧砲車。',64,'全唐诗/poet.song.151000.json','["山行風色怒飛沙，山末屯雲湧砲車。", "伏軾不容同蝶夢，問炊猶可趁蜂衙。", "龜魚泛淥熹晴日，草樹留春著晚花。", "暮憩自憐塵滿面，五漿先饋定誰家。"]'),
('9d1ebe99-2dfb-4524-8eda-d0320afb1bcf','次日再次韻三首  其二','陳造','宋','宋诗','song-poetry','','[]','微吟緩步愜晴沙，聊謝愔愔載婦車。',64,'全唐诗/poet.song.151000.json','["微吟緩步愜晴沙，聊謝愔愔載婦車。", "時遣貰貂邨店酒，回思縛虎長官衙。", "春山好著屏中色，吟筆誰添錦上花。", "不妨習池風月主，只今何處問詩家。"]'),
('2a047160-6a6d-4573-a321-f027ddd82f67','次日再次韻三首  其三','陳造','宋','宋诗','song-poetry','','[]','鷗雙鷺隻傍汀沙，却匯沙汀過客車。',64,'全唐诗/poet.song.151000.json','["鷗雙鷺隻傍汀沙，却匯沙汀過客車。", "清吹解撩叢竹嘯，高山如受衆峰衙。", "寒生碧澗懸魚網，潤著蒼崖賸土花。", "所惜隔牆紅紫滿，行行無暇訪山家。"]'),
('445e96f6-9598-4589-9031-86ed6553c831','穀城道中','陳造','宋','宋诗','song-poetry','','[]','何許珠襟繡袂娘，額黄胸粉自新粧。',64,'全唐诗/poet.song.151000.json','["何許珠襟繡袂娘，額黄胸粉自新粧。", "野芳貪折髻丫重，蝴蝶亂隨裙幅香。", "緩唱采菱空答響，小留挑菜翠盈筐。", "漢風未許休喬木，行客相逢莫漫狂。"]'),
('56f92022-9ccd-410e-b8e0-8764734e1574','再次習池詩韻寄程帥二首  其一','陳造','宋','宋诗','song-poetry','','[]','南園勝絕真堪畫，邊上誰爲李伯時。',64,'全唐诗/poet.song.151000.json','["南園勝絕真堪畫，邊上誰爲李伯時。", "山納嫩嵐侵密坐，花駢紅影闖清池。", "吟牋傳遍鴛鴻友，舞袖輕于翡翠兒。", "東府西州皆四鬴，若爲長伴酒邊嬉。"]'),
('23d5c9d5-a8b3-4ac0-a5d2-aedddd7a801c','再次習池詩韻寄程帥二首  其二','陳造','宋','宋诗','song-poetry','','[]','春意垂垂如我老，客懷領畧欠當時。',64,'全唐诗/poet.song.151000.json','["春意垂垂如我老，客懷領畧欠當時。", "倏驚鶗鴂鳴清晝，便有蜻蜓點碧池。", "酒榼相過但溪友，錦囊餘幾問廬兒。", "芳辰渠盡人離索，苦念從公乘燭嬉。"]'),
('c8172068-b9af-4f03-8ae9-53e805da5526','次韻寄王帥屬','陳造','宋','宋诗','song-poetry','','[]','才華奔逸可能追，我識王郎自壯時。',64,'全唐诗/poet.song.151000.json','["才華奔逸可能追，我識王郎自壯時。", "酒處每看鯨吸海，書成還想墨爲池。", "窮交徒自憐東野，孰看于今敬道兒。", "莫靳詩筒數還往，人生何處不兒嬉。"]'),
('606a8295-bd5d-4ee2-8d32-eb53fa0d07be','次韻寄陳主管','陳造','宋','宋诗','song-poetry','','[]','軺軿七十曉相追，記得張園敘拜時。',64,'全唐诗/poet.song.151000.json','["軺軿七十曉相追，記得張園敘拜時。", "香襯蕙蘭來北里，雲隨笙鶴燕仇池。", "朋簪重盍寧人力，貧仕居卑聽化兒。", "祇冀幕蓮分靫菂，詩壇棋社與閑嬉。"]'),
('0e5d618d-d399-4cdd-aa40-708915386f45','諸公邀留不及赴次前韻寄謝','陳造','宋','宋诗','song-poetry','','[]','一失濃歡悔可追，故人應念獨醒時。',64,'全唐诗/poet.song.151000.json','["一失濃歡悔可追，故人應念獨醒時。", "回思翠幕圍香霧，定復長虹起硯池。", "照應鼎來聯璧客，風流羞死聚蚊兒。", "當時枉重千金諾，不見芳辰卜夜嬉。"]'),
('69554203-c0e8-405a-bcdd-fb30283a6027','次韻謝程帥復遊習池見寄二首  其一','陳造','宋','宋诗','song-poetry','','[]','名園壯觀還前日，禊事追遊可後時。',64,'全唐诗/poet.song.151000.json','["名園壯觀還前日，禊事追遊可後時。", "試問繡筵張綠野，何如詩客到昆池。", "綺羅香外鶑偷眼，花柳稀間鳥哢兒。", "定許此民同此樂，春城無處不嬉嬉。"]'),
('f65ad802-9c79-4cb9-a2ca-d2559b7ba02d','次韻謝程帥復遊習池見寄二首  其二','陳造','宋','宋诗','song-poetry','','[]','風流羊杜不勞追，况復輕裘緩带時。',64,'全唐诗/poet.song.151000.json','["風流羊杜不勞追，况復輕裘緩带時。", "醉倒莫孤桃李月，詔歸恐便鳳凰池。", "政傳西蜀中和頌，筆跨東京大小兒。", "我亦抄詩支郡去，公餘吟玩取娛嬉。"]'),
('b64261d5-85cb-4b6f-ba72-d264216a2744','復次韻寄程帥二首  其一','陳造','宋','宋诗','song-poetry','','[]','節物匆匆可挽追，直須樂事趁芳時。',64,'全唐诗/poet.song.151000.json','["節物匆匆可挽追，直須樂事趁芳時。", "行春倏喜花圍屋，借景何殊月在池。", "對酒不無桃葉女，扣舷却笑木腸兒。", "山家有約須重到，定放遊人張水嬉。"]'),
('b08facee-bd32-423a-b7d4-9834a5702098','復次韻寄程帥二首  其二','陳造','宋','宋诗','song-poetry','','[]','人家禊祓競攀追，刺史春遊正此時。',64,'全唐诗/poet.song.151000.json','["人家禊祓競攀追，刺史春遊正此時。", "羯鼓聲中花作錦，壺籌多處酒爲池。", "絕須絲竹娛安石，賸有篇章付雪兒。", "聞道續貂容下客，老無佳句坐荒嬉。"]'),
('c995206c-4761-47c3-aae4-14e3b5c43500','留交代韋倅','陳造','宋','宋诗','song-poetry','','[]','山城老稚競攀轅，况復官曹辱後先。',64,'全唐诗/poet.song.151000.json','["山城老稚競攀轅，况復官曹辱後先。", "敢愛一樽追笑語，未妨五日作留連。", "天香國色酡顔去，渭北江東把臂前。", "已辦明朝開煮酒，絲桐小置式微篇。"]'),
('80952788-3440-40e7-aaa0-1312f8e76e84','觀山刑鵝夜歸','陳造','宋','宋诗','song-poetry','','[]','巢鵲枝蜩已罷鳴，風聲露氣可勝清。',64,'全唐诗/poet.song.151000.json','["巢鵲枝蜩已罷鳴，風聲露氣可勝清。", "人諳淺瀨安然度，月隔高林未肯明。", "却亂宿雲尋去路，漸因更鼓辨孤城。", "誰知歲事關心切，翻憶衝泥傍險行。"]'),
('4c84b3b9-1b79-4cb3-8fc6-dab2c7fb5fe7','禱雨鳳凰山二首  其一','陳造','宋','宋诗','song-poetry','','[]','跨鳳西來得好山，千年人與鳳俱還。',64,'全唐诗/poet.song.151000.json','["跨鳳西來得好山，千年人與鳳俱還。", "本規法席專嶄絕，先遣山靈鑿捍頑。", "聞道碧泓嚴水印，試携清醥闖雲關。", "此心炯炯龍應識，莫遣歸塗更厚顔。"]'),
('6af40394-80ee-4275-a59c-f59a1e4d94d5','禱雨鳳凰山二首  其二','陳造','宋','宋诗','song-poetry','','[]','人心神理未交孚，敢愛微軀走道塗。',64,'全唐诗/poet.song.151000.json','["人心神理未交孚，敢愛微軀走道塗。", "雲氣滿山空夢永，秧畦夾澗就焦枯。", "罷羸眼看號庚癸，感格吾猶愧鼓桴。", "老去憂民心易折，龍公高卧得知無。"]'),
('70eaed34-ca59-4523-813f-93513c7ab990','病起二首  其一','陳造','宋','宋诗','song-poetry','','[]','吏民兩兩議公癡，簿領空勤笑語稀。',64,'全唐诗/poet.song.151000.json','["吏民兩兩議公癡，簿領空勤笑語稀。", "元亮有詩新止酒，休文多病不勝衣。", "飛塵嬾拂孤三絕，止水初澄悟百非。", "窗度凉颸殘午夢，閑聽喜鵲啅斜暉。"]'),
('d2902030-b7ae-427d-b440-a18187197ebe','病起二首  其二','陳造','宋','宋诗','song-poetry','','[]','即病偷閑却自怡，坐憑竹几獨多時。',64,'全唐诗/poet.song.151000.json','["即病偷閑却自怡，坐憑竹几獨多時。", "銅爐烟畔熏風度，藥臼聲中晝漏遲。", "政自腐腸嚴酒戒，不應了事悔兒癡。", "凈名文惠誰優劣，爲問沾沾造化兒。"]'),
('f241cbfd-fa6c-4b51-8015-5f2384c46a58','寄高郵僧','陳造','宋','宋诗','song-poetry','','[]','門巷蕭然草不鋤，小軒祇置兩團蒲。',64,'全唐诗/poet.song.151000.json','["門巷蕭然草不鋤，小軒祇置兩團蒲。", "惟師表表叢林秀，眷我凉凉山澤臞。", "晨飯每同三韭陋，夜棋常辦百籌輸。", "一書未負西飛翼，滿寄清風到座隅。"]'),
('46383cee-4a0e-43a5-be19-07a4bb6c0f3e','苦雨','陳造','宋','宋诗','song-poetry','','[]','連月奔趨禱雨壇，即今積雨厭濛漫。',64,'全唐诗/poet.song.151000.json','["連月奔趨禱雨壇，即今積雨厭濛漫。", "蒼天信自有時漏，后土不知何日乾。", "坐想田疇淪沼沚，忍聞升合換罷紈。", "縱陽援溺知無術，慙愧身爲撫字官。"]'),
('48e7eef2-51ea-4d72-aa42-d05bd0279218','客次小憩','陳造','宋','宋诗','song-poetry','','[]','竹屋深明許息肩，田家延客解欣然。',64,'全唐诗/poet.song.151000.json','["竹屋深明許息肩，田家延客解欣然。", "霜枝高掛頳虬卵，風砌初摇白玉錢。", "得飽祇疑珠作粒，汲深仍詫乳爲泉。", "譚間更笑狂沮溺，政復知津未是賢。"]'),
('80a94980-c34e-420f-a356-ce5a65f86140','騎過山村','陳造','宋','宋诗','song-poetry','','[]','烟村面勢枕蒼山，一徑循山作屈蟠。',64,'全唐诗/poet.song.151000.json','["烟村面勢枕蒼山，一徑循山作屈蟠。", "入望高幢羅翠密，掛空匹練噀清寒。", "吟髭撚白迎風去，粧面駢紅倚戶看。", "頗似騎馿後山老，倩誰粉墨灑豪端。"]'),
('23b271c5-e7d7-45f2-a096-6aef82f088f9','杜母','陳造','宋','宋诗','song-poetry','','[]','杜母遺芳豈遠求，田功誰比此邦優。',64,'全唐诗/poet.song.151000.json','["杜母遺芳豈遠求，田功誰比此邦優。", "麥疄桑隴疑淮左，近水遥山似秀州。", "樓識景疎知俗美，亭因思孟各風流。", "我來眷眷淳厖處，比屋嬉嬉路載謳。"]'),
('bd374b9d-c0ef-4877-876c-6b258be560de','次韻程帥二首  其一','陳造','宋','宋诗','song-poetry','','[]','滿懷披霧慰生平，到日音容隔暮城。',64,'全唐诗/poet.song.151000.json','["滿懷披霧慰生平，到日音容隔暮城。", "想見舟中留郭泰，可能酒處欠公榮。", "韋家相業應門戶，謝氏才華况弟兄。", "愧我携兒在塵滓，寸田墝埆望茨京。"]'),
('1170b3c4-9b65-4f9a-9ebc-bb72cb1baeb7','次韻程帥二首  其二','陳造','宋','宋诗','song-poetry','','[]','人間塵不到籌邊，詩老乘閒思湧泉。',64,'全唐诗/poet.song.151000.json','["人間塵不到籌邊，詩老乘閒思湧泉。", "千佛香名仍世繼，一燈素業自家傳。", "斗城一去嗟多病，賓幕重登便半仙。", "要看諸郎各行馬，染鬚膏面計留年。"]'),
('89db4dba-1290-4759-8792-e96300016a72','再次韻  其一','陳造','宋','宋诗','song-poetry','','[]','門第應疑甚不庭，翩隨府檄下山城。',64,'全唐诗/poet.song.151000.json','["門第應疑甚不庭，翩隨府檄下山城。", "江梅作意先秋拆，檻菊多情擅晚榮。", "飲處凝香嚴畫㦸，客間張丈間殷兄。", "主賓縹緲蜚埃外，信有人間小玉京。"]'),
('ff559371-6693-476d-a612-9bb8a8cad999','再次韻  其二','陳造','宋','宋诗','song-poetry','','[]','從公囊筆看西邊，不比分弓出酒泉。',64,'全唐诗/poet.song.151000.json','["從公囊筆看西邊，不比分弓出酒泉。", "觴詠每忘秋漏永，平安晏有夕烽傳。", "痼腸頓已蜂腰病，妙手親逢鶴背仙。", "歸捋霜鬚詫兒子，爲翁試校故新年。"]'),
('e8c606a4-15a8-4098-87f2-1056f3a25735','再次韻  其三','陳造','宋','宋诗','song-poetry','','[]','橫前整整萬全兵，自笑空弮借背城。',64,'全唐诗/poet.song.151000.json','["橫前整整萬全兵，自笑空弮借背城。", "更遣齊竽混東郭，坐令鵠卵化南榮。", "黄陳得法仍宗派，甫白論情自弟兄。", "顧我無能鄒賈役，放公筆力擅西京。"]'),
('67540778-0b45-4790-b5f7-5693377e91d4','再次韻  其四','陳造','宋','宋诗','song-poetry','','[]','因詩衰病顧徒然，鑿井今猶未及泉。',64,'全唐诗/poet.song.151000.json','["因詩衰病顧徒然，鑿井今猶未及泉。", "藥幻霜鬚端有待，囊緘玉唾愧無傳。", "冥心擬學無言子，授訣今猶不老仙。", "探妙衛生俄兩得，信知穮蔉解逢年。"]'),
('5c5f98ea-7147-4046-9ed6-f92737557740','再次韻小雪餘言別  其一','陳造','宋','宋诗','song-poetry','','[]','舞霙飛霰閙中庭，已辦持盃聽渭城。',64,'全唐诗/poet.song.151000.json','["舞霙飛霰閙中庭，已辦持盃聽渭城。", "漢水襄山驟漂忽，早梅晚菊自枯榮。", "雪神作意凌風伯，客子歸途待日兄。", "蹀躞霜蹄從踣鐵，穿林䠞石賦于京。"]'),
('de3742e5-28b2-4171-8088-88de5c4711ac','再次韻小雪餘言別  其二','陳造','宋','宋诗','song-poetry','','[]','語別詩翁玉麈邊，已催歌舞壓香泉。',64,'全唐诗/poet.song.151000.json','["語別詩翁玉麈邊，已催歌舞壓香泉。", "日陪色笑庸何取，橐攟篇章敢浪傳。", "還舍賸書銀筆字，今朝猶是玉壺仙。", "後山幸自坡公客，誰遣離懷愴暮年。"]'),
('3819a520-dce8-4af2-a859-f006f78f75b5','送詩陳惠伯','陳造','宋','宋诗','song-poetry','','[]','危樓深室桂爲堂，題品端宜虎豹章。',64,'全唐诗/poet.song.151000.json','["危樓深室桂爲堂，題品端宜虎豹章。", "歷數諸公皆大手，尚須此老索枯腸。", "馳神幾夜層虛上，血指如今妙斲傍。", "聊復送君供覆瓿，未須傳到鄭公鄉。"]'),
('6980ece7-215c-4f29-a01c-81dc2aba7f77','襄陽賦秋日江梅菊花','陳造','宋','宋诗','song-poetry','','[]','秋香冬艷各時宜，叵怪花神令出奇。',64,'全唐诗/poet.song.151000.json','["秋香冬艷各時宜，叵怪花神令出奇。", "金菊正含霜曉秀，江梅不待雪寒期。", "帽欹同伴龍山醉，詩到終嫌驛使遲。", "陶杜當時儻經目，定并東閤賦東籬。"]'),
('9a0304f0-b5ef-4854-ad53-774847b03d69','次韻程帥二首  其一','陳造','宋','宋诗','song-poetry','','[]','平時渭北與江東，文會賓筵幸許同。',64,'全唐诗/poet.song.151000.json','["平時渭北與江東，文會賓筵幸許同。", "政使遲遲嗟去魯，未應咄咄遽書空。", "抄詩奚翅無瑕璧，會意俄乘在下風。", "更喜朝來賓鴈足，陽春封寄客塗中。"]'),
('b9e4cfe2-fbbf-4374-a47a-17f0cc1d69bd','次韻程帥二首  其二','陳造','宋','宋诗','song-poetry','','[]','從昔文章蓋代翁，言間有物自無同。',64,'全唐诗/poet.song.151000.json','["從昔文章蓋代翁，言間有物自無同。", "娟妍徒玩花含露，灑落還驚月印空。", "底許賤工慙擢矢，信知妙斲有成風。", "古今一印元呈露，要在神融領會中。"]'),
('c6272315-f52b-4987-a0de-e0896b4ab229','次韻言懷','陳造','宋','宋诗','song-poetry','','[]','房陵回首望淮東，物土人情未易同。',64,'全唐诗/poet.song.151000.json','["房陵回首望淮東，物土人情未易同。", "比屋蜂懸人带癭，亂山㦸立勢凌空。", "汙鯫共饜川人食，簡樸仍存太古風。", "破我殘年七百日，盡拋詩卷酒盃中。"]'),
('1db88d59-7d93-4ce3-b56b-1b69b6f7b936','次韻記別程帥穀城旅夢','陳造','宋','宋诗','song-poetry','','[]','金翹摇曳玉丁東，賓主依然醉笑同。',64,'全唐诗/poet.song.151000.json','["金翹摇曳玉丁東，賓主依然醉笑同。", "舊事忽隨殘漏斷，新愁不逐曉雲空。", "挑燈旋拂穿帷雪，攬轡還禁逆帽風。", "回首夢魂飛到處，壺公窟宅五雲中。"]'),
('018d37ec-5ddb-4cbd-9652-9584a80d1c63','梁教病起','陳造','宋','宋诗','song-poetry','','[]','側聽長須得好音，笑譚已復替呻吟。',64,'全唐诗/poet.song.151000.json','["側聽長須得好音，笑譚已復替呻吟。", "逃知二豎今無地，仇想三彭亦就禽。", "定免带圍憂沈約，可須檄手待陳琳。", "尚須十日安岑寂，酒聖詩愁恐未禁。"]'),
('6dd4227d-aa84-4851-8c5e-4682209289d4','上外朝山','陳造','宋','宋诗','song-poetry','','[]','度隴凌坡冒百艱，今朝又上外朝山。',64,'全唐诗/poet.song.151000.json','["度隴凌坡冒百艱，今朝又上外朝山。", "當車狠石通人過，交道飛蘿要手攀。", "猿坐泬寥猶嘯詫，鴈驚巉絕故飛還。", "臨風却快塵埃眼，全楚山川指顧間。"]'),
('daee8cdb-1b39-4d80-aa10-005e93c2f91b','過八疊山','陳造','宋','宋诗','song-poetry','','[]','路入于平舒倦眼，襄陽佳處亦班班。',64,'全唐诗/poet.song.151000.json','["路入于平舒倦眼，襄陽佳處亦班班。", "燒香峴好思三峴，八疊山高似萬山。", "喜此經行無雨阻，向來遊覽坐天慳。", "山靈定笑貴野鶩，默遣歸求邦域間。"]'),
('f064d393-6f2a-4561-b0e0-f70c9b571602','馬息山','陳造','宋','宋诗','song-poetry','','[]','猿蹊鳥道且攀隮，暝靄頑蒼只尺迷。',64,'全唐诗/poet.song.151000.json','["猿蹊鳥道且攀隮，暝靄頑蒼只尺迷。", "狠石忽開防地裂，屯雲不散訝天低。", "眼高欲了三千界，夢斷猶驚七百梯。", "回望故山真可指，杜鵑腸斷爲誰啼。"]'),
('8e0fe8f7-5eed-454b-bf1b-a610a284396a','寄鄉中親友二首  其一','陳造','宋','宋诗','song-poetry','','[]','棋酒遊從嘆離羣，酒床吟筆漫飛塵。',64,'全唐诗/poet.song.151000.json','["棋酒遊從嘆離羣，酒床吟筆漫飛塵。", "潮乎可奈才力老，甫也尚爲南北人。", "安信不隨秋鴈到，流年倏復野梅新。", "南崗北阜憑高地，引首吳天幾愴神。"]'),
('ab90b510-b14b-4a70-810f-be5cc4ae8bbd','寄鄉中親友二首  其二','陳造','宋','宋诗','song-poetry','','[]','坐衙隨分吏分行，退食還先藥探囊。',64,'全唐诗/poet.song.151000.json','["坐衙隨分吏分行，退食還先藥探囊。", "已爲河魚廢詩酒，彊教籠鳥聽宮商。", "老猶苟祿寧良計，病悟休心是秘方。", "想見親朋遲歸楫，爲翁補漏斸空荒。"]'),
('3af0ed2a-779c-4351-8db0-88345c91b136','賀程帥因任四首且言久缺詩筒之意  其一','陳造','宋','宋诗','song-poetry','','[]','恩綸蜚下漢江濱，特許襄民借寇恂。',64,'全唐诗/poet.song.151000.json','["恩綸蜚下漢江濱，特許襄民借寇恂。", "千里江山皆動色，列城條教再生春。", "灌瓜夙稔安邊策，茹草寧無待哺民。", "方倚金城親邵父，近君寧惜小逡巡。"]'),
('38442327-54ab-4003-a85d-54c27dca3092','賀程帥因任四首且言久缺詩筒之意  其二','陳造','宋','宋诗','song-poetry','','[]','詩律寧惟似變風，姓名久矣御屏中。',64,'全唐诗/poet.song.151000.json','["詩律寧惟似變風，姓名久矣御屏中。", "逢辰千載合致主，入夢九華仍插空。", "鐵甕倚聽新號令，銅蹄終舞舊兒童。", "煩𣂏叶氣成豐歲，却簉皋夔侍舜瞳。"]'),
('b33125f9-6807-4e18-a4fb-101c1755818b','賀程帥因任四首且言久缺詩筒之意  其三','陳造','宋','宋诗','song-poetry','','[]','肯優襄峴劣南徐，行止平時每裕餘。',64,'全唐诗/poet.song.151000.json','["肯優襄峴劣南徐，行止平時每裕餘。", "荷紫端宜冠鴛鷺，飛黄猶似顧蟾蜍。", "緬懷夜燭賡清唱，况許春郊載後車。", "從此追陪得如願，重分膏馥澤空虛。"]'),
('f3c3bedd-937c-4003-8a02-f4e0b7b9a241','賀程帥因任四首且言久缺詩筒之意  其四','陳造','宋','宋诗','song-poetry','','[]','先生一筆將詩壇，庋匱珠璣底坐慳。',64,'全唐诗/poet.song.151000.json','["先生一筆將詩壇，庋匱珠璣底坐慳。", "平日鷗盟當未憗，于今鴈足每空還。", "傳抄可但聞平水，老瘦從知笑飯山。", "緩带輕裘祇常日，千篇破竹定乘閑。"]'),
('010f38b0-d54b-4304-8b92-59f606f92fba','再次韻答程帥高機宜四首  其一','陳造','宋','宋诗','song-poetry','','[]','自分迂愚著海濱，諸公薦力漫忱恂。',64,'全唐诗/poet.song.151000.json','["自分迂愚著海濱，諸公薦力漫忱恂。", "摧頹晚境空多感，局縮窮山亦再春。", "故里歸耕雖有約，中田敬饁遂無人。", "何由消破愁千斛，甓社春濃莫計巡。"]'),
('091819c7-cc25-42d4-a3be-8cffbc556362','再次韻答程帥高機宜四首  其二','陳造','宋','宋诗','song-poetry','','[]','名德誰今挺古風，人嗟汲直合居中。',64,'全唐诗/poet.song.151000.json','["名德誰今挺古風，人嗟汲直合居中。", "揮毫有物鬼落膽，與世無心雲度空。", "倚聽金鑾拜新渥，又煩竹馬走羣童。", "貝宮風露鼇峯月，行矣輝華映兩瞳。"]'),
('2eb93be6-e3e7-49b0-bae9-3efb7543f2d2','再次韻答程帥高機宜四首  其三','陳造','宋','宋诗','song-poetry','','[]','高郎筆勢未姑徐，千紙珠璣欬唾餘。',64,'全唐诗/poet.song.151000.json','["高郎筆勢未姑徐，千紙珠璣欬唾餘。", "春興漂蕭陵野馬，夜窗清絕冰金蜍。", "諸公交口傳黄絹，蜚詔褒賢定赤車。", "亦使窮山拜嘉惠，衰翁擊節正馮虛。"]'),
('df476221-e0c2-4739-8d7c-257bbaa2cdc8','再次韻答程帥高機宜四首  其四','陳造','宋','宋诗','song-poetry','','[]','倒海翻湖袖手觀，揆子才思坐天慳。',64,'全唐诗/poet.song.151000.json','["倒海翻湖袖手觀，揆子才思坐天慳。", "愁攻心折仍無頼，債壓頭低不辦還。", "坐想賡酬聯白璧，祇令翹企仰高山。", "拙疎却喜便衰病，贏得蕭齋盡日閑。"]'),
('c34fd1a8-d603-407b-9fbb-09e9db500d7a','正仲和帥屬被盜二首  其一','陳造','宋','宋诗','song-poetry','','[]','衣囊緘鐍竟胡爲，祇與偷兒便挈携。',64,'全唐诗/poet.song.151000.json','["衣囊緘鐍竟胡爲，祇與偷兒便挈携。", "髻重得無猜祖珽，璧亡遮莫議張儀。", "館人求屨古未免，有力負山人得知。", "不用經營辦春服，舊紉蘭芷扈玄蘺。"]'),
('6891c7b0-b971-4ee2-8d37-19a768e27836','正仲和帥屬被盜二首  其二','陳造','宋','宋诗','song-poetry','','[]','向來忠信倚垣牆，誨盜如今坐慢藏。',64,'全唐诗/poet.song.151000.json','["向來忠信倚垣牆，誨盜如今坐慢藏。", "望意漫言疑聖智，奇文不合吐光芒。", "玉川空屋遭窺瞰，子敬青氈果在亡。", "頼有平生千牘在，未妨攟載作歸裝。"]'),
('9a0517bc-b878-4d0c-8dd2-7426c151670b','贈高司理','陳造','宋','宋诗','song-poetry','','[]','窮鄉洗眼挹清揚，凜若重登月旦堂。',64,'全唐诗/poet.song.151000.json','["窮鄉洗眼挹清揚，凜若重登月旦堂。", "驥子鳳雛端不苟，吏能儒業况兼長。", "簡孚首解秋荼密，襞積仍熏古錦香。", "我亦床頭一經在，自公正欲共平章。"]'),
('e3983581-4b69-4d1b-95c6-d685205770ea','再用前韻贈高司理共八首  其一','陳造','宋','宋诗','song-poetry','','[]','少年場裏獨鷹揚，他日懸知玉作堂。',64,'全唐诗/poet.song.151000.json','["少年場裏獨鷹揚，他日懸知玉作堂。", "小試問囚窮兩造，徐看載筆擅三長。", "得詩遽眩珠璣爛，玩味還疑齒頰香。", "風月無窮才不盡，坐須喬木擁千章。"]'),
('54f1afda-6f43-4733-8044-eb35f3e4dfb2','再用前韻贈高司理共八首  其二','陳造','宋','宋诗','song-poetry','','[]','帥幕羣才頼激揚，衰遲猶喜後升堂。',64,'全唐诗/poet.song.151000.json','["帥幕羣才頼激揚，衰遲猶喜後升堂。", "雷封局縮聊償債，衮字褒嘉但寸長。", "再試真成不龜藥，九言終佩辟邪香。", "龍門夢斷誰知己，幾誦桑阿賦末章。"]'),
('6b75ff5a-ce1e-4539-9d2a-41515fcc6835','再用前韻贈高司理共八首  其三','陳造','宋','宋诗','song-poetry','','[]','衰宗如此况他揚，碌碌諸雛欠肯堂。',64,'全唐诗/poet.song.151000.json','["衰宗如此况他揚，碌碌諸雛欠肯堂。", "薄宦幽憂殊未醒，故園歸夢可勝長。", "盃盤頓頓家鷄嫩，翁媼嗚嗚社酒香。", "猶記比鄰笑行客，夏畦龍斷爲金章。"]'),
('6be74844-0ec9-47d3-bffc-dd32f8025cce','再用前韻贈高司理共八首  其四','陳造','宋','宋诗','song-poetry','','[]','詩語庸非自播揚，流傳朋舊定哄堂。',64,'全唐诗/poet.song.151000.json','["詩語庸非自播揚，流傳朋舊定哄堂。", "儒書投老空成癖，舞袖平生不解長。", "黄鳥啄殘丹杏顆，清風摇動綠筠香。", "山城寂寞便吾嬾，劣勝精神弊句章。"]'),
('a0829471-4fb2-479e-9ba4-bd28ecbc0917','再用前韻贈高司理共八首  其五','陳造','宋','宋诗','song-poetry','','[]','俗裏毫絲起抑揚，請君時閉讀書堂。',64,'全唐诗/poet.song.151000.json','["俗裏毫絲起抑揚，請君時閉讀書堂。", "渭清肯混涇流濁，鳬短徒憂鶴脛長。", "千載流傳防造次，百年表立要馨香。", "了知此印君堪付，過眼尨凉忽報章。"]'),
('6107ac34-65e6-41d3-9e26-82dea91b8f57','再用前韻贈高司理共八首  其六','陳造','宋','宋诗','song-poetry','','[]','蘇李宗風我舉揚，少陵公按子開堂。',64,'全唐诗/poet.song.151000.json','["蘇李宗風我舉揚，少陵公按子開堂。", "官曹此地文書省，詩社從今日月長。", "山滴曉烟收後翠，蓮漂天女戲時香。", "可孤煮餠分彊韻，正使銅花澁印章。"]'),
('065c1a6c-d6b6-4647-92c6-3421844789bd','再用前韻贈高司理共八首  其七','陳造','宋','宋诗','song-poetry','','[]','腰錢幾夜夢維揚，上雨傍風祇此堂。',64,'全唐诗/poet.song.151000.json','["腰錢幾夜夢維揚，上雨傍風祇此堂。", "人笑鉛刀那用割，自知襪線豈能長。", "課詩壇畔獨飛動，問字人來且碧香。", "徑欲披衣還舊隠，二天寧久溷蘇章。"]'),
('92fd7608-7544-4c77-87bf-17057bec6008','再用前韻贈高司理共八首  其八','陳造','宋','宋诗','song-poetry','','[]','帝旅曾觀武事揚，如君文勢整堂堂。',64,'全唐诗/poet.song.151000.json','["帝旅曾觀武事揚，如君文勢整堂堂。", "了知一筆無前古，坐遣諸生喪所長。", "丹桂高攀霄漢迥，捷書西下姓名香。", "貝宮鼇禁應餘地，看展平生補衮章。"]'),
('3867d43d-636c-4fc6-858a-61a48ce13d4a','病起閒步','陳造','宋','宋诗','song-poetry','','[]','瞑綠園亭小雨晴，病翁雙眼爲誰明。',64,'全唐诗/poet.song.151000.json','["瞑綠園亭小雨晴，病翁雙眼爲誰明。", "柳如張緒不殊昔，竹與子猷相對清。", "門下鳥烏無客到，壁棲蛇蚓又詩成。", "回頭溪友千山阻，更向何人話此情。"]'),
('a6f91a75-ffe0-4b02-97e2-a5e0ed4f6dee','寄師文二首  其一','陳造','宋','宋诗','song-poetry','','[]','世塗豈必盡籠囚，自是迂疎拙應酬。',64,'全唐诗/poet.song.151000.json','["世塗豈必盡籠囚，自是迂疎拙應酬。", "簿領嬰心寧素志，夢魂何日不滄洲。", "揆吾溫飽兒堪託，平昔行藏婦與謀。", "已判來年拂衣去，寄言亟辦釣魚舟。"]'),
('aa83e222-cad7-45c9-b083-0ef1795cc167','寄師文二首  其二','陳造','宋','宋诗','song-poetry','','[]','萍梗漂浮已老翁，歸來差樂未終窮。',64,'全唐诗/poet.song.151000.json','["萍梗漂浮已老翁，歸來差樂未終窮。", "稻田取足隨豐歉，花圃逢春自白紅。", "禪老版頭容客飽，臧孫鼎足祇牆東。", "更聞名酒新傳法，詩外棋邊莫放空。"]'),
('dc309421-0a1c-4e60-ab5b-0cd5952717a6','次韻什邡馬主簿二首  其一','陳造','宋','宋诗','song-poetry','','[]','陶謝前蹤一筆追，掀天聲價舊風馳。',64,'全唐诗/poet.song.151000.json','["陶謝前蹤一筆追，掀天聲價舊風馳。", "瑞時不數九文羽，換骨疑餐三秀芝。", "蜚電燭巖方左席，明珠照乘忽清漪。", "裹創瞢欲凌堅陣，可諱含毫不自持。"]'),
('213b5c51-1115-4e36-bb42-26ffac022d92','次韻什邡馬主簿二首  其二','陳造','宋','宋诗','song-poetry','','[]','紛紛過眼甚螽斯，膽掉驚逢驥騄馳。',64,'全唐诗/poet.song.151000.json','["紛紛過眼甚螽斯，膽掉驚逢驥騄馳。", "獻替付君溫省樹，朝晡還我故山芝。", "荆江蜀棧聊舒嘯，卷耳思齊正採詩。", "回首定傳天上信，囊荷知傍紫皇持。"]'),
('5c1f8721-4c40-46ce-9216-9f583ebf6020','再次韻馬主簿二首  其一','陳造','宋','宋诗','song-poetry','','[]','冥搜成癖漫勤斯，緬想騷人正坐馳。',64,'全唐诗/poet.song.151000.json','["冥搜成癖漫勤斯，緬想騷人正坐馳。", "點化今逢萬金劑，神奇蒸出九華芝。", "三吳才雋應焚硯，萬里風烟盡入詩。", "盍與元劉論伯仲，未容郊島更矜持。"]'),
('cbb9a50e-63ed-4909-997e-59e0faad0704','再次韻馬主簿二首  其二','陳造','宋','宋诗','song-poetry','','[]','左顧衰翁底取斯，轉頭歸馬又西馳。',64,'全唐诗/poet.song.151000.json','["左顧衰翁底取斯，轉頭歸馬又西馳。", "賸催阿買抄新稿，大勝齋房紀瑞芝。", "樂歲人家皆有酒，高秋天氣總宜詩。", "霜花露菊留迎客，預戒西成省控持。"]'),
('82c2611d-cd84-4c5e-82c6-63bc0638a300','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','飽食頻頻祇鸒斯，可堪迅景隙駒馳。',64,'全唐诗/poet.song.151000.json','["飽食頻頻祇鸒斯，可堪迅景隙駒馳。", "不逢猶是桐爲弩，當價胡寧菌作芝。", "天籟寂時三弄笛，楚山窮處四愁詩。", "將壇可復宜衰病，此柄須君爲主持。"]'),
('00baa8d3-d418-486c-b011-c00603ecaf90','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','歷塊飛黄可得追，加鞭十駕浪驅馳。',64,'全唐诗/poet.song.151000.json','["歷塊飛黄可得追，加鞭十駕浪驅馳。", "不應猗頓懷周朴，敢向天仙話土芝。", "晚傍涪翁觀落筆，了知高叟固爲詩。", "謬爲恭敬吾何取，政恐龍泉有倒持。"]'),
('3e9fb272-cc4d-43da-8b89-c7e639adcc7c','偕章宰勸農房山  其一','陳造','宋','宋诗','song-poetry','','[]','登臨一擬豁心胸，著我松窗竹屋中。',64,'全唐诗/poet.song.151000.json','["登臨一擬豁心胸，著我松窗竹屋中。", "宛是官曹縛雕虎，不容塵眼到飛鴻。", "綿延天際應平碧，孤負林梢抹嫩紅。", "俛仰去年舒嘯地，解衣聊復近熏籠。"]'),
('1c6bfd7a-dc9e-4f03-8e6f-d6ae2455b6a2','偕章宰勸農房山  其二','陳造','宋','宋诗','song-poetry','','[]','簷外雲深雨合圍，此行不嘆始謀非。',64,'全唐诗/poet.song.151000.json','["簷外雲深雨合圍，此行不嘆始謀非。", "對君便是蘇端過，把酒曾無御叔譏。", "紅濕烟郊思散策，寒欺病骨旋添衣。", "了知未盡山陰興，共作衝泥傍險歸。"]'),
('97df8214-d299-4dea-bdaf-0f995c5138d9','簡章宰二首  其一','陳造','宋','宋诗','song-poetry','','[]','蕙蘭洲北觀山頭，未暇尋盟訪舊遊。',64,'全唐诗/poet.song.151000.json','["蕙蘭洲北觀山頭，未暇尋盟訪舊遊。", "自笑春來多病過，靜無人處但詩愁。", "遥知聯轡窮幽勝，更想簪花賸獻酬。", "報答東風應得句，奚奴亟肯寄儂不。"]'),
('77c57453-3322-425a-a220-848b97e010ba','簡章宰二首  其二','陳造','宋','宋诗','song-poetry','','[]','縹緲雲藏羽客廬，不妨尋勝小踟躕。',64,'全唐诗/poet.song.151000.json','["縹緲雲藏羽客廬，不妨尋勝小踟躕。", "鴟夷載酒鶑花處，古錦囊詩簿領餘。", "百和風輕吹欲醉，萬山嵐凝對憑虛。", "譚間定笑衰慵客，竹屋高舂尚枕書。"]'),
('267628d6-b12f-4475-b137-d0d214075733','上巳溪上燕二首  其一','陳造','宋','宋诗','song-poetry','','[]','後溪分占羽觴浮，雷隠歡聲半棹謳。',64,'全唐诗/poet.song.151000.json','["後溪分占羽觴浮，雷隠歡聲半棹謳。", "况我閑官似犀首，爲渠領客作鰲頭。", "玻瓈影裏粧光膩，桃李香中步障留。", "病骨得晴堪近酒，與君同拜醉鄉侯。"]'),
('cb25071d-b336-4f5c-9629-17d41e281d53','上巳溪上燕二首  其二','陳造','宋','宋诗','song-poetry','','[]','杜若洲邊卓旆旌，佳晨一醉萬金輕。',64,'全唐诗/poet.song.151000.json','["杜若洲邊卓旆旌，佳晨一醉萬金輕。", "春光僅有一分在，天氣可能三日晴。", "解道蘭亭亦陳迹，肯吟楚些愴幽情。", "人生到處皆兒戲，笑看爭標鬭兩鯨。"]'),
('1b26aa6b-d0c5-40ca-9740-a085a28d276a','試柘枝溪上','陳造','宋','宋诗','song-poetry','','[]','蕙風花氣雨餘天，報答融和玉作船。',64,'全唐诗/poet.song.151000.json','["蕙風花氣雨餘天，報答融和玉作船。", "壯歲自能鸜鵒舞，老狂猶有柘枝顛。", "羣鴻翩度昆昭錦，雙鳳翔從玉井蓮。", "起我少時豪俠興，未甘詩客號臞仙。"]'),
('81410718-9b1e-4687-808a-c521ad04e609','次韻答許推章宰二首  其一','陳造','宋','宋诗','song-poetry','','[]','矞雲非霧靄飛浮，滿聽遊人載路謳。',64,'全唐诗/poet.song.151000.json','["矞雲非霧靄飛浮，滿聽遊人載路謳。", "痛飲君能判濡首，新翻我亦辦纏頭。", "羽觴瀲灧風微度，翠蓋蹁躚晚尚留。", "且倩銀鈎寫陳迹，未須詩律壓劉侯。"]'),
('aff4287b-9abe-4d2e-944c-e42e65c03bb1','次韻答許推章宰二首  其二','陳造','宋','宋诗','song-poetry','','[]','北來青翼導霓旌，翩若凌雲鶴馭輕。',64,'全唐诗/poet.song.151000.json','["北來青翼導霓旌，翩若凌雲鶴馭輕。", "烟柳困眠纔寤曉，露花酣醉正熹晴。", "獻之能賦雖辭罰，楚客同醒恐不情。", "豪興尚堪追少雋，漏巵灌酒鱠長鯨。"]'),
('3f9dd83b-b1e4-4d54-8081-555f3bdb4d24','再次韻答節推二首  其一','陳造','宋','宋诗','song-poetry','','[]','透幕穿簾香霧浮，行雲低影傍清謳。',64,'全唐诗/poet.song.151000.json','["透幕穿簾香霧浮，行雲低影傍清謳。", "遊人是處歌鼓腹，佳客伴翁吟掉頭。", "令節可孤三日醉，歸期猶有一春留。", "詩壇酒會容先歃，莫問將軍老不侯。"]'),
('f6237862-bbfb-490c-95b9-3ec758fd94c8','再次韻答節推二首  其二','陳造','宋','宋诗','song-poetry','','[]','虧成久不撓心旌，老閲人間百事輕。',64,'全唐诗/poet.song.151000.json','["虧成久不撓心旌，老閲人間百事輕。", "却笑平生甘淡薄，每緣行樂問陰晴。", "羽觴餳粥同春事，卧醉行歌見俗情。", "擊鉢更遭强敵困，可能赤手控奔鯨。"]'),
('dac917b2-cbfe-4a92-b9da-8ed717b78233','再次韻答許節推二首  其一','陳造','宋','宋诗','song-poetry','','[]','起依筇竹似桴浮，改就新詞却自謳。',64,'全唐诗/poet.song.151000.json','["起依筇竹似桴浮，改就新詞却自謳。", "囊錦斬關聊袖手，酒兵推戶且扶頭。", "東風已拆紅躑躅，碧樹更啼黄栗留。", "醒醉醉醒殊未沬，不應通守羨通侯。"]'),
('f52921c2-e90a-4cad-acb3-042d0c75f71f','再次韻答許節推二首  其二','陳造','宋','宋诗','song-poetry','','[]','步屧巉巖屏騎旌，松風茵露爲誰輕。',64,'全唐诗/poet.song.151000.json','["步屧巉巖屏騎旌，松風茵露爲誰輕。", "已無桃李擅春事，忽有鳥烏啼晚晴。", "羽客不妨同水厄，宿酲端解敗詩情。", "開緘又拜同寮賜，錦段中含掉尾鯨。"]'),
('e4c6e3cc-b9f5-4a26-a8bf-f0d67b51f6ea','再次韻四首  其一','陳造','宋','宋诗','song-poetry','','[]','新釀開缸淥蟻浮，舊辭仍缺唾壺謳。',64,'全唐诗/poet.song.151000.json','["新釀開缸淥蟻浮，舊辭仍缺唾壺謳。", "宦塗要處難插手，詩社叢中常引頭。", "倒載肯陪山簡醉，反關莫厭孟公留。", "秋田粗可供佳客，不比封君亦素侯。"]'),
('d36a97a7-55e5-470f-a399-6e955e419b3c','再次韻四首  其二','陳造','宋','宋诗','song-poetry','','[]','翰墨場中對抗旌，黄陳一筆萬鈞輕。',64,'全唐诗/poet.song.151000.json','["翰墨場中對抗旌，黄陳一筆萬鈞輕。", "武安屋瓦秋鼙震，湘水波光夜月晴。", "沮洳求魚真自笑，渚涯向若倍馳情。", "吾生恨落任公後，不見投綸掣海鯨。"]'),
('2d422b0b-a941-4283-860c-5aa550b98302','再次韻四首  其三','陳造','宋','宋诗','song-poetry','','[]','尸祝代庖良過矣，即今坐嘯免謿謳。',64,'全唐诗/poet.song.151000.json','["尸祝代庖良過矣，即今坐嘯免謿謳。", "陶朱計食魚萬尾，景畧有兒牛十頭。", "甫里過從勞夢寐，輞川歸去忌遲留。", "大弨一弛吾通袖，冷看逢蒙中射侯。"]'),
('ed4192a9-f83f-4b9b-810e-d498865b5c67','再次韻四首  其四','陳造','宋','宋诗','song-poetry','','[]','韻語聯翩到浚旌，楚珩非重夜光輕。',64,'全唐诗/poet.song.151000.json','["韻語聯翩到浚旌，楚珩非重夜光輕。", "吟成品物回春態，誦處東風放曉晴。", "抖擻錦囊娛我老，滌除愁斛見君情。", "固應詩膽驁無本，刺手霜牙摩怒鯨。"]'),
('44a86174-d5b4-47d3-a3e7-fb83b27eab51','梁教授次柘枝詩韻再和','陳造','宋','宋诗','song-poetry','','[]','洞裏鶑花別有天，爲渠蘸甲上金船。',64,'全唐诗/poet.song.151000.json','["洞裏鶑花別有天，爲渠蘸甲上金船。", "舞姝貪看塵生襪，飲興渾忘雪滿顛。", "弄影競垂三昧手，倚風疑裊五枝蓮。", "廣寒再閲霓裳罷，笙鶴飛來未是仙。"]'),
('e83e9a40-bf92-488c-b476-5966d2f2c78b','書懷','陳造','宋','宋诗','song-poetry','','[]','人間窮達命污隆，作意功名欲捕風。',64,'全唐诗/poet.song.151000.json','["人間窮達命污隆，作意功名欲捕風。", "但見劉班誤車子，何曾鄧禹笑王融。", "官曹得飽餘何事，書課乘閑亦雋功。", "少待蓴鱸付張翰，一溪風月放船篷。"]'),
('82b963ab-4774-456d-a2af-cab05a163d82','次韻高機宜送別  其一','陳造','宋','宋诗','song-poetry','','[]','棋枰詩課憶同堂，轉首暄寒幾蔀章。',64,'全唐诗/poet.song.151000.json','["棋枰詩課憶同堂，轉首暄寒幾蔀章。", "每嘆羈離念陳迹，更因衰病感流光。", "亟催江鷁休停棹，已信溪禽不亂行。", "魚澳芋區真好在，連宵歸夢爲誰長。"]'),
('6b867fb4-94c0-4823-87ba-caa6058df75b','次韻高機宜送別  其二','陳造','宋','宋诗','song-poetry','','[]','士價如君定玉堂，陳陳腹笥漢文章。',64,'全唐诗/poet.song.151000.json','["士價如君定玉堂，陳陳腹笥漢文章。", "即今綵筆春爭媚，它日青藜夜有光。", "詩力不勞凌汝輩，才名况自溢班行。", "清篇見屬吾何取，愧闖辭壇闕寸長。"]'),
('b85a3352-83e0-4d7d-8423-454dfa6c5d9e','再次韻謝惠詩  其一','陳造','宋','宋诗','song-poetry','','[]','百鎰籯金數仞堂，何如盥手頌佳章。',64,'全唐诗/poet.song.151000.json','["百鎰籯金數仞堂，何如盥手頌佳章。", "奪胎信自非凡劑，獻佛當知便放光。", "斤運向來車合轍，影斜還惜鴈分行。", "衰年離緒誰禁得，鏡裏新絲莫計長。"]'),
('35b8be75-d0e1-48a8-859d-335190dafc85','再次韻謝惠詩  其二','陳造','宋','宋诗','song-poetry','','[]','小家茨竹即爲堂，暇訪深林索豫章。',64,'全唐诗/poet.song.151000.json','["小家茨竹即爲堂，暇訪深林索豫章。", "平日牀頭但周易，看人筆落便靈光。", "庳隆賦質嗟多樣，良楛論材要當行。", "莫向黔婁問奇貨，長沙舞袖可能長。"]'),
('b8c1bc5d-c9d8-455d-a2cf-183b1c5ae75c','贈黄國器二首  其一','陳造','宋','宋诗','song-poetry','','[]','交情凜凜久彌堅，遊舊何人似子賢。',64,'全唐诗/poet.song.151000.json','["交情凜凜久彌堅，遊舊何人似子賢。", "別去漂零各天末，喜今譚笑復樽前。", "德人政用寬幽獨，歸路胡宜更後先。", "彈壓山川須妙語，不妨排日爲君編。"]'),
('36e4da5d-dfa7-4ebf-8dd4-6a9aab2646ca','贈黄國器二首  其二','陳造','宋','宋诗','song-poetry','','[]','簿書叢裏久囚拘，鷗鷺羣邊忽自如。',64,'全唐诗/poet.song.151000.json','["簿書叢裏久囚拘，鷗鷺羣邊忽自如。", "白傅已甘多病過，安仁况復悼亡餘。", "歸田且辦充腸米，遮眼非無插架書。", "如子功名方迫逐，未應偕我問樵漁。"]'),
('631f02d0-0a97-4e8d-94f5-c491c49b96c8','過伏龍祠','陳造','宋','宋诗','song-poetry','','[]','蜀棧荆江志未酬，兩京直擬笑譚收。',64,'全唐诗/poet.song.151000.json','["蜀棧荆江志未酬，兩京直擬笑譚收。", "僅容孱后存酅祀，誰遣東吳解魏仇。", "制敵豈應無法正，爲謀不合有譙周。", "伏龍祠上長烟靄，憤氣堂堂恐未休。"]'),
('7bba24d2-8e57-4398-820d-630831e2d810','武昌','陳造','宋','宋诗','song-poetry','','[]','客子脩程未息肩，江山佳處小留連。',64,'全唐诗/poet.song.151000.json','["客子脩程未息肩，江山佳處小留連。", "醉臨庾亮樓前月，夢闖回翁洞裏天。", "形勢盤縈蹲虎鳳，輪蹄隠軫度絲絃。", "登高欲賦還東望，楚些無因喚謫仙。"]'),
('76e3d58e-74ff-4418-87d8-9879374713af','歸歟老秋','陳造','宋','宋诗','song-poetry','','[]','已辦求田問舍謀，登臨那復更悲秋。',64,'全唐诗/poet.song.151000.json','["已辦求田問舍謀，登臨那復更悲秋。", "蟹肥與客爭先把，稻熟催兒徹晚收。", "霜後峯巒添峭措，波間鷗鷺劇風流。", "寰中勝處天應惜，付與癡兒祇暗投。"]'),
('3023f485-8a6f-4179-ae83-f1b5de3fc94c','宿何人家','陳造','宋','宋诗','song-poetry','','[]','步尋松篠款谽谺，忽到孤山處士家。',64,'全唐诗/poet.song.151000.json','["步尋松篠款谽谺，忽到孤山處士家。", "十頃蒼鱗漾牆角，一鉤寒玉插簷牙。", "杯行不乏紅絲鱠，飯了仍供白露芽。", "把臂傾舒吾已怯，又分離緒上歸槎。"]'),
('0f2a10ca-56d2-445e-b49d-904b0c6666cf','次韻張司戶  其一','陳造','宋','宋诗','song-poetry','','[]','橘頌精靈雜遠遊，如君信是古詩流。',64,'全唐诗/poet.song.151000.json','["橘頌精靈雜遠遊，如君信是古詩流。", "吳門肯問鱸魚鱠，東武當營燕子樓。", "有底揮毫挾風雨，定知貯腹盡陽秋。", "即看珥筆鴛鸞右，莫漫江城詫狎鷗。"]'),
('1b6f0bf3-506f-4dc1-9934-42506ec8f007','次韻張司戶  其二','陳造','宋','宋诗','song-poetry','','[]','他日猶能說宦遊，老禁多病厭漂流。',64,'全唐诗/poet.song.151000.json','["他日猶能說宦遊，老禁多病厭漂流。", "近臨西蜀窺鮫室，舊傍東溟看蜃樓。", "歸計已嗟霜蟹晚，吟聲閑伴候蟲秋。", "塵冠徑欲留神武，萬頃蒼茫漾白鷗。"]'),
('322e03d8-7307-409b-a270-87fc687ecd62','凌晨復有惠急筆次韻  其一','陳造','宋','宋诗','song-poetry','','[]','小駐江干接雋遊，渭清涇濁可同流。',64,'全唐诗/poet.song.151000.json','["小駐江干接雋遊，渭清涇濁可同流。", "假真笑我陳驚坐，造妙推君趙倚樓。", "姓字已高時輩上，功名尤忌鬢毛秋。", "等閑莫學金華伯，碧水如天擬夢鷗。"]'),
('3190c89e-8024-471f-847a-7eb66965dbbb','凌晨復有惠急筆次韻  其二','陳造','宋','宋诗','song-poetry','','[]','仕塗决矣息交遊，姑向林泉訪勝流。',64,'全唐诗/poet.song.151000.json','["仕塗决矣息交遊，姑向林泉訪勝流。", "短褐直甘乘下澤，異鄉終勝賦登樓。", "驚心夢境檀槐戰，屈指鄉園秫稻秋。", "雉翳龜燋緣有用，未聞金彈中沙鷗。"]'),
('0c8493cc-3551-4bb1-990c-f90f2a919246','贈四子二首  其一','陳造','宋','宋诗','song-poetry','','[]','峩峩冰港僅通舟，策策霜風透重裘。',64,'全唐诗/poet.song.151000.json','["峩峩冰港僅通舟，策策霜風透重裘。", "良爲予來真好事，小留君住得銷憂。", "可無譚笑傳觴處，賸有煙雲灑筆頭。", "保社相娛倚公等，暮年干祿判悠悠。"]'),
('32073129-6c2d-49a4-a86b-e1bb13a4523d','贈四子二首  其二','陳造','宋','宋诗','song-poetry','','[]','交遊過眼亦班班，四子聲猷豈易攀。',64,'全唐诗/poet.song.151000.json','["交遊過眼亦班班，四子聲猷豈易攀。", "百里來羞長翁贐，片言仍解相公顔。", "事乖雅意疇忘嘆，我已南驅子北還。", "繼此開樽講德處，定知矯首向雲山。"]'),
('11cb4d06-816a-48ac-8118-2e1a9a0cf540','次韻雪詩','陳造','宋','宋诗','song-poetry','','[]','欺梅瀉竹透承塵，熒侮東風似妬春。',64,'全唐诗/poet.song.151000.json','["欺梅瀉竹透承塵，熒侮東風似妬春。", "匝地閭閻皆種玉，插空樓觀忽鎔銀。", "窗明尚憶躭書夜，身曲誰憐旅食人。", "親見飛仙下瑶檢，諸公居處與天鄰。"]'),
('db87cd24-f658-4046-b1cd-b3f5eb4d3364','再口占次韻','陳造','宋','宋诗','song-poetry','','[]','君家朱閤隔囂塵，可欠賓筵蘭蕙春。',64,'全唐诗/poet.song.151000.json','["君家朱閤隔囂塵，可欠賓筵蘭蕙春。", "橫草定銘鞮汗石，穿楊新賜上方銀。", "幾時釃酒招嘉客，不假傾囊得麗人。", "莫坐風慳仍雨澀，祇將詩筆詫無鄰。"]'),
('b15b5fba-cd8e-4985-9fe6-312490223015','次曾左司韻贈俞德瑞','陳造','宋','宋诗','song-poetry','','[]','班荆同冒軟紅塵，一種東風兩樣春。',64,'全唐诗/poet.song.151000.json','["班荆同冒軟紅塵，一種東風兩樣春。", "雋飲放君顔似赭，幽居憐我鬢如銀。", "簡編自誑供良夜，要襋渠今有好人。", "把酒若歌歸緩緩，不妨折簡喚東鄰。"]'),
('246282d4-b867-4b3d-8fe4-d496926846d8','次韻答德瑞','陳造','宋','宋诗','song-poetry','','[]','詩客胸襟舊絕塵，惠然分我一緘春。',64,'全唐诗/poet.song.151000.json','["詩客胸襟舊絕塵，惠然分我一緘春。", "裁成蜀國添花錦，貴重丹砂伏火銀。", "暮雨朝雲知有夢，瓊枝璧月可無人。", "要須共醉彭宣酒，莫諉忘情宋玉鄰。"]'),
('af6e7587-f78e-4270-bbf3-be1d4f0068f7','再次韻贈俞德瑞  其一','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','珠軒綉轂輾香塵，回首西湖羅綺春。',64,'全唐诗/poet.song.151000.json','["珠軒綉轂輾香塵，回首西湖羅綺春。", "便合行歌訪花柳，可辭買笑費金銀。", "清吟自屬當千客，勸醉那無第一人。", "肯學孤山舊居士，平生詩酒祇僧鄰。"]'),
('879632df-5cd5-4d71-a2fb-eb46706839d6','再次韻贈俞德瑞  其二','陳造','宋','宋诗','song-poetry','','[]','孰知妙語析微塵，細寫都城浩蕩春。',64,'全唐诗/poet.song.151000.json','["孰知妙語析微塵，細寫都城浩蕩春。", "向我能分趙城璧，爲君還缺唾壺銀。", "平時宦路甘違俗，投老詩聲更後人。", "枘鑿推敲有砭劑，不勞千萬得芳鄰。"]'),
('42336100-5b55-4cfe-a1dd-5051822c85f6','再次韻贈俞德瑞  其三','陳造','宋','宋诗','song-poetry','','[]','襟袂猶緇客路塵，攀追强踏帝城春。',64,'全唐诗/poet.song.151000.json','["襟袂猶緇客路塵，攀追强踏帝城春。", "落身窮僻才全璧，敵己遊從半佩銀。", "枉却近臣開薦口，頗嘗內地著癡人。", "君看捉筆青燈夜，得句歡呼聒四鄰。"]'),
('fd8f4d84-26c3-40af-a662-0202d5520250','送張文昌帥豫章二首  其一','陳造','宋','宋诗','song-poetry','','[]','倚俟新年轉化鈞，晝方三接徑抽身。',64,'全唐诗/poet.song.151000.json','["倚俟新年轉化鈞，晝方三接徑抽身。", "平時但有凝香夢，盛世那無勇退人。", "滕閤賓筵時可醉，金華詩令看重新。", "盍思遠邇商霖望，不但淮鄉有涸鱗。"]'),
('a9dc8e60-862e-4c45-937b-265258e2313d','送張文昌帥豫章二首  其二','陳造','宋','宋诗','song-poetry','','[]','談間賓客重宣州，到後兒童敬細侯。',64,'全唐诗/poet.song.151000.json','["談間賓客重宣州，到後兒童敬細侯。", "薤本擊彊休領擥，棠陰問俗見風流。", "湖連市屋疑豐樂，江遶城闉似石頭。", "鷗鷺要盟公莫信，江湖祇許半年留。"]'),
('bd0ac059-fbd5-4094-91f2-c6a91f45c8fa','行都夜歸','陳造','宋','宋诗','song-poetry','','[]','燈火通衢苦未稀，望仙橋外獨歸時。',64,'全唐诗/poet.song.151000.json','["燈火通衢苦未稀，望仙橋外獨歸時。", "風梳御柳娟娟浄，月傍觚稜故故遲。", "隠地輪蹄忘夜旦，幾家樓閤不金絲。", "時平睿澤天無外，帝力何曾爾輩知。"]'),
('8515bb76-795e-443a-b49c-1adb3ed68eb3','次韻同年諸公環碧敘同年會  其一','陳造','宋','宋诗','song-poetry','','[]','天瓢挹注拱仙官，更閲詩仙錦繡端。',64,'全唐诗/poet.song.151000.json','["天瓢挹注拱仙官，更閲詩仙錦繡端。", "離合不忘車笠誓，留傳當並畫圖看。", "玄譚想有蛟龍聽，得醉仍均客主歡。", "俛仰謫仙三百載，從知樂事繼今難。"]'),
('0e742fa4-da9f-44fb-94d9-9783eed61c4a','次韻同年諸公環碧敘同年會  其二','陳造','宋','宋诗','song-poetry','','[]','春意溫然侍上官，松醪更勸語更端。',64,'全唐诗/poet.song.151000.json','["春意溫然侍上官，松醪更勸語更端。", "行厨賸遣黄頭載，下客何曾白眼看。", "傑在漢庭方眷注，功將周室更祗歡。", "孰知末至慈恩舊，老境猶歌行路難。"]'),
('bcc0906c-1f70-4153-9100-ee18be7c4b15','次韻同年諸公環碧敘同年會  其三','陳造','宋','宋诗','song-poetry','','[]','聚首論年不計官，寥寥故事復開端。',64,'全唐诗/poet.song.151000.json','["聚首論年不計官，寥寥故事復開端。", "俯容我輩輸心語，更遣時流洗眼看。", "庾亮賓筵無盡興，昌黎文飲有餘歡。", "舍人妙句還新樣，白雪賡酬政自難。"]'),
('eef5a809-3c0f-476b-87f7-6ecadf59f416','約徐南卿出遊','陳造','宋','宋诗','song-poetry','','[]','古寺周圍錦樹窠，清湖演漾麴塵波。',64,'全唐诗/poet.song.151000.json','["古寺周圍錦樹窠，清湖演漾麴塵波。", "偷閑已計三餐反，敗興其如一雨何。", "政復小孤鷗鷺約，未妨來校魯魚訛。", "春光尚有三之一，徐辦蘇隄一再過。"]'),
('49076f81-338a-4387-8789-005ccf7184cd','西林訪銛師','陳造','宋','宋诗','song-poetry','','[]','天將宿雨凈春空，却著湖山鼓吹中。',64,'全唐诗/poet.song.151000.json','["天將宿雨凈春空，却著湖山鼓吹中。", "載酒言辭藉花伴，運斤來看斲泥工。", "前身師定參寥子，拙宦吾今張長公。", "俛首人間皆長物，未妨分饗北窗風。"]'),
('ebae12f1-a403-4230-b3a9-719c2ef7193a','約呂徐二友遊凈慈二首  其一','陳造','宋','宋诗','song-poetry','','[]','芒鞋明日踏晴沙，肯學渠儂走狹斜。',64,'全唐诗/poet.song.151000.json','["芒鞋明日踏晴沙，肯學渠儂走狹斜。", "天井巷前休倦足，暗門城外把煎茶。", "暫同佛屋僧庖飯，徐訪姚黄魏紫花。", "要及錢唐尚留鑰，共揄吟袂緩歸家。"]'),
('eb0b9040-7908-466f-b6f0-02e18446799c','約呂徐二友遊凈慈二首  其二','陳造','宋','宋诗','song-poetry','','[]','一笑成行不待營，可無條約諗同盟。',64,'全唐诗/poet.song.151000.json','["一笑成行不待營，可無條約諗同盟。", "盤餐取飽真君事，杯酒邀歡太俗生。", "撥冗得閑殊自樂，吸光飲淥不勝清。", "即今冷眼聚蚊夢，彼此劣優君試評。"]'),
('7626069c-a703-4a93-a595-e0d6d1fd9b40','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','問舟初立柳汀沙，雲日昇空淥影斜。',64,'全唐诗/poet.song.151000.json','["問舟初立柳汀沙，雲日昇空淥影斜。", "詩橐恥隨金埒客，蔬腸未厭玉川茶。", "青湖波外方遊女，翠幄叢間亦晚花。", "小待春歸簫鼓靜，還容襆被款禪家。"]'),
('e1a6bb8f-f261-492d-b02c-e388058c38ec','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','塵中誰定免營營，鷺渚鷗沙且舊盟。',64,'全唐诗/poet.song.151000.json','["塵中誰定免營營，鷺渚鷗沙且舊盟。", "夙世林逋漫千首，逢人圓澤悟三生。", "扣門喜共僧窗飯，斲句猶能鏡樣清。", "身世已拋春夢外，更於文字措譏評。"]'),
('ffe28cb0-f24f-4ffe-86cd-1a145f80f0c5','還王編修詩卷','陳造','宋','宋诗','song-poetry','','[]','奕奕長篇間短吟，子綦天籟伯牙琴。',64,'全唐诗/poet.song.151000.json','["奕奕長篇間短吟，子綦天籟伯牙琴。", "幾人不溺西崑體，老我親聆正始音。", "得寶渾驚探驪頷，換金當復售雞林。", "還詩正恐非子助，晝易忘饑夜易深。"]'),
('6980dd98-d3d2-4dfa-b717-0573b8c7881b','元日訪丁端叔安撫二首  其一','陳造','宋','宋诗','song-poetry','','[]','幾夜徒勞夢帝宸，行貲已橐更逡巡。',64,'全唐诗/poet.song.151000.json','["幾夜徒勞夢帝宸，行貲已橐更逡巡。", "北山祇合追逋客，南道于今欠主人。", "表表德名當世重，堂堂公議有時申。", "繼今重策沖霄足，鶚表胡寧後隠淪。"]'),
('c0b11f6b-4e24-4f8b-884b-964d03635c55','元日訪丁端叔安撫二首  其二','陳造','宋','宋诗','song-poetry','','[]','節中應接可辭煩，客子回車重慨然。',64,'全唐诗/poet.song.151000.json','["節中應接可辭煩，客子回車重慨然。", "比我過秦應一笑，想君出峽富千篇。", "前知此別非久別，定復新年勝故年。", "紅藥紫薇方次第，莫占風色問春田。"]'),
('212e1ab0-68be-4272-a608-067f923e6c0d','次韻王編修二首  其一','陳造','宋','宋诗','song-poetry','','[]','落手新詩吮復吟，自甘壁角掛枯琴。',64,'全唐诗/poet.song.151000.json','["落手新詩吮復吟，自甘壁角掛枯琴。", "祈光已吸金莖露，張野俄聆帝樂音。", "療我平生風雅渴，放君高步雋英林。", "人間夢想珊瑚樹，龍護靈湫萬仞深。"]'),
('aed8e56e-5271-4cf0-806e-3972d4d3b55b','次韻王編修二首  其二','陳造','宋','宋诗','song-poetry','','[]','老誓捐書斷苦吟，君苗筆硯戴逵琴。',64,'全唐诗/poet.song.151000.json','["老誓捐書斷苦吟，君苗筆硯戴逵琴。", "因君又試推敲手，揆我終慙繳繹音。", "漫作蠹魚餐朽策，倏聽鵯鵊語中林。", "肉臺盤客曾丁字，碧酒留賓聽淺深。"]'),
('9ef4fb5f-29bc-46d7-965e-9f4b1df5fa4d','次韻楊宰食蓮戲作  其一','陳造','宋','宋诗','song-poetry','','[]','平時蓮實吾羊棗，日飫甘寒不自疑。',64,'全唐诗/poet.song.151000.json','["平時蓮實吾羊棗，日飫甘寒不自疑。", "病恐傷生嚴食事，居多節口甚嬰兒。", "舌融沆瀣詩能說，手掬珠璣我屬思。", "對酒移風勞想像，靜看千柄泛前池。"]'),
('cefb8ca5-aeb2-41a3-9b66-723502a42d98','次韻楊宰食蓮戲作  其二','陳造','宋','宋诗','song-poetry','','[]','詩到衰翁耐病時，辟渠三舍更何疑。',64,'全唐诗/poet.song.151000.json','["詩到衰翁耐病時，辟渠三舍更何疑。", "才高王儉幕中雋，氣懾孫郎帳下兒。", "向我論交得無意，他時懷舊更長思。", "蓮莖把玩不爲腹，羨殺逢人飲上池。"]'),
('6d17803f-5d6a-45ac-b9c4-70b81e33ec3a','次兒輩戲商卿設醴韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','水豢山膚自土宜，况邀從事到青齊。',64,'全唐诗/poet.song.151000.json','["水豢山膚自土宜，况邀從事到青齊。", "賓筵大嚼寧虛口，竈婦深顰想噬臍。", "爛醉豈無醒酒鱠，明朝重閲不鳴鷄。", "扶頭更憶松江曉，旋買鱸魚薤擣虀。"]'),
('98c16a61-fe67-494e-a666-04bd3151cd29','次兒輩戲商卿設醴韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','將命長鬚脚未移，聯翩客馬已來齊。',64,'全唐诗/poet.song.151000.json','["將命長鬚脚未移，聯翩客馬已來齊。", "菊花旋採浮雲液，羅幙寬圍護麝臍。", "醉裏有詩皆虎鳳，區中無物不蟲鷄。", "主賓等是龍津客，未分金鱗卧甕虀。"]'),
('cfe40ba1-ff0a-4c16-ba60-b14414fbc875','再贈澤卿商卿道舊三首  其一','陳造','宋','宋诗','song-poetry','','[]','一昨西風散馬蹄，肯如接淅去東齊。',64,'全唐诗/poet.song.151000.json','["一昨西風散馬蹄，肯如接淅去東齊。", "人家炊玉香馥鼻，禾壠如雲高過臍。", "飲雋不無驚渴虎，醉歸同約候鳴鷄。", "二卿好客家聲在，遮莫茅柴薦韭虀。"]'),
('ee77a823-d5a8-419c-852c-3f0c22c7bb5b','再贈澤卿商卿道舊三首  其二','陳造','宋','宋诗','song-poetry','','[]','隆污非是莫端倪，瞢蹈觴深試汩齊。',64,'全唐诗/poet.song.151000.json','["隆污非是莫端倪，瞢蹈觴深試汩齊。", "荆璞笑渠忘衛足，塢金何策贖然臍。", "悠悠塞上悲亡馬，斷斷尸鄉叢養鷄。", "可是世紛吾屑去，平生結習晚吹虀。"]'),
('a2254fbe-5235-4f82-9fea-59e474cfdc32','再贈澤卿商卿道舊三首  其三','陳造','宋','宋诗','song-poetry','','[]','過眼紛紛更問爲，幽人生死况能齊。',64,'全唐诗/poet.song.151000.json','["過眼紛紛更問爲，幽人生死况能齊。", "海桑恐礙日車轍，宸極劣爲天磨臍。", "臧穀君方墮書蠹，研桑我亦笑醯鷄。", "晚知戰勝輕千乘，悔厭晨鹽與暮虀。"]'),
('a750e402-30d5-469f-9729-78bbe4b5ea73','九日登神居留題','陳造','宋','宋诗','song-poetry','','[]','行行十刻冒風沙，驟喜深堂放馬撾。',64,'全唐诗/poet.song.151000.json','["行行十刻冒風沙，驟喜深堂放馬撾。", "旋報陰雲漏紅日，共追佳節把黄花。", "多煩沽酒留元亮，莫漫移文調孟嘉。", "未竟笑譚人樹醉，簷棲片月欲翻鴉。"]'),
('1e97f240-067e-4e4a-91ad-9f9e05e14474','傅商卿借鵝','陳造','宋','宋诗','song-poetry','','[]','吾家水豢慣秋春，穀飼欄栖又一新。',64,'全唐诗/poet.song.151000.json','["吾家水豢慣秋春，穀飼欄栖又一新。", "友義何須換鵝帖，鄰牆防有嗾獒人。", "眠沙泛渚期它日，問俗充庖戒未仁。", "酬我質劑當倍稱，學書還復慰清真。"]'),
('f4905737-45dc-42cb-82a2-4f9d6a132604','次韻謝陳守伯固','陳造','宋','宋诗','song-poetry','','[]','投老登龍借齒牙，可能病驥待揮撾。',64,'全唐诗/poet.song.151000.json','["投老登龍借齒牙，可能病驥待揮撾。", "清篇久矣窺修月，谹論琅然聽粲花。", "小却御屏書姓字，行當宣室拜亨嘉。", "恩章衮衮從天下，濃墨疎行砌亂鴉。"]'),
('2c223c08-fff0-4c27-8343-8531cbdcaf6f','贈傅商卿','陳造','宋','宋诗','song-poetry','','[]','殘年多病更銜哀，今日衰懷得好開。',64,'全唐诗/poet.song.151000.json','["殘年多病更銜哀，今日衰懷得好開。", "聞道場功因雨止，徑緣老子犯寒來。", "下簾小熾萁爐火，煨芋聊持藥玉杯。", "翻憶黄公酒壚夜，畧無憂患嬈靈臺。"]'),
('eb55f479-34b7-4fe5-ab68-77113a491b68','夜宿商卿家','陳造','宋','宋诗','song-poetry','','[]','萑蒲無警南塘靜，歉歲村謳鼓罷撾。',64,'全唐诗/poet.song.151000.json','["萑蒲無警南塘靜，歉歲村謳鼓罷撾。", "更喜良宵共譚麈，幾煩親手剪燈花。", "酌無多酒仍餘味，嬾不吟詩政自嘉。", "蝶夢蘧蘧纔一霎，鄰鷄啼罷又啼鴉。"]'),
('a5c76834-891d-4aca-88a0-b0e756265aed','述懷有作','陳造','宋','宋诗','song-poetry','','[]','青奴白牯共幽情，鷺隻鷗雙自舊盟。',64,'全唐诗/poet.song.151000.json','["青奴白牯共幽情，鷺隻鷗雙自舊盟。", "家視子平如已死，世嗤張翰不求名。", "馬牛見命從浮俗，螟蠃觀傍得此生。", "千載淵明吾易地，心期端有不容聲。"]'),
('003cda81-ebd4-40c2-bd44-10686587f5f7','贈實老','陳造','宋','宋诗','song-poetry','','[]','幾時風色不飛沙，再遣齋魚爲客撾。',64,'全唐诗/poet.song.151000.json','["幾時風色不飛沙，再遣齋魚爲客撾。", "塵裏槐安空夢境，眼中優鉢忽天花。", "玄譚正用蠲憂患，白飯胡寧當旨嘉。", "南去路貧同一笑，不憂攫肉有飛鴉。"]'),
('88bac25d-58b1-4387-9932-ec9d92090073','次韻答龔澤卿','陳造','宋','宋诗','song-poetry','','[]','君如綠耳抹流沙，躞蹀追風不待撾。',64,'全唐诗/poet.song.151000.json','["君如綠耳抹流沙，躞蹀追風不待撾。", "綴葺曾童楚山竹，燕遊行插曲江花。", "久煩鳳詔搜奇逸，定復龍光疊寵嘉。", "叱咤即今凌筆陣，坐令楚幕集歸鴉。"]'),
('3f09a5c2-3177-45da-9bdf-40bdb94c64a0','晚飯商卿家','陳造','宋','宋诗','song-poetry','','[]','我似長松久卧沙，迄今諫鼓夢猶撾。',64,'全唐诗/poet.song.151000.json','["我似長松久卧沙，迄今諫鼓夢猶撾。", "倚消愁斛人如玉，欲近書籤眼有花。", "投老無庸尚强聒，過君每肯具柔嘉。", "婪酣得飽行摩腹，不省饑號有莫鴉。"]'),
('51b0eb01-55f4-4d59-addf-5074c381c080','次韻答楊宰','陳造','宋','宋诗','song-poetry','','[]','民情可但絕愁嗟，吏畏誰何等受撾。',64,'全唐诗/poet.song.151000.json','["民情可但絕愁嗟，吏畏誰何等受撾。", "教諭久知風偃草，山行聊賦雪飛花。", "牛刀試用終稱屈，鳳詔緘春定拜嘉。", "穩上要津吾拭目，角犀冰峙鬢如鴉。"]'),
('b0a5fa6a-2846-4caf-a545-ebab36891a8d','次韻楊宰宿北阿','陳造','宋','宋诗','song-poetry','','[]','寒事崢嶸念解携，芳樽憶共拆紅泥。',64,'全唐诗/poet.song.151000.json','["寒事崢嶸念解携，芳樽憶共拆紅泥。", "郵筒空有詩相續，夫子東歸我復西。", "剌剌掀林朔風駛，沈沈閤雪晚雲低。", "巴歌擬報陽春贈，未敢從人索品題。"]'),
('2d0afb05-9a72-4b67-8dc1-cd5b0d995cb1','次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','君方總轡冒塵沙，我亦青燈未著花。',64,'全唐诗/poet.song.151000.json','["君方總轡冒塵沙，我亦青燈未著花。", "縣宰憂民暇黔突，道人有飯即爲家。", "倦溫村釀萁火暗，笑撚吟髭風帽斜。", "等有灞陵橋上興，不妨頻著小詩誇。"]'),
('c27d245b-e6ef-4c75-b357-394ccf16f8d7','次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','我方獺髓療蜂腰，渠自才華蓋代豪。',64,'全唐诗/poet.song.151000.json','["我方獺髓療蜂腰，渠自才華蓋代豪。", "州掾聊容養文豹，玉音催去踏金鼇。", "聯芳君亦花封最，雙峙人推玉筍高。", "看即提衡霄漢上，得無交口話啼號。"]'),
('15e2ad5c-6262-47ed-955b-7dbad0e83c96','次韻楊宰遊神居','陳造','宋','宋诗','song-poetry','','[]','峯頂留雲一鷲騫，山腰涵碧老蛟蟠。',64,'全唐诗/poet.song.151000.json','["峯頂留雲一鷲騫，山腰涵碧老蛟蟠。", "鵾鵬翻海十洲近，江漢分流三楚寬。", "曾是乘閑上埃靄，小留舒嘯倚高寒。", "想君緩憩雙鳬舄，不羨沖霄吳綵鸞。"]'),
('90a8b94b-7ed2-4c89-9a92-64756e8cd267','次韻楊宰二首  其一','陳造','宋','宋诗','song-poetry','','[]','早緣官事坐兒癡，晚悟騷人賦汩泥。',64,'全唐诗/poet.song.151000.json','["早緣官事坐兒癡，晚悟騷人賦汩泥。", "耐病久閑金騕褭，扶衰時近玉東西。", "詞場尚友心終在，詩力逢君價自低。", "欲試成風須妙質，莫懷章甫問雕題。"]'),
('da779857-e8b9-4b45-8bad-999929ac7295','次韻楊宰二首  其二','陳造','宋','宋诗','song-poetry','','[]','五斗寧辭小折腰，簿書那久困才豪。',64,'全唐诗/poet.song.151000.json','["五斗寧辭小折腰，簿書那久困才豪。", "得無貍豹驚雕虎，妙有鉤絲掣巨鼇。", "詩就鼎來宮錦腸，閑中眼與楚雲高。", "橫陳景物無央數，付子秋崖萬竅號。"]'),
('4223ea65-4030-45be-86d7-148df4c8e88c','次韻楊宰野步','陳造','宋','宋诗','song-poetry','','[]','眼邊室邇嘆人遐，再見驚飈衮雪花。',64,'全唐诗/poet.song.151000.json','["眼邊室邇嘆人遐，再見驚飈衮雪花。", "歲歉民勞真諉子，泥行草宿又誰家。", "題詩山寺神應助，問俗村區日易斜。", "隨處棠陰誦遺愛，他年賸著翠珉誇。"]'),
('32851547-3d5d-48f0-9987-17d88e05ce4d','再次楊宰遊土山韻','陳造','宋','宋诗','song-poetry','','[]','志公巖頂雲縈繞，羅漢洞前山鬰盤。',64,'全唐诗/poet.song.151000.json','["志公巖頂雲縈繞，羅漢洞前山鬰盤。", "鯀禹鑴鑱那用許，乾坤包納若爲寬。", "我行六月猶春服，誰遣千巖起暮寒。", "思與三花古仙伯，往還遊戲轡青鸞。"]'),
('1f094a24-93aa-4ef7-a28e-9b58e4dd5bc0','次韻張守塗中生日','陳造','宋','宋诗','song-poetry','','[]','諸雛稱壽紀桑蓬，此會頻年客路逢。',64,'全唐诗/poet.song.151000.json','["諸雛稱壽紀桑蓬，此會頻年客路逢。", "撫事祗令傷急景，持盃隨分發衰容。", "心緣羈旅長多遻，情爲思親政復鍾。", "更惜齊眉舊蘭友，今春觴詠斷相從。"]'),
('18ab6cb4-c7c9-4d29-bc15-3cd21a76aae0','次韻張守妻閔忌','陳造','宋','宋诗','song-poetry','','[]','萊妻魂逝不容招，敢問何方處寂寥。',64,'全唐诗/poet.song.151000.json','["萊妻魂逝不容招，敢問何方處寂寥。", "老去更堪聽薤露，病來久不近金蕉。", "聲摇夜夢蛩相弔，垢翳篝衣雨輒潮。", "細讀君詩重悽惋，隠侯膚骨不勝銷。"]'),
('94719cdd-9768-4d9f-9e8e-8d19d91850f2','次韻張守曉起','陳造','宋','宋诗','song-poetry','','[]','客亭移枕待殘更，起趁鄰鷄第二聲。',64,'全唐诗/poet.song.151000.json','["客亭移枕待殘更，起趁鄰鷄第二聲。", "了了每添新悟解，營營無復舊心情。", "興來命酒禁詩瘦，老去衰容怯鏡明。", "况是杏花濃露曉，不應蒙被問春晴。"]'),
('26e9b1b6-af4a-465b-a4eb-429b14fa2051','正月十六夜大雪次張守諸公韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','陽闔陰開意莫窮，東君衒巧似良工。',64,'全唐诗/poet.song.151000.json','["陽闔陰開意莫窮，東君衒巧似良工。", "紅蓮熄燄人收市，丹杏開時雪滾風。", "韻語真宜詠飛絮，短歌當有頌元豐。", "一番壯觀俄漂忽，已落詩人卷軸中。"]'),
('9000622b-6fca-4434-9ccc-95cc399146e6','正月十六夜大雪次張守諸公韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','詩款鈴齋到即通，細工時肯博粗工。',64,'全唐诗/poet.song.151000.json','["詩款鈴齋到即通，細工時肯博粗工。", "政聲已獨當時步，人士飫觀前輩風。", "未分清新命開府，可能簡遠盡安豐。", "譚間和氣熏人醉，不覺栖栖客路中。"]'),
('5f8ff1c5-6b98-40ec-93dc-edfc885f24d3','次韻王簽判二首  其一','陳造','宋','宋诗','song-poetry','','[]','客中誰者伴閑身，祇有蒼槐與翠筠。',64,'全唐诗/poet.song.151000.json','["客中誰者伴閑身，祇有蒼槐與翠筠。", "回首昔遊驚夢斷，故人重見倍情親。", "簿書簡省官居好，月露清圓句語新。", "千里相思匪天意，聚頭一笑此何因。"]'),
('b56cf4a8-da44-4758-bbee-82250c88130f','次韻王簽判二首  其二','陳造','宋','宋诗','song-poetry','','[]','五鬼侵陵兩鬢蒼，振窮掃白分無妨。',64,'全唐诗/poet.song.151000.json','["五鬼侵陵兩鬢蒼，振窮掃白分無妨。", "酒徒叢裏投名嬾，詩社中間趁課忙。", "塵暗鳳笙空自嘆，風驚鴈字不能行。", "向君草草追强韻，政復通人笑楚狂。"]'),
('67ad4837-1842-4395-90b1-a9570d019735','贈吳子隆','陳造','宋','宋诗','song-poetry','','[]','詩到吳侯信崛奇，汗顔飛動可容追。',64,'全唐诗/poet.song.151000.json','["詩到吳侯信崛奇，汗顔飛動可容追。", "小揮夢裏五色筆，吟作人間黄絹辭。", "滿耳龍鸞嘯空曠，驚人雨雹散雷搥。", "相如氣壓鄒枚倒，未覺樽前運思遲。"]'),
('3d75a611-8d67-4f10-86b0-e8bc4c1c2baa','次韻張德恭主簿二首  其一','陳造','宋','宋诗','song-poetry','','[]','一日乘閑燕畫樓，連宵飛夢只樓頭。',64,'全唐诗/poet.song.151000.json','["一日乘閑燕畫樓，連宵飛夢只樓頭。", "掾郎談麈驚飛雹，公子吟毫漲怒流。", "歸去定誰扶下馬，重來有約屬馴鷗。", "可堪風雨妨人樂，却向盧家訪莫愁。"]'),
('7f5d399e-1587-4282-a867-a90f2a0b2d7f','次韻張德恭主簿二首  其二','陳造','宋','宋诗','song-poetry','','[]','漢南獨步有登樓，肯爲衰翁吟掉頭。',64,'全唐诗/poet.song.151000.json','["漢南獨步有登樓，肯爲衰翁吟掉頭。", "價比連城容品裁，句專八米見風流。", "生涯枯澤鳴饑鶴，老去驚波蕩白鷗。", "當念飯山人似削，撩人更遣耐新愁。"]'),
('5b160b59-4990-4523-b763-632f4ae7b96b','次韻張守勸農二首  其一','陳造','宋','宋诗','song-poetry','','[]','傳聞載酒西郊曉，迎候前旌擁老農。',64,'全唐诗/poet.song.151000.json','["傳聞載酒西郊曉，迎候前旌擁老農。", "賢守承宣先勸課，太平風俗見聲容。", "官堤烟樹紆紅纈，沙岸風蒲裊紫茸。", "想憩凝香倒囊錦，銀鉤側理疊千重。"]'),
('a8d619b5-7a65-4d6b-a698-1c601684c3dd','次韻張守勸農二首  其二','陳造','宋','宋诗','song-poetry','','[]','競簉行軒親色笑，教條初不作風霜。',64,'全唐诗/poet.song.151000.json','["競簉行軒親色笑，教條初不作風霜。", "爲公醉德仍醇酎，惠我溫言亦報章。", "重見桐鄉敬朱邑，不須畏壘詫庚桑。", "受廛定許休吾老，已戒諸雛計裹糧。"]'),
('f50b4748-91f8-4dd6-8fa0-f6f97142a9b3','次韻張守泛春亭','陳造','宋','宋诗','song-poetry','','[]','小退鈴齋復此亭，自公喜色更津津。',64,'全唐诗/poet.song.151000.json','["小退鈴齋復此亭，自公喜色更津津。", "再紆皇眷分憂寄，坐鎮江城與物春。", "長日雍容少公事，共誰談笑作詩人。", "撚髭慣厠分題客，元亮柴車已命巾。"]'),
('c5f18bdf-081d-4826-90cc-6da33ec635b2','遊乾明分韻得山字','陳造','宋','宋诗','song-poetry','','[]','一從雋軌得追攀，日日江皋倒載還。',64,'全唐诗/poet.song.151000.json','["一從雋軌得追攀，日日江皋倒載還。", "貪向諸公論友義，未容老子憶家山。", "酒邊鯨吸仍疇昔，筆底羊腸出險艱。", "莫便樽前話分袂，此心不與石俱頑。"]'),
('ecb34577-b2fc-4516-b3f5-239360370308','寄真州詩社諸友','陳造','宋','宋诗','song-poetry','','[]','疇昔離亭酒一鍾，酒盃不比別愁濃。',64,'全唐诗/poet.song.151000.json','["疇昔離亭酒一鍾，酒盃不比別愁濃。", "羨君聯璧方保社，付我耦耕親老農。", "握手陳雷便膠漆，幾時韓孟果雲龍。", "自今筆硯還高閤，可是詩情病後慵。"]'),
('00b8c638-281b-485a-babb-059721f2e3a4','真州諸公語別','陳造','宋','宋诗','song-poetry','','[]','嬌紅爛紫正銜枚，不待王家羯鼓催。',64,'全唐诗/poet.song.151000.json','["嬌紅爛紫正銜枚，不待王家羯鼓催。", "佳客又衝新雨至，羈人未許片帆回。", "自今寒食嗟無幾，奈許閒愁撥不開。", "只擬分携乘醉去，爲君領略十分盃。"]'),
('29c4148a-0f2c-4218-aee5-adc8cfb7946c','次韻趙夷仲  其一','陳造','宋','宋诗','song-poetry','','[]','趙侯才望屹撐空，肯我過從笑語同。',64,'全唐诗/poet.song.151000.json','["趙侯才望屹撐空，肯我過從笑語同。", "妙論全勝十年讀，清篇分餉一襟風。", "珷玞可用酬崑璞，涎顙何曾夢錦蒙。", "莫把詩聲陵此老，遲君謁帝畫平戎。"]'),
('e294af34-6906-4192-b8c9-4248c7ad965a','次韻趙夷仲  其二','陳造','宋','宋诗','song-poetry','','[]','坐聽嚴更一再通，卓肩搜句夜蟲同。',64,'全唐诗/poet.song.151000.json','["坐聽嚴更一再通，卓肩搜句夜蟲同。", "拜嘉傑作開囊錦，似爲衰翁療首風。", "紫誥君宜步西掖，蒼顔我欲隠東蒙。", "鞬櫜文陳甘三舍，百勝將軍正總戎。"]'),
('f5d91bb3-9836-4294-8e92-6ae21a8ae057','再次趙侯韻','陳造','宋','宋诗','song-poetry','','[]','理窟疎明面面通，如君襟抱古賢同。',64,'全唐诗/poet.song.151000.json','["理窟疎明面面通，如君襟抱古賢同。", "孤標碧落行霜月，勝韻芳林度蕙風。", "妙語寧惟壓元白，大封端合啟龜蒙。", "規恢佇看收功去，自勒豐碑紀殪戎。"]'),
('7289c81e-be09-4e4b-baf8-58d00ed25fe0','送臧汝舟楚州秋試','陳造','宋','宋诗','song-poetry','','[]','羨殺君家有兩方，阿戎材幹更昂藏。',64,'全唐诗/poet.song.151000.json','["羨殺君家有兩方，阿戎材幹更昂藏。", "久知筆力能扛鼎，此去賢書定探囊。", "鄰近玉淵嘗借潤，眼中珠樹看爭芳。", "舊陪衆俊工飛動，老氣因君尚激昂。"]'),
('0f4f0ef1-7617-4edd-91d4-483638f9fc80','重九山陽儀真兩使君送酒','陳造','宋','宋诗','song-poetry','','[]','酒會文期興尚濃，佳辰一笑坐天窮。',64,'全唐诗/poet.song.151000.json','["酒會文期興尚濃，佳辰一笑坐天窮。", "兩州各遣六從事，九日俄成一病翁。", "詩不受催空急雨，帽無緣落任西風。", "明朝晴徑通行屐，却漫枝笻遶菊叢。"]'),
('ed02a7f1-a95b-416e-946d-83b47c9261b9','次梔子花韻','陳造','宋','宋诗','song-poetry','','[]','居士窗前薝蔔花，清香不斷逗窗紗。',64,'全唐诗/poet.song.151000.json','["居士窗前薝蔔花，清香不斷逗窗紗。", "傷和錯詆風霜實，照夜偏憐玉雪葩。", "瓊樹未應矜潔白，金神端爲發英華。", "世間俗眼便紅紫，試遣詩翁較等差。"]'),
('30d58f63-9934-4bef-acb8-b13d42538306','次喜雨韻','陳造','宋','宋诗','song-poetry','','[]','被旱農家怒伏龍，衰翁歲望甚於農。',64,'全唐诗/poet.song.151000.json','["被旱農家怒伏龍，衰翁歲望甚於農。", "人方半菽延朝夕，我亦頻年闕釜鍾。", "洒潤似驚萁火冷，驟寒不貸布衾重。", "有來喜雨清新句，一笑令人失病容。"]'),
('1e71cf18-ef67-49e8-a932-994eef9b165d','次韻李壽卿明府憶梅  其一','陳造','宋','宋诗','song-poetry','','[]','不分無花空折枝，探梅要趁未紛披。',64,'全唐诗/poet.song.151000.json','["不分無花空折枝，探梅要趁未紛披。", "憶常月地携笻去，似許風裳倚竹時。", "莊蝶認香憐夢短，墨君寫影竟誰欺。", "故人底事江南北，驛使來時僅好詩。"]'),
('387d8e19-d11a-4901-8ef6-f035c6ee0e3c','次韻李壽卿明府憶梅  其二','陳造','宋','宋诗','song-poetry','','[]','炯若橫陳耐凍枝，清篇細讀更重披。',64,'全唐诗/poet.song.151000.json','["炯若橫陳耐凍枝，清篇細讀更重披。", "即令扶病揩塵硯，痛憶尋芳載酒時。", "政使雪霙來眼底，却愁霜鬢被花欺。", "暗香疎影君能事，何處羈人敢語詩。"]'),
('d16e03b7-60b0-4b93-ba5e-6bce1f8674b1','次崔帥韻','陳造','宋','宋诗','song-poetry','','[]','虎塞風雲自壯懷，詩壇尤見不凡才。',64,'全唐诗/poet.song.151000.json','["虎塞風雲自壯懷，詩壇尤見不凡才。", "至音忽作鏘金發，急筆寧須擊鉢催。", "屬饜重嘗項上臠，拜嘉如嗅隴頭梅。", "還家定遣比鄰怪，珠璧光芒重載回。"]'),
('e8ec420f-1193-474f-afa0-14f89bd6eab9','崔侯燕城西高家亭復次韻','陳造','宋','宋诗','song-poetry','','[]','昔人勝踐此興懷，復見西園遊上才。',64,'全唐诗/poet.song.151000.json','["昔人勝踐此興懷，復見西園遊上才。", "譚麈生風容滿聽，酒觴插羽未須催。", "小令纖指鳴飛雹，却遣紅檀趁落梅。", "更約歸來醉叢碧，將軍端豈興闌回。"]'),
('5ac80e9d-cf94-4426-b876-f3c1f1d883df','鄧倅有詩次韻','陳造','宋','宋诗','song-poetry','','[]','袖手從公辟不懷，天心月脇有餘才。',64,'全唐诗/poet.song.151000.json','["袖手從公辟不懷，天心月脇有餘才。", "將壇賈勇知無敵，冊府新除定見催。", "楚國誰今衙屈宋，歐門我亦後蘇梅。", "錦囊得句無虛日，盡卷淮山勝槩回。"]'),
('53063da2-d3bf-44b9-aa67-7170464f85ba','次韻寄汪教授二首  其一','陳造','宋','宋诗','song-poetry','','[]','友賢端許寫中懷，千丈孤標十倍才。',64,'全唐诗/poet.song.151000.json','["友賢端許寫中懷，千丈孤標十倍才。", "黄絹舊知儒業富，黑頭寧受歲華催。", "筆囊小却司盤誥，鼎實終期薦傅梅。", "指日元侯矕龍衮，未容文學久低回。"]'),
('bc492637-9cb7-403a-829b-fed56f9f14e6','次韻寄汪教授二首  其二','陳造','宋','宋诗','song-poetry','','[]','客路何人起病懷，論交今得謫仙才。',64,'全唐诗/poet.song.151000.json','["客路何人起病懷，論交今得謫仙才。", "每當玉麈玄譚勝，不問銅壺漏箭催。", "魯泮舊常烹瓠葉，廣平聊復賦江梅。", "揆予儻可陪英軌，莫向詩筒靳往回。"]'),
('e9730325-c22a-4ab3-a954-e73793e0ae57','客路寄崔帥','陳造','宋','宋诗','song-poetry','','[]','笑語生春慰老懷，鄒枚端復顧凡才。',64,'全唐诗/poet.song.151000.json','["笑語生春慰老懷，鄒枚端復顧凡才。", "酒邊徐罷長鯨吸，夢裏還驚去鷁催。", "野渡水渾妨轉柂，霜林寒淺未逢梅。", "神馳縹緲凝香地，却惜無人爲挽回。"]'),
('20f35c70-39bf-46a8-a54a-6db8dca3305e','再次韻','陳造','宋','宋诗','song-poetry','','[]','解橐臨風得好懷，祇令公等費詩才。',64,'全唐诗/poet.song.151000.json','["解橐臨風得好懷，祇令公等費詩才。", "行裝併喜鴟夷滿，春意如煩羯鼓催。", "飯白重供飛雪鱠，眼青還對照溪梅。", "滯留不惡歸仍好，笑殺山陰興盡回。"]'),
('76734536-be37-4a2d-bb21-9a582022b5e3','次韻陳學正  其一','陳造','宋','宋诗','song-poetry','','[]','區中塵外自由身，囊不留錢最入神。',64,'全唐诗/poet.song.151000.json','["區中塵外自由身，囊不留錢最入神。", "便約春秋同保社，不妨天地著陳人。", "園翁溪友曾無間，野蔌山肴繼薦新。", "却嘆聲名雪堂老，莫年嶺海夢峨岷。"]'),
('e09a11ff-b963-4703-a55e-d35ccc76fbe7','次韻陳學正  其二','陳造','宋','宋诗','song-poetry','','[]','自審江湖槁項翁，浪將張邴並高風。',64,'全唐诗/poet.song.151000.json','["自審江湖槁項翁，浪將張邴並高風。", "就閑耕釣真無說，投合侯王况不工。", "策足不應諸俊後，如君寧復老夫同。", "亟須秉燭歡遊地，行簉英雄入彀中。"]'),
('96378731-b577-4a64-92f8-f5cc83a6f67f','次韻趙帥賞古梅','陳造','宋','宋诗','song-poetry','','[]','把酒花前量自寬，花同人意愜輕寒。',64,'全唐诗/poet.song.151000.json','["把酒花前量自寬，花同人意愜輕寒。", "盈盈似駕翠虬起，特特爲邀青眼看。", "紙貴共誇詩律細，客來旋報粉香殘。", "若爲白璧青錢費，可問東君博此歡。"]'),
('d8448186-52ad-41ef-9ad2-3f47292fa27a','次韻劉常甫見贈二首  其一','陳造','宋','宋诗','song-poetry','','[]','重來觸目總宜詩，頗費行吟與坐思。',64,'全唐诗/poet.song.151000.json','["重來觸目總宜詩，頗費行吟與坐思。", "舊友相過有嘉惠，滿篇更喜勝前時。", "連朝把玩驚飛動，萬象低摧受控持。", "塵翳玉笙嗟耳冷，何人度曲顫鸞篦。"]'),
('e73e62bd-38e6-4bb1-b46e-f20ca41bd6e7','次韻劉常甫見贈二首  其二','陳造','宋','宋诗','song-poetry','','[]','筆陣平時枉計功，鈍鎚那辦突銛鋒。',64,'全唐诗/poet.song.151000.json','["筆陣平時枉計功，鈍鎚那辦突銛鋒。", "灞橋雪裏嗟良苦，飯顆山頭記昔逢。", "斲句自知窮有相，從人財博繆爲恭。", "彭郎小隠劉郎宅，抖擻塵襟聽所從。"]'),
('9811cae5-7808-449c-89c7-0f36b5eef39c','次韻張守勸耕二首  其一','陳造','宋','宋诗','song-poetry','','[]','吾徒一笑似關天，離合胡寧付偶然。',64,'全唐诗/poet.song.151000.json','["吾徒一笑似關天，離合胡寧付偶然。", "夢境萍蓬渺雲水，舊遊花柳更風煙。", "交情繾綣今猶昔，妙句傳抄喜欲顛。", "廷尉歸須結襪客，爲公飽飯計留年。"]'),
('65095d22-09b1-403b-9baf-f834f49beb0c','次韻張守勸耕二首  其二','陳造','宋','宋诗','song-poetry','','[]','三揖清揚歲兩更，煩公倒屣費逢迎。',64,'全唐诗/poet.song.151000.json','["三揖清揚歲兩更，煩公倒屣費逢迎。", "抽簪仕籍心彌厲，撰屨詞壇計欲成。", "西洛况聞高紙價，蘇州從昔擅詩聲。", "拙衰枉作登龍客，領略玄譚自阿平。"]'),
('3f2b40a5-bcb4-4bfd-9ad4-da3af845a562','題彭傳師無喧境壁','陳造','宋','宋诗','song-poetry','','[]','塵外軒窗寓嘯吟，勝遊重到更情深。',64,'全唐诗/poet.song.151000.json','["塵外軒窗寓嘯吟，勝遊重到更情深。", "湖山覿面渾相識，蜂蝶窺簾似見尋。", "客路每歌歸緩緩，歲華亦嘆去駸駸。", "摩挱竹樹論今昔，親見栽時已欲林。"]'),
('b831a659-8472-4f4a-bfef-e778be63bc5c','次韻高賓王見投四首  其一','陳造','宋','宋诗','song-poetry','','[]','殘年病眼苦眵昏，盡屏甘腴誓綠樽。',64,'全唐诗/poet.song.151000.json','["殘年病眼苦眵昏，盡屏甘腴誓綠樽。", "龍樹難逢刮膜手，孟公顧有獨醒孫。", "頗煩十吏供揮掃，無奈諸峯役夢魂。", "友義惟公記衰疾，新編肯到雀羅門。"]'),
('45a1af8b-1a5b-498d-bff5-ee124edf4cf7','次韻高賓王見投四首  其二','陳造','宋','宋诗','song-poetry','','[]','病念還家可奈愁，客中日月急梭投。',64,'全唐诗/poet.song.151000.json','["病念還家可奈愁，客中日月急梭投。", "土花暈壁迎梅雨，海燕將雛送麥秋。", "霑袖正憐珠隕睫，關門能復玉爲舟。", "搘頭閤膝高舂卧，黄嬭青奴共此樓。"]'),
('865d1f30-ef10-4e12-bb2d-a6595d279ab2','次韻高賓王見投四首  其三','陳造','宋','宋诗','song-poetry','','[]','簷花如霧濕黄昏，猶夢君前白獸樽。',64,'全唐诗/poet.song.151000.json','["簷花如霧濕黄昏，猶夢君前白獸樽。", "但有紅塵染衣袂，更堪碧草思王孫。", "逃威正坐齊竽謬，歈舞難招楚客魂。", "回首仙曹雲雨上，誰云九虎踞天門。"]'),
('55c8486a-49a5-4357-a0a7-3d46f3b57543','次韻高賓王見投四首  其四','陳造','宋','宋诗','song-poetry','','[]','知君斲句爲祛愁，得句須防有暗投。',64,'全唐诗/poet.song.151000.json','["知君斲句爲祛愁，得句須防有暗投。", "我病床頭但周易，人誰皮裏著陽秋。", "騎馿久袖推門手，載酒慵移捉月舟。", "祇命君詩作三益，伴翁聽雨卧徐樓。"]'),
('12ed54b5-555e-4963-8340-504f9620277d','次韻贈高賓王二首  其一','陳造','宋','宋诗','song-poetry','','[]','瓦注緣窮也自昏，掃除膠擾近清樽。',64,'全唐诗/poet.song.151000.json','["瓦注緣窮也自昏，掃除膠擾近清樽。", "瘦田可糓宜投劾，小子今年亦抱孫。", "慣病已拚疎藥物，就閑聊免愴吟魂。", "徑當雲卧山南北，芋火醅缸晝掩門。"]'),
('654a6349-0fac-4d14-a3a7-6fd8117d3427','次韻贈高賓王二首  其二','陳造','宋','宋诗','song-poetry','','[]','滯留無地豁閑愁，詩將壇高許客投。',64,'全唐诗/poet.song.151000.json','["滯留無地豁閑愁，詩將壇高許客投。", "過我肯論新舊雨，即君如望蔉穮秋。", "幾時霧縠搴蛟室，快意湍濤放鷁舟。", "搯抉腎腸須小息，請携霜竹上危樓。"]'),
('25023c45-826b-43a2-8ddf-d2d22f22de62','再次韻贈高賓王二首  其一','陳造','宋','宋诗','song-poetry','','[]','塵外高人謝宦昏，生全天爵嚌衢樽。',64,'全唐诗/poet.song.151000.json','["塵外高人謝宦昏，生全天爵嚌衢樽。", "逸民佳傳須銀筆，常侍流風見耳孫。", "入洛真能折傖父，浮湘更欲弔英魂。", "男兒有志輕萬里，辟世何如金馬門。"]'),
('fad91940-7c33-4c62-aa05-1e6fd2f836a9','再次韻贈高賓王二首  其二','陳造','宋','宋诗','song-poetry','','[]','虞卿與世得窮愁，枘鑿方圓豈易投。',64,'全唐诗/poet.song.151000.json','["虞卿與世得窮愁，枘鑿方圓豈易投。", "政復有文衙屈宋，須防罪我坐春秋。", "千株已種柴桑菊，萬斛空橫野渡舟。", "可惜玉堂揮翰手，獨緣羈旅賦登樓。"]'),
('3a1bc799-cfc8-42e2-8987-1dcc4ca1ea6c','再次韻自誑簡賓王二首  其一','陳造','宋','宋诗','song-poetry','','[]','魚避清澄鳥愛昏，陶翁歸計酒盈樽。',64,'全唐诗/poet.song.151000.json','["魚避清澄鳥愛昏，陶翁歸計酒盈樽。", "山田雨足鳩呼婦，籬院春深竹有孫。", "百首旋編新賦詠，三生猶憶舊精魂。", "小摩他日紅塵眼，閑送蜚雲過海門。"]'),
('ef05253a-5d7f-4928-8a30-989b30cb021d','再次韻自誑簡賓王二首  其二','陳造','宋','宋诗','song-poetry','','[]','庾郎胸次枉堆愁，馮衍才名迄不投。',64,'全唐诗/poet.song.151000.json','["庾郎胸次枉堆愁，馮衍才名迄不投。", "歸去來兮歲華晚，末如何矣鬢毛秋。", "令威心事千年鶴，張翰生涯一葉舟。", "回首月堂金谷夢，却憐海蜃結飛樓。"]'),
('0179dcf4-0316-4a5d-a15f-30927baa62f1','次韻方秘正  其一','陳造','宋','宋诗','song-poetry','','[]','靜女無媒未易昏，幽人樂地但琴樽。',64,'全唐诗/poet.song.151000.json','["靜女無媒未易昏，幽人樂地但琴樽。", "詩聲况自推侯喜，牆仞懸知陋叔孫。", "拜手行申不敏謝，慕賢正黯索居魂。", "拘拘泄柳非君匹，老子來時肯閉門。"]'),
('a1bcefe7-2469-44da-8fb5-46fca8f88adb','次韻方秘正  其二','陳造','宋','宋诗','song-poetry','','[]','小窗危坐正凝愁，詩客華編肯見投。',64,'全唐诗/poet.song.151000.json','["小窗危坐正凝愁，詩客華編肯見投。", "明月拜嘉千斛賜，清風分送一襟秋。", "路迷端倚司南駕，金換還隨過海舟。", "誇與湖山須快讀，湧金門外倚曾樓。"]'),
('d2d6d66e-edb3-4508-88c5-01b49d7d0331','次韻答高賓王  其一','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','向來騎鳳下天津，冠屨因循混世塵。',64,'全唐诗/poet.song.151000.json','["向來騎鳳下天津，冠屨因循混世塵。", "行處西湖作西子，靜中佳茗是佳人。", "秋風暗凝金莖露，香霧潛浮海樹春。", "喚萼綠華書玉葉，人間新筆有通神。"]'),
('3e3cc9ec-c4c3-48f2-a58c-5e559d77e538','次韻答高賓王  其二','陳造','宋','宋诗','song-poetry','','[]','陂量如君信有容，諾金到我豈宜蒙。',64,'全唐诗/poet.song.151000.json','["陂量如君信有容，諾金到我豈宜蒙。", "蛾眉自古偕三惑，虎旅何心待九攻。", "雨室聊辭秉燭女，石腸莫笑叩舷翁。", "吾徒嫵媚青編在，檗茹冰棲定雋功。"]'),
('28f98283-cca3-4b09-9a1d-6666ed8b2151','次韻林子長一首','陳造','宋','宋诗','song-poetry','','[]','使華不袖生春手，絳老泥塗亦使年。',64,'全唐诗/poet.song.151000.json','["使華不袖生春手，絳老泥塗亦使年。", "病後隠淪甘甫里，向來魂夢頗祁連。", "受廛已傍鄉三老，對客還矜我二天。", "處士一星君漫記，會揚光彩映台躔。"]'),
('3699da6c-edc4-40ab-ad88-e14bfe4fa1cd','次韻楊帥留客賞雪二首  其一','陳造','宋','宋诗','song-poetry','','[]','錫羨端知自杳冥，更資和氣與烘成。',64,'全唐诗/poet.song.151000.json','["錫羨端知自杳冥，更資和氣與烘成。", "饜觀攪海翻雲勢，旋聽摧簷瀉竹聲。", "狎坐鴛鴦方薦笑，窺簷烏鵲已熹晴。", "從公草賦梁園罷，未羨將軍下蔡城。"]'),
('e34274e2-3579-4605-80dc-2f836f3ab32d','次韻楊帥留客賞雪二首  其二','陳造','宋','宋诗','song-poetry','','[]','園林花絮忽冥冥，水墨工夫憶李成。',64,'全唐诗/poet.song.151000.json','["園林花絮忽冥冥，水墨工夫憶李成。", "瓊樹挽春爭炫晝，玉龍轉野寂無聲。", "綺羅樽俎諸賓醉，簫鼓樓臺九陌晴。", "不比遊仙向來夢，真陪仙伯燕曾城。"]'),
('fffe088b-fe11-44c7-9aaf-ebb7c46a75a3','再次韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','雪神不袖噓枯手，嗣歲豐登預告成。',64,'全唐诗/poet.song.151000.json','["雪神不袖噓枯手，嗣歲豐登預告成。", "泚筆徑煩書上瑞，載塗况已沸歡聲。", "騎馿有客搜新句，扶路何人趁晚晴。", "一笑與渠分樂事，的知瓊露勝宜城。"]'),
('ac9d17ba-6feb-4593-bf5e-d82aa8129a95','再次韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','吹花舞絮纔俄頃，可待區區刻楮成。',64,'全唐诗/poet.song.151000.json','["吹花舞絮纔俄頃，可待區區刻楮成。", "催動江梅傲春意，喜聽冰筯滴階聲。", "剡溪載酒人乘興，縣圃明空月碾晴。", "更想捧觴天一笑，恩光旋浸鳳凰城。"]'),
('c43490d2-ff73-42f2-b929-3e277ee5de26','次韻趙帥四首  其一','陳造','宋','宋诗','song-poetry','','[]','酒會頻頻詩課忙，從公祇爾了星霜。',64,'全唐诗/poet.song.151000.json','["酒會頻頻詩課忙，從公祇爾了星霜。", "虛舟自昔安驚浪，左角從渠赴敵場。", "戀月每忘寒夜永，寄梅渾訝驛書香。", "吟邊更厭秋蛩苦，滿聽青鸞嘯女床。"]'),
('c20f17b8-0249-4b64-a393-28fd9b266476','次韻趙帥四首  其二','陳造','宋','宋诗','song-poetry','','[]','北歸客子謾貪忙，河欲生冰野覆霜。',64,'全唐诗/poet.song.151000.json','["北歸客子謾貪忙，河欲生冰野覆霜。", "他日鸛鵝常避敵，即今竿木又逢場。", "思遲正坐相如渴，文好知熏武仲香。", "妙語鼎來吾拜手，乳泉更用汲銀床。"]'),
('02e62271-3820-4ed6-abb3-157a04f217ef','次韻趙帥四首  其三','陳造','宋','宋诗','song-poetry','','[]','月姊多情闖綺窗，停雲著意護飛霜。',64,'全唐诗/poet.song.151000.json','["月姊多情闖綺窗，停雲著意護飛霜。", "艷桃穠李寬圍坐，舞雪歌雲各擅場。", "醉倒不堪酬禮數，歸來贏得夢魂香。", "明朝誰省扁舟客，但載茶鐺與筆床。"]'),
('7622c82f-cef3-4274-adbd-22dd47920daf','次韻趙帥四首  其四','陳造','宋','宋诗','song-poetry','','[]','舟子喧呼解纜忙，駝裘答颯冷禁霜。',64,'全唐诗/poet.song.151000.json','["舟子喧呼解纜忙，駝裘答颯冷禁霜。", "行分槁項新岐路，心屬毛錐舊戰場。", "談笑慣陪北海酒，馥膏擬炷後山香。", "詩筒儻肯生毛羽，飛到幽人夢蝶床。"]'),
('9b2c2da9-ac29-4b48-aeaa-c91f0d26adbc','用贈朴翁舊韻二詩送徐南卿南歸  其一','陳造','宋','宋诗','song-poetry','','[]','飛鵬尺鷃計窮通，今古幽人一笑中。',64,'全唐诗/poet.song.151000.json','["飛鵬尺鷃計窮通，今古幽人一笑中。", "等是勞生浮大塊，誰能詭遇詫良工。", "書堪引睡聊遮眼，酒可祛愁勝作公。", "此意平章有同社，絕憐相望馬牛風。"]'),
('b1b82ca4-ed2c-471c-8484-ba0f83087833','用贈朴翁舊韻二詩送徐南卿南歸  其二','陳造','宋','宋诗','song-poetry','','[]','莫將半菽羨千鍾，生世誰非囿數中。',64,'全唐诗/poet.song.151000.json','["莫將半菽羨千鍾，生世誰非囿數中。", "薦福議碑雷已震，浩然遻意句徒工。", "我知寒餓憐顔闔，人說乘除有誌公。", "窮鬼趁渠來敗類，秋禾一昔仆霜風。"]'),
('b3b079e9-4704-41e3-adba-48c59b1da968','次韻趙帥登平山堂  其一','陳造','宋','宋诗','song-poetry','','[]','東皇未憗養花功，遠近嬌紅亂老紅。',64,'全唐诗/poet.song.151000.json','["東皇未憗養花功，遠近嬌紅亂老紅。", "勝賞已容陪雋軌，憑虛仍喜受雄風。", "小𣂏蜀井寒冰齒，旋俯波光碧蘸空。", "更看詩翁落椽筆，彈丸句法許誰同。"]'),
('b3a669dc-1fa7-4471-8a1e-98feda268aed','次韻趙帥登平山堂  其二','陳造','宋','宋诗','song-poetry','','[]','平章景物我何功，猶博賓筵醉頰紅。',64,'全唐诗/poet.song.151000.json','["平章景物我何功，猶博賓筵醉頰紅。", "歡甚銳戈思却日，吟餘豪興欲凌風。", "急觴泛灩春浮淥，摻鼓喧轟鴈墮空。", "白雪拜嘉仍袖手，汗顔終恐坐雷同。"]'),
('8590414c-48ef-41d6-83ce-cb89b345c60c','次韻趙帥登平山堂  其三','陳造','宋','宋诗','song-poetry','','[]','修月于今第一功，後車九萬蜀牋紅。',64,'全唐诗/poet.song.151000.json','["修月于今第一功，後車九萬蜀牋紅。", "詩供寒食鶑花課，袖拂平山楊柳風。", "匝坐蕙蘭歌似剪，生香笑語酒如空。", "胡床不減南樓興，今古風流正自同。"]'),
('f609bb65-58d3-4dcc-97c4-9ddbfc6a57c2','次韻鄭同年餞行','陳造','宋','宋诗','song-poetry','','[]','一官自食天水草，羣雋追奔風馬牛。',64,'全唐诗/poet.song.151000.json','["一官自食天水草，羣雋追奔風馬牛。", "儉幕胡寧效涓滴，孔裝未擬借膏油。", "交情顧我失一臂，才地較君輸幾籌。", "更引功名挽衰朽，天生江水不西流。"]'),
('9eb2aba0-a2f0-4148-862b-dbba733eb168','挽章  其一','陳造','宋','宋诗','song-poetry','','[]','隠操人將處士看，寧知器業自槃槃。',64,'全唐诗/poet.song.151000.json','["隠操人將處士看，寧知器業自槃槃。", "襄陽耆舊今餘幾，儒館先生定莫攀。", "元亮歸來猶責子，德公老去竟無官。", "子孫忠孝聯三綬，說似前人合厚顔。"]'),
('749579d5-719c-4c5c-a40e-80e8cc237444','挽章  其二','陳造','宋','宋诗','song-poetry','','[]','少微前夕欲無光，白首俄傳地下郎。',64,'全唐诗/poet.song.151000.json','["少微前夕欲無光，白首俄傳地下郎。", "一代衣冠郭太宅，百年文物鄭公鄉。", "松煙黯慘空黄壤，芝檢紛綸漫紫囊。", "人過新阡應下馬，不論知識涕滂浪。"]'),
('da8faaf9-d5d4-465f-8c0f-2d05620a47bb','太碩人臧氏挽章二首  其一','陳造','宋','宋诗','song-poetry','','[]','德風千祀藹芳馨，生享修齡歿更榮。',64,'全唐诗/poet.song.151000.json','["德風千祀藹芳馨，生享修齡歿更榮。", "早歲衣冠賢德耀，莫年門戶寄升卿。", "迹陳莫嗣登堂拜，匏繫空馳執紼情。", "里巷萬人緦布會，一應如我淚河傾。"]'),
('50185f25-c9b7-4afb-a943-25489a0d730e','太碩人臧氏挽章二首  其二','陳造','宋','宋诗','song-poetry','','[]','帝恩三沐壽親筵，更數何人福慶全。',64,'全唐诗/poet.song.151000.json','["帝恩三沐壽親筵，更數何人福慶全。", "紙眩鸞迴餘舊誥，地占牛卧忽新阡。", "陰功不倚長年藥，補處仍開上品蓮。", "欲紀哀榮付豐石，諸儒當有筆如椽。"]'),
('bb670e64-c76b-4d3c-b4f1-8bc74bce3a73','次張學錄韻十首  其一','陳造','宋','宋诗','song-poetry','','[]','俗習有南北，交情無故新。',24,'全唐诗/poet.song.151000.json','["俗習有南北，交情無故新。", "得子班荆地，朴魯俱淮人。"]'),
('f46af179-acd0-41e0-8436-a572525778d2','次張學錄韻十首  其二','陳造','宋','宋诗','song-poetry','','[]','東鄰夜牙籌，西鄰晨伊凉。',24,'全唐诗/poet.song.151000.json','["東鄰夜牙籌，西鄰晨伊凉。", "孰知陋巷士，乾坤書一床。"]'),
('48799d39-635c-4b52-a5ec-c44d92f365e7','次張學錄韻十首  其三','陳造','宋','宋诗','song-poetry','','[]','學者闖聖門，贔屭未易入。',24,'全唐诗/poet.song.151000.json','["學者闖聖門，贔屭未易入。", "張子乃深造，以文作梯級。"]'),
('9d87b763-792b-4809-9064-1e6cef103b4c','次張學錄韻十首  其四','陳造','宋','宋诗','song-poetry','','[]','三吳士淵藪，向我肯論交。',24,'全唐诗/poet.song.151000.json','["三吳士淵藪，向我肯論交。", "尚友忌一鄉，同人貴于郊。"]'),
('aa856e45-19eb-493a-ba56-23c57b33f8ae','次張學錄韻十首  其五','陳造','宋','宋诗','song-poetry','','[]','燒香爲後山，展像拜太虛。',24,'全唐诗/poet.song.151000.json','["燒香爲後山，展像拜太虛。", "誰能作九原，候蟲弔寒墟。"]'),
('83bf741d-dda7-445d-9ca0-ac0ac0bd58ca','次張學錄韻十首  其六','陳造','宋','宋诗','song-poetry','','[]','張子五車讀，筆作蛟龍騰。',24,'全唐诗/poet.song.151000.json','["張子五車讀，筆作蛟龍騰。", "百戰氣彌厲，依然短檠燈。"]'),
('27913a5b-02f6-40a6-bbde-44e6d1259723','次張學錄韻十首  其七','陳造','宋','宋诗','song-poetry','','[]','廣文無酒錢，到官倏改火。',24,'全唐诗/poet.song.151000.json','["廣文無酒錢，到官倏改火。", "清譚坐蕭齋，惟子屢過我。"]'),
('d9be647d-091d-492f-b7c8-0598a60a2fc1','次張學錄韻十首  其八','陳造','宋','宋诗','song-poetry','','[]','臛鴨久欲忘，食蛙近亦稍。',24,'全唐诗/poet.song.151000.json','["臛鴨久欲忘，食蛙近亦稍。", "人言淮浙殊，得飽不汝較。"]'),
('70411e1e-260b-414e-a84e-62c680599597','次張學錄韻十首  其九','陳造','宋','宋诗','song-poetry','','[]','君才高一時，從我計已左。',24,'全唐诗/poet.song.151000.json','["君才高一時，從我計已左。", "要追莊惠塵，揮麈論然可。"]'),
('09289780-86f4-47bf-bb33-1764979a9a32','次張學錄韻十首  其一○','陳造','宋','宋诗','song-poetry','','[]','衆景紛驕蹇，君獨著語親。',24,'全唐诗/poet.song.151000.json','["衆景紛驕蹇，君獨著語親。", "十詩已櫝藏，不與俗子論。"]'),
