('62ba6099-fc8e-4459-af13-3e1f457b9cc4','循資趙宰有賀詩次韻三首  其三','陳造','宋','宋诗','song-poetry','','[]','反唇餘子輕玄白，屬目耆儒上紫清。',32,'全唐诗/poet.song.151000.json','["反唇餘子輕玄白，屬目耆儒上紫清。", "老境我甘追汗漫，明時君合訂章程。"]'),
('483c8c66-36dd-40d0-b6a1-ad35f41a1ee2','都下春日','陳造','宋','宋诗','song-poetry','','[]','烟林紅翠已班班，雨後春工不暇慳。',32,'全唐诗/poet.song.151000.json','["烟林紅翠已班班，雨後春工不暇慳。", "付與笙簫三萬指，平分綵舫聒湖山。"]'),
('4dd34429-1998-44d9-9d94-efbdfd51486e','次韻答趙文卿四首  其一','陳造','宋','宋诗','song-poetry','','[]','才名一世未通班，天向詩人每坐慳。',32,'全唐诗/poet.song.151000.json','["才名一世未通班，天向詩人每坐慳。", "不作上書來北闕，可無携妓醉東山。"]'),
('5639db67-72e0-46d7-996c-bcc5b61f325c','次韻答趙文卿四首  其二','陳造','宋','宋诗','song-poetry','','[]','平日詩聲不易班，聯翩屬我未應慳。',32,'全唐诗/poet.song.151000.json','["平日詩聲不易班，聯翩屬我未應慳。", "得無紙貴咸陽市，當有人逢飯顆山。"]'),
('1fec7eec-ff8c-42a3-aad5-6595aa081c80','次韻答趙文卿四首  其三','陳造','宋','宋诗','song-poetry','','[]','小燕招邀慰病顔，何曾雨澁與風慳。',32,'全唐诗/poet.song.151000.json','["小燕招邀慰病顔，何曾雨澁與風慳。", "分明喜鵲先知得，未曉飛鳴閙屋山。"]'),
('3cb9fbc5-3457-4e20-b26b-39d57c1a5940','次韻答趙文卿四首  其四','陳造','宋','宋诗','song-poetry','','[]','簾疎財許客窺班，未得纏頭小破慳。',32,'全唐诗/poet.song.151000.json','["簾疎財許客窺班，未得纏頭小破慳。", "已結雲愁蜚蝶夢，莫斜秋水蹙春山。"]'),
('5738eb09-5e58-477f-89b7-1645336ea17c','次韻袁憲勞軍許浦中路冰合二首  其一','陳造','宋','宋诗','song-poetry','','[]','風聲雪意恣馮陵，更挾霜華夜氣凝。',32,'全唐诗/poet.song.151000.json','["風聲雪意恣馮陵，更挾霜華夜氣凝。", "水伯護河銀作板，欲留公鬭玉壺冰。"]'),
('10d5371e-d024-4bfc-b9ae-131766aee124','次韻袁憲勞軍許浦中路冰合二首  其二','陳造','宋','宋诗','song-poetry','','[]','細讀清詩擬泣岐，問津平日幾河湄。',32,'全唐诗/poet.song.151000.json','["細讀清詩擬泣岐，問津平日幾河湄。", "只今西去須遵陸，平地風波恐更危。"]'),
('1de86a51-c0b8-4d46-8308-6fb1fc44274b','次韻袁憲打冰移舟三首  其一','陳造','宋','宋诗','song-poetry','','[]','倚柂扶篙待打冰，回思鷁首潄波聲。',32,'全唐诗/poet.song.151000.json','["倚柂扶篙待打冰，回思鷁首潄波聲。", "定知行止非人計，料理詩愁喚麴生。"]'),
('534ab3c0-26f5-4520-8ada-a3289c4b44fc','次韻袁憲打冰移舟三首  其二','陳造','宋','宋诗','song-poetry','','[]','留滯何曾念奮飛，君恩已布得徐歸。',32,'全唐诗/poet.song.151000.json','["留滯何曾念奮飛，君恩已布得徐歸。", "賢勞肯羨膏粱子，醉眼瞢騰坐妓圍。"]'),
('389ec269-1e4a-4fb7-b69f-f46f081b600d','次韻袁憲打冰移舟三首  其三','陳造','宋','宋诗','song-poetry','','[]','東行定見野橋梅，望望花隨驛使來。',32,'全唐诗/poet.song.151000.json','["東行定見野橋梅，望望花隨驛使來。", "曾約南枝春信否，急煩好句與催開。"]'),
('24cb2792-7eeb-44cc-a8e6-cba01f7a0f90','贈何符山人二首  其一','陳造','宋','宋诗','song-poetry','','[]','小詩落紙粲春葩，傳遍侯家與主家。',32,'全唐诗/poet.song.151000.json','["小詩落紙粲春葩，傳遍侯家與主家。", "未怪東來將隻影，十年囊筆飯京華。"]'),
('ce24ac0c-7fe7-4016-9cc8-4db1feaf4842','贈何符山人二首  其二','陳造','宋','宋诗','song-poetry','','[]','冷看俗態詼嘲裏，緩閲年光醉夢間。',32,'全唐诗/poet.song.151000.json','["冷看俗態詼嘲裏，緩閲年光醉夢間。", "想得酒瓢詩卷外，此生無物更相關。"]'),
('29024694-ca9f-404f-8a67-35cae786a0cb','趙介卿見簡解嘲二首  其一','陳造','宋','宋诗','song-poetry','','[]','複閤朱樓繡箔褰，蕙蘭風處各嬋娟。',32,'全唐诗/poet.song.151000.json','["複閤朱樓繡箔褰，蕙蘭風處各嬋娟。", "詩翁它日揚州夢，回施京華美少年。"]'),
('47105f71-7ab8-4c00-8b1a-f728dc7c7c57','趙介卿見簡解嘲二首  其二','陳造','宋','宋诗','song-poetry','','[]','酒家舊識玄真子，街吏嘗隨杜牧之。',32,'全唐诗/poet.song.151000.json','["酒家舊識玄真子，街吏嘗隨杜牧之。", "回首昔遊堪一笑，暮年茶果祇僧期。"]'),
('777e32ca-abb3-407f-8a56-329b210f1ca7','寓吳門十首  其一','陳造','宋','宋诗','song-poetry','','[]','一寒驅去還干祿，萬慮紛然祇愛山。',32,'全唐诗/poet.song.151000.json','["一寒驅去還干祿，萬慮紛然祇愛山。", "閲世怳如清夢覺，求田聊計白頭閑。"]'),
('7de529e9-0e98-406d-ac2c-185b849343fb','寓吳門十首  其二','陳造','宋','宋诗','song-poetry','','[]','官卑責薄得徜徉，漫仕歸來味更長。',32,'全唐诗/poet.song.151000.json','["官卑責薄得徜徉，漫仕歸來味更長。", "它日故人多好事，籠鷄載酒未吾忘。"]'),
('03dc0df7-3944-4fe4-bb6c-01a37198b487','寓吳門十首  其三','陳造','宋','宋诗','song-poetry','','[]','諸公念我閑無食，粟繼輿臺扣戶頻。',32,'全唐诗/poet.song.151000.json','["諸公念我閑無食，粟繼輿臺扣戶頻。", "眼底梅花還索笑，酒腸詩膽已輪囷。"]'),
('77cf09d3-1394-444a-9d53-07b1d8f425c4','寓吳門十首  其四','陳造','宋','宋诗','song-poetry','','[]','溪翁園客問何如，可諱浮生百計疎。',32,'全唐诗/poet.song.151000.json','["溪翁園客問何如，可諱浮生百計疎。", "不憚典衣規得酒，長因乞米衒能書。"]'),
('d721d0d9-2d0c-4a6e-93ce-ce13177de0ee','寓吳門十首  其五','陳造','宋','宋诗','song-poetry','','[]','向來勇策著書勳，一刻曾將白璧論。',32,'全唐诗/poet.song.151000.json','["向來勇策著書勳，一刻曾將白璧論。", "老去光陰都不惜，靜看烏兔役朝昏。"]');
